import { type DocumentEntry } from "./structure";
import { type ContentType, type ContentTypeField } from "./types";

function isValidSchemaIdentifier(str: string): boolean {
    // Valid identifiers start with a-z, A-Z, and can only contain a-z, A-Z, 0-9, _, and $
    const regex = /^[a-zA-Z][a-zA-Z0-9_$]*$/;
    return regex.test(str);
}

// A content entry's name becomes a top-level key in the content object and the
// leading segment of the dotted field paths used to index nested and per-locale
// content (e.g. "entryName.fieldName"). A "." in the name would corrupt that
// path, so it is rejected here. Unlike type and field names, entry names are not
// required to be valid identifiers -- existing entries use namespaced names such
// as "sdk:localeConfig" -- so only the path separator is disallowed.
export function validateEntry<T extends DocumentEntry>(entry: T): T {
    if (entry.name.length === 0) {
        throw new Error("Invalid content entry: name cannot be empty");
    }

    if (entry.name.includes(".")) {
        throw new Error(
            `Invalid content entry ${entry.name}: name must not contain "." because fields are indexed by dot path`
        );
    }

    return entry;
}

export function validateType(type: ContentType): ContentType {
    if (type.type === "canned") {
        return type;
    }

    if (type.name.length === 0) {
        throw new Error("Invalid content type: name cannot be empty");
    }

    if (!isValidSchemaIdentifier(type.name)) {
        throw new Error(
            `Invalid content type ${type.name}: name must be a valid typescript identifier`
        );
    }

    if (type.fields.length === 0) {
        throw new Error(`Invalid content type ${type.name}: type has no fields`);
    }

    // Check for duplicate field names

    const fieldNames = type.fields.map(field => field.name);

    const seen = new Set<string>();
    const duplicates = new Set<string>();
    fieldNames.forEach(name => {
        if (seen.has(name)) {
            duplicates.add(name);
        } else {
            seen.add(name);
        }
    });

    if (duplicates.size > 0) {
        throw new Error(
            `Invalid content type ${type.name}: duplicate field names ${Array.from(duplicates).join(", ")}`
        );
    }

    return type;
}

// Wrapper field types whose `childType` is a single nested ContentCoreType.
// Nesting two of these (e.g. per_environment > per_locale) is rejected because
// the storage and editor flows assume at most one wrapper per leaf.
const SINGLE_CHILD_WRAPPER_TYPES = ["per_environment", "per_resource", "per_locale"] as const;
type SingleChildWrapperType = (typeof SINGLE_CHILD_WRAPPER_TYPES)[number];

function isSingleChildWrapperType(type: string): type is SingleChildWrapperType {
    return (SINGLE_CHILD_WRAPPER_TYPES as readonly string[]).includes(type);
}

export function validateField(field: ContentTypeField): ContentTypeField {
    if (field.name.length === 0) {
        throw new Error("Invalid field: name cannot be empty");
    }

    if (!isValidSchemaIdentifier(field.name)) {
        throw new Error(`Invalid field ${field.name}: name must be a valid typescript identifier`);
    }

    if (field.label.length === 0) {
        throw new Error(`Invalid field ${field.name}: label cannot be empty`);
    }

    if (field.type === "picklist") {
        if (field.items.length === 0) {
            throw new Error(`Invalid field ${field.name}: picklist has no items`);
        }
    }

    if (
        field.type === "per_environment" ||
        field.type === "per_resource" ||
        field.type === "per_locale"
    ) {
        const childTypeName = field.childType.type;
        if (childTypeName !== undefined && isSingleChildWrapperType(childTypeName)) {
            throw new Error(
                `Invalid field ${field.name}: ${field.type} cannot wrap ${childTypeName}; nest at most one of per_environment / per_resource / per_locale per leaf`
            );
        }
    }

    return field;
}
