import {
    type Constraint,
    type Rule,
    StringBuilder,
    ObjectBuilder,
    ArrayBuilder,
    NumberBuilder,
    GenericBuilder,
} from "./rule";
import { type ContentSchema } from "./schema";
import { type DocumentEntry } from "./structure";
import { type ContentType, type ContentTypeField } from "./types";

/**
 * Build a schema definition into a json-ready object by converting
 * Rule functions into serializable Constraints.
 */
export function buildSchema(contentSchema: ContentSchema): ContentSchema {
    return {
        ...contentSchema,
        contentTypes: contentSchema.contentTypes.map(buildSchemaType),
        contentEntries: contentSchema.contentEntries.map(buildDocumentEntry),
    };
}

function buildDocumentEntry(entry: DocumentEntry): DocumentEntry {
    switch (entry.type) {
        case "list":
            return {
                ...entry,
                contentType: buildSchemaType(entry.contentType),
            };
        case "constant":
            return {
                ...entry,
                contentType: buildSchemaType(entry.contentType),
            };
    }
}

function buildSchemaType(type: ContentType) {
    switch (type.type) {
        case "canned":
            return type;
        case "custom":
        case undefined:
            return {
                ...type,
                fields: type.fields.map(field => buildSchemaField(field)),
                constraints: build(type.validation?.(new GenericBuilder())),
            };
    }
}

function buildSchemaField(type: ContentTypeField) {
    return schemaFieldBuilder[type.type](schemaFieldBuilder, type as any);
}

type SchemaFieldBuilder = {
    [K in ContentTypeField["type"]]: (
        builder: SchemaFieldBuilder,
        field: Extract<ContentTypeField, { type: K }>
    ) => Extract<ContentTypeField, { type: K }> & {
        constraints?: Constraint;
    };
};

const schemaFieldBuilder: SchemaFieldBuilder = {
    text: (builder, field) => {
        return {
            ...field,
            constraints: build(field.validation?.(new StringBuilder())),
        };
    },
    number: (builder, field) => {
        return {
            ...field,
            constraints: build(field.validation?.(new NumberBuilder())),
        };
    },
    checkbox: (builder, field) => {
        return field;
    },
    picklist: (builder, field) => {
        return {
            ...field,
            constraints: build(field.validation?.(new GenericBuilder())),
        };
    },
    file: (builder, field) => {
        return field;
    },
    array: (builder, field) => {
        return {
            ...field,
            childType: builder[field.childType.type](builder, field.childType as any),
            constraints: build(field.validation?.(new ArrayBuilder())),
        };
    },
    reference: (builder, field) => {
        return field;
    },
    object: (builder, field) => {
        return {
            ...field,
            fields: field.fields.map(f => builder[f.type](builder, f as any)),
            constraints: build(field.validation?.(new ObjectBuilder())),
        };
    },
    constant: (builder, field) => {
        return field;
    },
    multiline: (builder, field) => {
        return {
            ...field,
            constraints: build(field.validation?.(new StringBuilder())),
        };
    },
    code: (builder, field) => {
        return field;
    },
    per_environment: (builder, field) => {
        return {
            ...field,
            childType: builder[field.childType.type](builder, field.childType as any),
        };
    },
    per_resource: (builder, field) => {
        return {
            ...field,
            childType: builder[field.childType.type](builder, field.childType as any),
        };
    },
    resource: (builder, field) => {
        return field;
    },
    per_locale: (builder, field) => {
        return {
            ...field,
            childType: builder[field.childType.type](builder, field.childType as any),
        };
    },
    secret: (builder, field) => {
        return {
            ...field,
            constraints: build(field.validation?.(new StringBuilder())),
        };
    },
    markdown: (builder, field) => {
        return field;
    },
    date: (builder, field) => {
        return field;
    },
    provider: (builder, field) => {
        return field;
    },
    oauth: (builder, field) => {
        return field;
    },
};

function build<T extends Rule<T>>(rules?: T | T[]): Constraint | undefined {
    if (!rules) {
        return undefined;
    }
    if (!Array.isArray(rules)) {
        return rules.build();
    }
    return {
        type: "list",
        constraints: rules.flatMap(rule => rule.build()),
    };
}
