/**
 * Single source of truth for agent config option values.
 *
 * When adding a new option to an existing picklist:
 *  1. Update the arrays below.
 *  2. Update the corresponding enum/type in skills/goal/types.ts
 *     (GoalDefault enum or LearningMode type).
 *  3. Run `pnpm --dir journeys/sdk run generate-base-agent-content-types`
 *     (or rely on the pre-commit hook) to regenerate content-types.ts files.
 *  The CMS schema and web UI (agent-config-dialog.tsx) derive their option
 *  lists from the arrays below, so no additional changes are needed there.
 *
 * When adding a new field group (e.g. migrating safetyConfig to CMS):
 *  1. Add the options array and type below.
 *  2. Add the field to content-schema/base.ts (defineConstantEntry schema).
 *  3. In sdk/base/agent.tsx:
 *     - Destructure the field out of useCustomGoalAgentProps() so it
 *       doesn't leak into the {...customGoalAgentProps} spread.
 *     - Read the CMS value from content.$sdk?.agentConfig?.newField.
 *     - Merge: const val = codeOverride ?? cmsValue.
 *     - Pass explicitly to <GoalAgent>.
 *  4. Add the field to goalAgentRegistry in skills/goal/goal-agent.tsx
 *     (both the type and the assignment in the render body).
 *  5. Regenerate content-types.ts (step 3 from the "new option" list).
 *  6. Update GoalAgentRegistryData + FIELD_GROUPS in the web UI
 *     (agent-config-dialog.tsx).
 *
 * Adding a new personality trait:
 *  1. Add an entry to PERSONALITY_TRAIT_OPTIONS below (id, label, description,
 *     category, modalities). The UI picks it up automatically.
 *  2. Add prompt content to TRAIT_PROMPTS in skills/goal/personality-traits.ts.
 *     TypeScript will error if you skip this step (the key type is derived
 *     from PersonalityTraitId).
 *  3. Optionally add the trait to a PERSONA_PRESETS entry below.
 */

// ---------------------------------------------------------------------------
// Disabled defaults (mirrors GoalDefault enum in skills/goal/types.ts)
//
// Every GoalDefault value must appear in exactly one of GOAL_DEFAULT_OPTIONS
// or GOAL_DEFAULT_HIDDEN. The compile-time check below enforces this.
//
// NOTE: We cannot import GoalDefault directly because this package is
// bundled into the public SDK declarations, and importing from
// skills/goal/types pulls in JSX types that cause duplicate identifier
// errors in the declaration bundle. Instead we duplicate the string
// values and use a compile-time assertion in skills/goal/types.ts
// (see the comment on GoalDefault and LearningMode there).
// ---------------------------------------------------------------------------

