import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";
import { ENGLISH_DAY_FIRST_DATE_REWRITE } from "../../common/synthesis-rewrites/english-day-first-date";

const ONES = [
    "",
    "one",
    "two",
    "three",
    "four",
    "five",
    "six",
    "seven",
    "eight",
    "nine",
    "ten",
    "eleven",
    "twelve",
    "thirteen",
    "fourteen",
    "fifteen",
    "sixteen",
    "seventeen",
    "eighteen",
    "nineteen",
] as const;

const TENS = [
    "",
    "",
    "twenty",
    "thirty",
    "forty",
    "fifty",
    "sixty",
    "seventy",
    "eighty",
    "ninety",
] as const;

function spellNumber(n: number): string | null {
    if (n < 0 || n > 99) {
        return null;
    }
    if (n < 20) {
        return ONES[n] || null;
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    if (ones === 0) {
        return TENS[tens] || null;
    }
    return `${TENS[tens]}-${ONES[ones]}`;
}

// ---------------------------------------------------------------------------
// Eircode normalisation
// ---------------------------------------------------------------------------

// Matches Irish Eircode formats: routing key (letter + digit + digit-or-W,
// e.g. A65, D6W) followed by an optional space and a 4-character unique
// identifier. Routing-key letters exclude B, G, I, J, L, M, O, Q, S, U, Z
// per the official spec.
const EN_IE_EIRCODE_REGEX = /\b[ACDEFHKNPRTVWXY][0-9][0-9W] ?[0-9ACDEFHKNPRTVWXY]{4}\b/i;

function rewriteEnIeEircodeForSynthesis(text: string): string {
    const normalized = text.toUpperCase().replace(/\s+/g, " ").trim();
    const spaceIdx = normalized.indexOf(" ");

    let routingKey: string;
    let uniqueIdentifier: string;

    if (spaceIdx !== -1) {
        routingKey = normalized.slice(0, spaceIdx);
        uniqueIdentifier = normalized.slice(spaceIdx + 1);
    } else {
        routingKey = normalized.slice(0, -4);
        uniqueIdentifier = normalized.slice(-4);
    }

    if (routingKey.length !== 3 || uniqueIdentifier.length !== 4) {
        return text;
    }

    return `<platform-spell group="3,4" ignoreSymbols="true">${routingKey} ${uniqueIdentifier}</platform-spell>`;
}

// ---------------------------------------------------------------------------
// PPSN (Personal Public Service Number) normalisation
// ---------------------------------------------------------------------------

// Matches Irish PPSNs: 7 digits followed by a check letter (A–W) and an
// optional second letter (A–I or W, historically used for spouses).
const EN_IE_PPSN_REGEX = /\b\d{7}[A-W][A-IW]?\b/i;

function rewriteEnIePpsnForSynthesis(text: string): string {
    const normalized = text.toUpperCase().replace(/\s+/g, "");
    const spaced = `${normalized[0]} ${normalized.slice(1, 3)} ${normalized.slice(3, 5)} ${normalized.slice(5, 7)} ${normalized.slice(7)}`;
    if (normalized.length === 8 || normalized.length === 9) {
        return `<platform-spell ignoreSymbols="true">${spaced}</platform-spell>`;
    }
    return text;
}

// ---------------------------------------------------------------------------
// Currency normalisation
// ---------------------------------------------------------------------------

// Matches €, £ and $ amounts with optional leading minus, optional thousands
// comma-separators, and optional two-digit decimal (e.g. -€1,234.56, £50, $0.50).
const EN_IE_CURRENCY_REGEX = /-?[€£$]\d{1,3}(?:(?:,\d{3})+|\d*)(?:\.\d{2})?/;

type CurrencyNames = {
    singular: string;
    plural: string;
    subunitSingular: string;
    subunitPlural: string;
};

// Spoken-English plurals for customer service voice contexts. The EU's invariant
// "euro"/"cent" form is correct for written documents and finance statements,
// but in spoken Irish English "euros"/"cents" lands more naturally. Switch the
// euro row back to invariant if this package is used in a formal-register
// context (banking statements, government communications).
const CURRENCY_NAMES: { [key: string]: CurrencyNames | undefined } = {
    "€": { singular: "euro", plural: "euros", subunitSingular: "cent", subunitPlural: "cents" },
    "£": { singular: "pound", plural: "pounds", subunitSingular: "penny", subunitPlural: "pence" },
    $: { singular: "dollar", plural: "dollars", subunitSingular: "cent", subunitPlural: "cents" },
};

// Fully spells out a non-negative integer in Irish English. Uses "and" after
// hundreds (e.g. "one hundred and twenty-three") and commas with "and" for
// thousands (e.g. "one thousand, two hundred and thirty-four"), matching
// British English conventions.
function spellEnIeWholeNumber(n: number): string | null {
    if (n === 0) {
        return "zero";
    }
    if (n < 0 || n >= 1_000_000_000) {
        return null;
    }
    if (n < 100) {
        return spellNumber(n);
    }
    if (n < 1000) {
        const hundreds = Math.floor(n / 100);
        const remainder = n % 100;
        const hundredWord = ONES[hundreds];
        if (!hundredWord) {
            return null;
        }
        const hundredsPart = `${hundredWord} hundred`;
        if (remainder === 0) {
            return hundredsPart;
        }
        const remainderPart = spellNumber(remainder);
        if (!remainderPart) {
            return null;
        }
        return `${hundredsPart} and ${remainderPart}`;
    }
    if (n < 1_000_000) {
        const thousands = Math.floor(n / 1000);
        const remainder = n % 1000;
        const thousandsPart = `${spellEnIeWholeNumber(thousands)} thousand`;
        if (remainder === 0) {
            return thousandsPart;
        }
        const remainderPart = spellEnIeWholeNumber(remainder);
        if (!remainderPart) {
            return null;
        }
        return `${thousandsPart}${remainder < 100 ? " and " : ", "}${remainderPart}`;
    }
    const millions = Math.floor(n / 1_000_000);
    const remainder = n % 1_000_000;
    const millionsPart = `${spellEnIeWholeNumber(millions)} million`;
    if (remainder === 0) {
        return millionsPart;
    }
    const remainderPart = spellEnIeWholeNumber(remainder);
    if (!remainderPart) {
        return null;
    }
    return `${millionsPart}${remainder < 100 ? " and " : ", "}${remainderPart}`;
}

function rewriteEnIeCurrencyForSynthesis(text: string): string {
    let remaining = text.trim();

    const negative = remaining.startsWith("-");
    if (negative) {
        remaining = remaining.slice(1);
    }

    const symbol = remaining[0];
    const currencyNames = CURRENCY_NAMES[symbol];
    if (!currencyNames) {
        return text;
    }
    remaining = remaining.slice(1);

    const dotIndex = remaining.indexOf(".");
    const wholePart = dotIndex === -1 ? remaining : remaining.slice(0, dotIndex);
    const whole = Number.parseInt(wholePart.replace(/,/g, ""), 10);
    const fraction = dotIndex === -1 ? 0 : Number.parseInt(remaining.slice(dotIndex + 1), 10);

    if (Number.isNaN(whole) || Number.isNaN(fraction)) {
        return text;
    }

    const parts: string[] = [];

    if (whole > 0) {
        const spokenWhole = spellEnIeWholeNumber(whole);
        if (!spokenWhole) {
            return text;
        }
        parts.push(`${spokenWhole} ${whole === 1 ? currencyNames.singular : currencyNames.plural}`);
    }

    if (fraction > 0) {
        const spokenFraction = spellNumber(fraction);
        if (!spokenFraction) {
            return text;
        }
        parts.push(
            `${spokenFraction} ${fraction === 1 ? currencyNames.subunitSingular : currencyNames.subunitPlural}`
        );
    }

    if (parts.length === 0) {
        parts.push(`zero ${currencyNames.plural}`);
    }

    return `${negative ? "minus " : ""}${parts.join(" and ")}`;
}

// ---------------------------------------------------------------------------
// Phone number normalisation
// ---------------------------------------------------------------------------

// Matches Irish phone numbers in the local 10-digit form (e.g. 0831234567)
// or the international form with the +353 country code (e.g. +353831234567).
// Optional single spaces or hyphens are allowed between digits.
const EN_IE_PHONE_REGEX = /(?<!\d)(?:\+353|0)(?:[ -]?\d){9}(?!\d)/;

function rewriteEnIePhoneForSynthesis(text: string): string {
    const normalized = text.replace(/[ -]/g, "");

    if (normalized.startsWith("+353")) {
        const digits = normalized.slice(4);
        if (digits.length !== 9 || /\D/.test(digits)) {
            return text;
        }
        const spaced = `+353 ${digits.slice(0, 2)} ${digits.slice(2, 5)} ${digits.slice(5, 9)}`;
        return `<platform-spell group="4,2,3,4">${spaced}</platform-spell>`;
    }

    if (normalized.startsWith("0")) {
        if (normalized.length !== 10 || /\D/.test(normalized)) {
            return text;
        }
        const spaced = `${normalized.slice(0, 3)} ${normalized.slice(3, 6)} ${normalized.slice(6, 10)}`;
        return `<platform-spell group="3,3,4" ignoreSymbols="true">${spaced}</platform-spell>`;
    }

    return text;
}

// ---------------------------------------------------------------------------
// Long digit-sequence normalisation
// ---------------------------------------------------------------------------

// Length threshold below which the rewrite stays off — short numbers (years,
// PINs, 4-digit codes, short references) are left for the TTS to read naturally.
const EN_IE_LONG_DIGIT_MIN_LENGTH = 7;

// Matches long digit sequences (7+ digits) that are NOT part of a phone number.
// Lookbehinds exclude sequences preceded by:
//   - '+' or a digit (international prefix like +353)
//   - ') ' (parenthesised area code like (01) 234 5678)
const EN_IE_LONG_DIGIT_REGEX = /(?<![+\d])(?<!\+\d\d\d\s)(?<!\)\s)\d(?:[ -]?\d){6,}(?!\d)/;

function rewriteEnIeLongDigitsForSynthesis(text: string): string {
    const digits = text.replace(/[ -]/g, "");
    if (digits.length < EN_IE_LONG_DIGIT_MIN_LENGTH || /\D/.test(digits)) {
        return text;
    }
    // Skip international dial-out numbers (00 + country code + number).
    if (digits.startsWith("00") && digits.length >= 12) {
        return text;
    }
    const pairs: string[] = [];
    for (let i = 0; i < digits.length; i += 2) {
        pairs.push(digits.slice(i, i + 2));
    }
    return `<platform-spell group="2">${pairs.join(" ")}</platform-spell>`;
}

