import { type DocumentEntry, type LegacyContentEntry } from "./structure";
import { type ContentType } from "./types";

export type ContentSchema = {
    version: number;
    contentTypes: ContentType[];
    contentFolders: LegacyContentEntry[];
    contentEntries: DocumentEntry[];
};

export function getDocumentEntries(schema: ContentSchema): DocumentEntry[] {
    return findDocumentEntries(schema.contentFolders);
}

export function findDocumentEntries(entries: LegacyContentEntry[]): DocumentEntry[] {
    return entries.flatMap(findDocumentEntriesForEntry);
}

function findDocumentEntriesForEntry(entry: LegacyContentEntry): DocumentEntry[] {
    switch (entry.type) {
        case "folder":
            return findDocumentEntries(entry.children);
        case "list":
        case "constant":
            return [entry];
        case "entry":
            return [];
    }
}
