import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";
import { ENGLISH_DAY_FIRST_DATE_REWRITE } from "../../common/synthesis-rewrites/english-day-first-date";

const ONES = [
    "",
    "one",
    "two",
    "three",
    "four",
    "five",
    "six",
    "seven",
    "eight",
    "nine",
    "ten",
    "eleven",
    "twelve",
    "thirteen",
    "fourteen",
    "fifteen",
    "sixteen",
    "seventeen",
    "eighteen",
    "nineteen",
] as const;

const TENS = [
    "",
    "",
    "twenty",
    "thirty",
    "forty",
    "fifty",
    "sixty",
    "seventy",
    "eighty",
    "ninety",
] as const;

function spellNumber(n: number): string | null {
    if (n < 0 || n > 99) {
        return null;
    }
    if (n < 20) {
        return ONES[n] || null;
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    if (ones === 0) {
        return TENS[tens] || null;
    }
    return `${TENS[tens]}-${ONES[ones]}`;
}

// ---------------------------------------------------------------------------
// Postcode normalisation
// ---------------------------------------------------------------------------

// Matches standard UK postcode formats: A9, A99, A9A, AA9, AA9A followed by
// an optional space and the 3-character inward code (digit + 2 letters).
const EN_GB_POSTCODE_REGEX = /\b[A-Z]{1,2}[0-9][0-9A-Z]? ?[0-9][A-Z]{2}\b/i;

function rewriteEnGbPostcodeForSynthesis(text: string): string {
    const normalized = text.toUpperCase().replace(/\s+/g, " ").trim();
    const spaceIdx = normalized.indexOf(" ");

    let outward: string;
    let inward: string;

    if (spaceIdx !== -1) {
        outward = normalized.slice(0, spaceIdx);
        inward = normalized.slice(spaceIdx + 1);
    } else {
        outward = normalized.slice(0, -3);
        inward = normalized.slice(-3);
    }

    if (!outward || inward.length !== 3) {
        return text;
    }

    return `<platform-spell group="${outward.length},3" ignoreSymbols="true">${outward} ${inward}</platform-spell>`;
}

// ---------------------------------------------------------------------------
// National Insurance number normalisation
// ---------------------------------------------------------------------------

// Matches UK NI numbers in unformatted (AB123456C) or formatted (AB 12 34 56 C) form.
// First two letters exclude invalid prefix characters (D, F, I, Q, U, V).
// Suffix is restricted to A–D.
const EN_GB_NI_NUMBER_REGEX = /\b[A-CEG-HJ-PR-TW-Z]{2} ?\d{2} ?\d{2} ?\d{2} ?[A-D]\b/i;

function rewriteEnGbNiNumberForSynthesis(text: string): string {
    const normalized = text.toUpperCase().replace(/\s+/g, "");
    if (normalized.length !== 9) {
        return text;
    }
    const spaced = `${normalized.slice(0, 2)} ${normalized.slice(2, 4)} ${normalized.slice(4, 6)} ${normalized.slice(6, 8)} ${normalized[8]}`;
    return `<platform-spell ignoreSymbols="true">${spaced}</platform-spell>`;
}

// ---------------------------------------------------------------------------
// Currency normalisation
// ---------------------------------------------------------------------------

// Matches £ and € amounts with optional leading minus, optional thousands
// comma-separators, and optional two-digit decimal (e.g. -£1,234.56, €50, £0.50).
const EN_GB_CURRENCY_REGEX = /-?[£€$]\d{1,3}(?:(?:,\d{3})+|\d*)(?:\.\d{2})?/;

type CurrencyNames = {
    singular: string;
    plural: string;
    subunitSingular: string;
    subunitPlural: string;
};

const CURRENCY_NAMES: { [key: string]: CurrencyNames | undefined } = {
    "£": { singular: "pound", plural: "pounds", subunitSingular: "penny", subunitPlural: "pence" },
    "€": { singular: "euro", plural: "euros", subunitSingular: "cent", subunitPlural: "cents" },
    $: { singular: "dollar", plural: "dollars", subunitSingular: "cent", subunitPlural: "cents" },
};

// Fully spells out a non-negative integer in British English.
// Uses "and" after hundreds (e.g. "one hundred and twenty-three") and
// commas with "and" for thousands (e.g. "one thousand, two hundred and thirty-four").
function spellEnGbWholeNumber(n: number): string | null {
    if (n === 0) {
        return "zero";
    }
    if (n < 0 || n >= 1_000_000_000) {
        return null;
    }
    if (n < 100) {
        return spellNumber(n);
    }
    if (n < 1000) {
        const hundreds = Math.floor(n / 100);
        const remainder = n % 100;
        const hundredWord = ONES[hundreds];
        if (!hundredWord) {
            return null;
        }
        const hundredsPart = `${hundredWord} hundred`;
        if (remainder === 0) {
            return hundredsPart;
        }
        const remainderPart = spellNumber(remainder);
        if (!remainderPart) {
            return null;
        }
        return `${hundredsPart} and ${remainderPart}`;
    }
    if (n < 1_000_000) {
        const thousands = Math.floor(n / 1000);
        const remainder = n % 1000;
        const thousandsPart = `${spellEnGbWholeNumber(thousands)} thousand`;
        if (remainder === 0) {
            return thousandsPart;
        }
        const remainderPart = spellEnGbWholeNumber(remainder);
        if (!remainderPart) {
            return null;
        }
        return `${thousandsPart}${remainder < 100 ? " and " : ", "}${remainderPart}`;
    }
    const millions = Math.floor(n / 1_000_000);
    const remainder = n % 1_000_000;
    const millionsPart = `${spellEnGbWholeNumber(millions)} million`;
    if (remainder === 0) {
        return millionsPart;
    }
    const remainderPart = spellEnGbWholeNumber(remainder);
    if (!remainderPart) {
        return null;
    }
    return `${millionsPart}${remainder < 100 ? " and " : ", "}${remainderPart}`;
}

function rewriteEnGbCurrencyForSynthesis(text: string): string {
    let remaining = text.trim();

    const negative = remaining.startsWith("-");
    if (negative) {
        remaining = remaining.slice(1);
    }

    const symbol = remaining[0];
    const currencyNames = CURRENCY_NAMES[symbol];
    if (!currencyNames) {
        return text;
    }
    remaining = remaining.slice(1);

    const dotIndex = remaining.indexOf(".");
    const wholePart = dotIndex === -1 ? remaining : remaining.slice(0, dotIndex);
    const whole = Number.parseInt(wholePart.replace(/,/g, ""), 10);
    const fraction = dotIndex === -1 ? 0 : Number.parseInt(remaining.slice(dotIndex + 1), 10);

    if (Number.isNaN(whole) || Number.isNaN(fraction)) {
        return text;
    }

    const parts: string[] = [];

    if (whole > 0) {
        const spokenWhole = spellEnGbWholeNumber(whole);
        if (!spokenWhole) {
            return text;
        }
        parts.push(`${spokenWhole} ${whole === 1 ? currencyNames.singular : currencyNames.plural}`);
    }

    if (fraction > 0) {
        const spokenFraction = spellNumber(fraction);
        if (!spokenFraction) {
            return text;
        }
        parts.push(
            `${spokenFraction} ${fraction === 1 ? currencyNames.subunitSingular : currencyNames.subunitPlural}`
        );
    }

    if (parts.length === 0) {
        parts.push(`zero ${currencyNames.plural}`);
    }

    return `${negative ? "minus " : ""}${parts.join(" and ")}`;
}

// ---------------------------------------------------------------------------
// Phone number normalisation
// ---------------------------------------------------------------------------

// Matches UK phone numbers in:
// - local 11-digit form (e.g. 07890627898, 07890 627 898)
// - international form with +44 prefix (e.g. +44 7890 627898)
// - international form with 0044 prefix (e.g. 0044 7890 627898)
const EN_GB_PHONE_REGEX = /(?<!\d)(?:\+44|0044|0)(?:[ -]?\d){10}(?!\d)/;

function rewriteEnGbPhoneForSynthesis(text: string): string {
    const normalized = text.replace(/[ -]/g, "");

    if (normalized.startsWith("+44")) {
        const digits = normalized.slice(3);
        if (digits.length !== 10 || /\D/.test(digits)) {
            return text;
        }
        const spaced = `+44 ${digits.slice(0, 4)} ${digits.slice(4, 7)} ${digits.slice(7, 10)}`;
        return `<platform-spell group="3,4,3,3">${spaced}</platform-spell>`;
    }

    if (normalized.startsWith("0044")) {
        const digits = normalized.slice(4);
        if (digits.length !== 10 || /\D/.test(digits)) {
            return text;
        }
        const spaced = `0044 ${digits.slice(0, 4)} ${digits.slice(4, 7)} ${digits.slice(7, 10)}`;
        return `<platform-spell group="4,4,3,3">${spaced}</platform-spell>`;
    }

    if (normalized.startsWith("0")) {
        if (normalized.length !== 11 || /\D/.test(normalized)) {
            return text;
        }
        const spaced = `${normalized.slice(0, 5)} ${normalized.slice(5, 8)} ${normalized.slice(8, 11)}`;
        return `<platform-spell group="5,3,3" ignoreSymbols="true">${spaced}</platform-spell>`;
    }

    return text;
}

// Matches long digit sequences (7+ digits) that are NOT part of a phone number.
// Lookbehinds exclude sequences preceded by:
//   - '+' or a digit (international prefix like +44)
//   - ') ' (parenthesised area code like (020) 7946 0958)
const EN_GB_LONG_DIGIT_REGEX = /(?<![+\d])(?<!\+\d\d\s)(?<!\)\s)\d(?:[ -]?\d){6,}(?!\d)/;

// Length threshold below which the rewrite stays off — short numbers (years,
const EN_GB_LONG_DIGIT_MIN_LENGTH = 7;

function rewriteEnGbLongDigitsForSynthesis(text: string): string {
    const digits = text.replace(/[ -]/g, "");
    if (digits.length < EN_GB_LONG_DIGIT_MIN_LENGTH || /\D/.test(digits)) {
        return text;
    }
    // Skip international dial-out numbers (00 + country code + number).
    if (digits.startsWith("00") && digits.length >= 12) {
        return text;
    }
    const pairs: string[] = [];
    for (let i = 0; i < digits.length; i += 2) {
        pairs.push(digits.slice(i, i + 2));
    }
    return `<platform-spell group="2">${pairs.join(" ")}</platform-spell>`;
}

