import { EN_ID_DEFAULT_SYNTHESIS_REWRITE_RULES } from "./rules";
import { defineLocaleSynthesisRewriteRules } from "../../synthesis-rewrites";

export { EN_ID_DEFAULT_SYNTHESIS_REWRITE_RULES } from "./rules";

export const EN_ID_SYNTHESIS_REWRITE_RULES = defineLocaleSynthesisRewriteRules(
    EN_ID_DEFAULT_SYNTHESIS_REWRITE_RULES.map((rule, index) => ({
        id: `en-id:digit-${index + 1}`,
        rule,
        expectedLabel: rule.label,
    }))
);
