const ONES = [
    "",
    "one",
    "two",
    "three",
    "four",
    "five",
    "six",
    "seven",
    "eight",
    "nine",
    "ten",
    "eleven",
    "twelve",
    "thirteen",
    "fourteen",
    "fifteen",
    "sixteen",
    "seventeen",
    "eighteen",
    "nineteen",
] as const;

const TENS = [
    "",
    "",
    "twenty",
    "thirty",
    "forty",
    "fifty",
    "sixty",
    "seventy",
    "eighty",
    "ninety",
] as const;

export function spellNumberUnder100(n: number): string | null {
    if (n < 0 || n > 99) {
        return null;
    }
    if (n < 20) {
        return ONES[n] || null;
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    if (ones === 0) {
        return TENS[tens] || null;
    }
    return `${TENS[tens]}-${ONES[ones]}`;
}

// Australian English number convention: "and" after hundreds and commas with
// "and" for thousands ("one thousand, two hundred and thirty-four").
export function spellWholeNumber(n: number): string | null {
    if (n === 0) {
        return "zero";
    }
    if (n < 0 || n >= 1_000_000_000) {
        return null;
    }
    if (n < 100) {
        return spellNumberUnder100(n);
    }
    if (n < 1000) {
        const hundreds = Math.floor(n / 100);
        const remainder = n % 100;
        const hundredWord = ONES[hundreds];
        if (!hundredWord) {
            return null;
        }
        const hundredsPart = `${hundredWord} hundred`;
        if (remainder === 0) {
            return hundredsPart;
        }
        const remainderPart = spellNumberUnder100(remainder);
        if (!remainderPart) {
            return null;
        }
        return `${hundredsPart} and ${remainderPart}`;
    }
    if (n < 1_000_000) {
        const thousands = Math.floor(n / 1000);
        const remainder = n % 1000;
        const thousandsPart = `${spellWholeNumber(thousands)} thousand`;
        if (remainder === 0) {
            return thousandsPart;
        }
        const remainderPart = spellWholeNumber(remainder);
        if (!remainderPart) {
            return null;
        }
        return `${thousandsPart}${remainder < 100 ? " and " : ", "}${remainderPart}`;
    }
    const millions = Math.floor(n / 1_000_000);
    const remainder = n % 1_000_000;
    const millionsPart = `${spellWholeNumber(millions)} million`;
    if (remainder === 0) {
        return millionsPart;
    }
    const remainderPart = spellWholeNumber(remainder);
    if (!remainderPart) {
        return null;
    }
    return `${millionsPart}${remainder < 100 ? " and " : ", "}${remainderPart}`;
}
