import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

const AU_STATE_SPOKEN_NAMES: { readonly [key: string]: string | undefined } = {
    NSW: "New South Wales",
    ACT: "A-C-T",
    QLD: "Queensland",
    VIC: "Victoria",
    TAS: "Tasmania",
    SA: "South Australia",
    WA: "Western Australia",
    NT: "Northern Territory",
};

const STATE_POSTCODE_REGEX = /\b(?:NSW|ACT|QLD|VIC|TAS|SA|WA|NT)\s+\d{4}\b/i;
const LABELLED_POSTCODE_REGEX = /\b(?:post ?code|postal code)(?:\s+is)?\s*:?\s*\d{4}\b/i;
const STATE_ABBREVIATION_REGEX =
    /\b(?:in|to|from|for|near|within|across|around|into|through|throughout|via|at)\s+(?:the\s+)?(?:NSW|ACT|QLD|VIC|TAS|SA|WA|NT)\b/;
const STATE_ABBREVIATION_SUFFIX_REGEX = /\b(?:NSW|ACT|QLD|VIC|TAS|SA|WA|NT)\b$/;

const POSTCODE_DIGIT_WORDS = [
    "zero",
    "one",
    "two",
    "three",
    "four",
    "five",
    "six",
    "seven",
    "eight",
    "nine",
] as const;

function spellPostcode(postcode: string): string {
    return [...postcode].map(ch => POSTCODE_DIGIT_WORDS[Number.parseInt(ch, 10)]).join(" ");
}

function spokenStateName(state: string): string | undefined {
    return AU_STATE_SPOKEN_NAMES[state.toUpperCase()];
}

function rewriteStatePostcodeForSynthesis(text: string): string {
    const [state, postcode] = text.trim().split(/\s+/);
    const spokenState = state ? spokenStateName(state) : undefined;
    if (!spokenState || !postcode || !/^\d{4}$/.test(postcode)) {
        return text;
    }
    return `${spokenState}, ${spellPostcode(postcode)}`;
}

function rewriteLabelledPostcodeForSynthesis(text: string): string {
    const trimmed = text.trim();
    const postcode = trimmed.slice(-4);
    if (!/^\d{4}$/.test(postcode)) {
        return text;
    }
    return `${text.slice(0, text.length - 4)}${spellPostcode(postcode)}`;
}

function rewriteStateAbbreviationForSynthesis(text: string): string {
    return text.replace(STATE_ABBREVIATION_SUFFIX_REGEX, state => spokenStateName(state) ?? state);
}

export const EN_AU_STATE_POSTCODE_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "State/postcode pairs",
    description:
        "Reads Australian address state abbreviations as state names and 4-digit postcodes digit by digit.",
    playgroundSample: "Send it to Sydney NSW 2000.",
    pattern: STATE_POSTCODE_REGEX,
    replacement: rewriteStatePostcodeForSynthesis,
};

export const EN_AU_LABELLED_POSTCODE_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "Postcodes",
    description:
        "Reads labelled Australian 4-digit postcodes digit by digit so they are not spoken as years or quantities.",
    playgroundSample: "The postcode is 3000.",
    pattern: LABELLED_POSTCODE_REGEX,
    replacement: rewriteLabelledPostcodeForSynthesis,
};

export const EN_AU_STATE_ABBREVIATION_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "State and territory abbreviations",
    description:
        "Reads contextual Australian state and territory abbreviations as names, with ACT kept as A-C-T.",
    playgroundSample: "Our office is in QLD.",
    pattern: STATE_ABBREVIATION_REGEX,
    replacement: rewriteStateAbbreviationForSynthesis,
};

export const EN_AU_ADDRESS_REWRITES: LocaleSynthesisRewriteRuleImpl[] = [
    EN_AU_STATE_POSTCODE_REWRITE,
    EN_AU_LABELLED_POSTCODE_REWRITE,
    EN_AU_STATE_ABBREVIATION_REWRITE,
];

// @visibleForTesting - exported for unit tests only; not part of the public API.
export {
    rewriteStatePostcodeForSynthesis as _rewriteStatePostcodeForSynthesis,
    rewriteLabelledPostcodeForSynthesis as _rewriteLabelledPostcodeForSynthesis,
    rewriteStateAbbreviationForSynthesis as _rewriteStateAbbreviationForSynthesis,
    STATE_POSTCODE_REGEX as _STATE_POSTCODE_REGEX,
    LABELLED_POSTCODE_REGEX as _LABELLED_POSTCODE_REGEX,
    STATE_ABBREVIATION_REGEX as _STATE_ABBREVIATION_REGEX,
};
