function localeObjectField({
    name,
    label,
    description,
}: {
    name: string;
    label: string;
    description?: string;
}) {
    return defineField({
        type: "object",
        name,
        label,
        description,
        display: {
            type: "vertical",
        },
        fields: [
            defineField({
                type: "picklist",
                name: "code",
                label: "Locale",
                description: "BCP 47 locale tag",
                items: [...LOCALE_CODE_ITEMS],
            }),
            defineField({
                type: "picklist",
                name: "variant",
                label: "Variant",
                optional: true,
                items: [...GRAMMATICAL_GENDER_ITEMS],
            }),
        ],
    });
}

export function localeConfigEntry(sdkNamespace: string) {
    return defineConstantEntry({
        name: `${sdkNamespace}:localeConfig`,
        label: "Locale configuration",
        description: "Default and supported locales for the agent",
        icon: ContentIcon.Chat,
        type: defineType({
            name: "CoreLocaleConfig",
            fields: [
                localeObjectField({
                    name: "defaultLocale",
                    label: "Default locale",
                    description: "BCP 47 tag used as the fallback locale for this agent",
                }),
                defineField({
                    type: "array",
                    name: "supportedLocales",
                    label: "Supported locales",
                    description:
                        "BCP 47 tags this agent supports, in addition to the default locale.",
                    childType: localeObjectField({
                        name: "supportedLocale",
                        label: "Supported locale",
                    }),
                    validation: rule =>
                        rule.minLength(1).error("At least one supported locale is required."),
                }),
                defineField({
                    type: "checkbox",
                    name: "allowVoiceLanguageSwitching",
                    label: "Multilingual voice support",
                    description: "Allow voice transcription in multiple configured locales.",
                    optional: true,
                }),
                defineField({
                    type: "number",
                    name: "voiceLanguageSwitchDetectionTurnThreshold",
                    label: "Turns to detect a language switch",
                    description:
                        "Number of recent conversation turns inspected when deciding whether to switch the voice locale. Lower values reduce latency. Defaults to 3.",
                    optional: true,
                    minValue: 1,
                }),
            ],
        }),
    });
}
