import { DE_DE_SYNTHESIS_REWRITE_RULES } from "./de-DE/synthesis-rewrites";
import { EN_AU_SYNTHESIS_REWRITE_RULES } from "./en-AU/synthesis-rewrites";
import { EN_GB_SYNTHESIS_REWRITE_RULES } from "./en-GB/synthesis-rewrites";
import { EN_ID_SYNTHESIS_REWRITE_RULES } from "./en-ID/synthesis-rewrites";
import { EN_IE_SYNTHESIS_REWRITE_RULES } from "./en-IE/synthesis-rewrites";
import { EN_NZ_SYNTHESIS_REWRITE_RULES } from "./en-NZ/synthesis-rewrites";
import { EN_SG_SYNTHESIS_REWRITE_RULES } from "./en-SG/synthesis-rewrites";
import { EN_US_SYNTHESIS_REWRITE_RULES } from "./en-US/synthesis-rewrites";
import { EN_ZA_SYNTHESIS_REWRITE_RULES } from "./en-ZA/synthesis-rewrites";
import { ES_AR_SYNTHESIS_REWRITE_RULES } from "./es-AR/synthesis-rewrites";
import { ES_ES_SYNTHESIS_REWRITE_RULES } from "./es-ES/synthesis-rewrites";
import { FI_FI_SYNTHESIS_REWRITE_RULES } from "./fi-FI/synthesis-rewrites";
import { FR_CA_SYNTHESIS_REWRITE_RULES } from "./fr-CA/synthesis-rewrites";
import { FR_FR_SYNTHESIS_REWRITE_RULES } from "./fr-FR/synthesis-rewrites";
import { FR_SN_SYNTHESIS_REWRITE_RULES } from "./fr-SN/synthesis-rewrites";
import { ID_ID_SYNTHESIS_REWRITE_RULES } from "./id-ID/synthesis-rewrites";
import { NB_NO_SYNTHESIS_REWRITE_RULES } from "./nb-NO/synthesis-rewrites";
import { SV_SE_SYNTHESIS_REWRITE_RULES } from "./sv-SE/synthesis-rewrites";
import { TH_TH_SYNTHESIS_REWRITE_RULES } from "./th-TH/synthesis-rewrites";
import { ZH_CN_SYNTHESIS_REWRITE_RULES } from "./zh-CN/synthesis-rewrites";
import { ZH_HK_SYNTHESIS_REWRITE_RULES } from "./zh-HK/synthesis-rewrites";
import {
    getLocaleSynthesisRewriteRuleIds,
    type LocaleSynthesisRewriteRule,
} from "./synthesis-rewrites";

const SYNTHESIS_REWRITE_RULES_BY_LOCALE = {
    "ar-AE": AR_AE_SYNTHESIS_REWRITE_RULES,
    "de-DE": DE_DE_SYNTHESIS_REWRITE_RULES,
    "en-AU": EN_AU_SYNTHESIS_REWRITE_RULES,
    "en-GB": EN_GB_SYNTHESIS_REWRITE_RULES,
    "en-ID": EN_ID_SYNTHESIS_REWRITE_RULES,
    "en-IE": EN_IE_SYNTHESIS_REWRITE_RULES,
    "en-NZ": EN_NZ_SYNTHESIS_REWRITE_RULES,
    "en-SG": EN_SG_SYNTHESIS_REWRITE_RULES,
    "en-US": EN_US_SYNTHESIS_REWRITE_RULES,
    "en-ZA": EN_ZA_SYNTHESIS_REWRITE_RULES,
    "es-AR": ES_AR_SYNTHESIS_REWRITE_RULES,
    "es-ES": ES_ES_SYNTHESIS_REWRITE_RULES,
    "fi-FI": FI_FI_SYNTHESIS_REWRITE_RULES,
    "fr-CA": FR_CA_SYNTHESIS_REWRITE_RULES,
    "fr-FR": FR_FR_SYNTHESIS_REWRITE_RULES,
    "fr-SN": FR_SN_SYNTHESIS_REWRITE_RULES,
    "id-ID": ID_ID_SYNTHESIS_REWRITE_RULES,
    "nb-NO": NB_NO_SYNTHESIS_REWRITE_RULES,
    "sv-SE": SV_SE_SYNTHESIS_REWRITE_RULES,
    "th-TH": TH_TH_SYNTHESIS_REWRITE_RULES,
    "zh-CN": ZH_CN_SYNTHESIS_REWRITE_RULES,
    "zh-HK": ZH_HK_SYNTHESIS_REWRITE_RULES,
} as const satisfies Record<string, readonly LocaleSynthesisRewriteRule[]>;

const SYNTHESIS_REWRITE_RULES_BY_LOWER_LOCALE = new Map(
    Object.entries(SYNTHESIS_REWRITE_RULES_BY_LOCALE).map(([locale, rules]) => [
        locale.toLowerCase(),
        rules,
    ])
);

function rulesForLocale(locale: string | undefined): readonly LocaleSynthesisRewriteRule[] {
    return locale ? (SYNTHESIS_REWRITE_RULES_BY_LOWER_LOCALE.get(locale.toLowerCase()) ?? []) : [];
}

export function getDefaultSynthesisRewriteRulesForLocale(
    locale: string | undefined,
    enabledRuleIds: readonly string[] | undefined
): LocaleSynthesisRewriteRule[] {
    const rules = rulesForLocale(locale);
    if (rules.length === 0 || !enabledRuleIds || enabledRuleIds.length === 0) {
        return [];
    }
    const byId = new Map(rules.map(rule => [rule.id, rule]));
    return enabledRuleIds.flatMap(id => {
        const rule = byId.get(id);
        return rule ? [rule] : [];
    });
}

export function getDefaultSynthesisRewriteRuleIdsForLocale(locale: string | undefined): string[] {
    return getLocaleSynthesisRewriteRuleIds(rulesForLocale(locale));
}

export type DefaultSynthesisRewriteRuleMetadata = {
    id: string;
    label: string;
    description?: string;
    playgroundSample?: string;
};

export function getDefaultSynthesisRewriteRuleMetadataForLocale(
    locale: string | undefined
): DefaultSynthesisRewriteRuleMetadata[] {
    return rulesForLocale(locale).map(rule => ({
        id: rule.id,
        label: rule.label ?? rule.id,
        ...(rule.description !== undefined ? { description: rule.description } : {}),
        ...(rule.playgroundSample !== undefined ? { playgroundSample: rule.playgroundSample } : {}),
    }));
}

export function getLocalesWithDefaultSynthesisRewriteRules(): string[] {
    return Object.keys(SYNTHESIS_REWRITE_RULES_BY_LOCALE);
}
