import { equals } from "../types";
import { defineField } from "../definitions";

export type DayOfWeek =
    | "sunday"
    | "monday"
    | "tuesday"
    | "wednesday"
    | "thursday"
    | "friday"
    | "saturday";

export type Increment = 15 | 30 | 45 | 60;

export function operatingHours(options: { validate?: boolean; increment?: Increment } = {}) {
    const { validate = true, increment = 60 } = options;
    return [
        operatingHoursForDay("sunday", { hideHeaders: false, validate, increment }),
        operatingHoursForDay("monday", { hideHeaders: true, validate, increment }),
        operatingHoursForDay("tuesday", { hideHeaders: true, validate, increment }),
        operatingHoursForDay("wednesday", { hideHeaders: true, validate, increment }),
        operatingHoursForDay("thursday", { hideHeaders: true, validate, increment }),
        operatingHoursForDay("friday", { hideHeaders: true, validate, increment }),
        operatingHoursForDay("saturday", { hideHeaders: true, validate, increment }),
    ];
}

export function operatingHoursForDay(
    dow: DayOfWeek,
    options?: {
        hideHeaders?: boolean;
        validate?: boolean;
        increment?: Increment;
    }
) {
    const { hideHeaders, validate, increment } = options ?? {};

    return defineField({
        "type": "object",
        "name": dow,
        "label": capitalize(dow),
        "display": {
            "type": "rows",
            "rows": [
                [
                    {
                        "field": "enabled",
                        "display": {
                            "basis": 120,
                            "grow": 0,
                            "shrink": 0,
                        },
                    },
                    {
                        "field": "start",
                        "display": {
                            "basis": 120,
                            "grow": 0,
                            "shrink": 0,
                        },
                    },
                    {
                        "field": "end",
                        "display": {
                            "basis": 120,
                            "grow": 0,
                            "shrink": 0,
                        },
                    },
                ],
            ],
        },
        "validation": validate
            ? r => [
                  r
                      .custom((value: { [key: string]: unknown }) => {
                          const v = value as { enabled: boolean; start: string; end: string };
                          return !(v.enabled && v.start == v.end);
                      })
                      .error("Start and end times cannot be the same"),
              ]
            : undefined,
        "fields": [
            defineField({
                "type": "constant",
                "showIf": { type: "constant", value: false },
                "hiddenMode": "collapsed",
                "name": "increment",
                "label": "Increment",
                "value": `${increment}`,
            }),
            defineField({
                "type": "checkbox",
                "name": "enabled",
                "label": capitalize(dow),
                "heading": hideHeaders ? undefined : "Day",
            }),
            defineField({
                "type": "picklist",
                "name": `start`,
                "hideLabel": hideHeaders ?? true,
                "label": "Start",
                "showIf": equals(`${dow}.enabled`, true),
                "hiddenMode": "invisible",
                "items": hours(increment),
            }),
            defineField({
                "type": "picklist",
                "name": `end`,
                "hideLabel": hideHeaders ?? true,
                "label": "End",
                "showIf": equals(`${dow}.enabled`, true),
                "hiddenMode": "invisible",
                "items": hours(increment),
            }),
        ],
    });
}

function hours(increment: Increment = 60) {
    const items: { id: string; label: string }[] = [];
    for (let minutes = 0; minutes < 24 * 60; minutes += increment) {
        const hour = Math.floor(minutes / 60) % 24;
        const minute = minutes % 60;
        const period = hour < 12 ? "AM" : "PM";
        const displayHour = hour === 0 ? 12 : hour > 12 ? hour - 12 : hour;
        const id = `${minutes}`;
        const label = `${displayHour}:${minute.toString().padStart(2, "0")} ${period}`;
        items.push({ id, label });
    }
    items.push({ id: `${24 * 60}`, label: "12:00 AM" });
    return items;
}

function capitalize(str: string) {
    return str.charAt(0).toUpperCase() + str.slice(1);
}
