import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

const DIGIT_WORDS = {
    "1": "one",
    "2": "two",
    "3": "three",
    "4": "four",
    "5": "five",
    "6": "six",
    "7": "seven",
    "8": "eight",
    "9": "nine",
    "10": "ten",
} as const;

export const EN_ID_DEFAULT_SYNTHESIS_REWRITE_RULES: LocaleSynthesisRewriteRuleImpl[] =
    Object.entries(DIGIT_WORDS).map(([digit, word]) => ({
        label: `${digit} to ${word}`,
        description: `Rewrites standalone ${digit} as "${word}" before English (en-ID) synthesis.`,
        playgroundSample: `Your queue number is ${digit}.`,
        pattern: new RegExp(`(?<![\\p{L}\\p{N}])${digit}(?![\\p{L}\\p{N}])`, "u"),
        replacement: word,
    }));
