import { validate, type Constraint, type ValidationResult } from "./rule";
import { type ContentSchema } from "./schema";
import { type DocumentEntry } from "./structure";
import { type ContentCoreType, type ContentType, type ShowIfCondition } from "./types";

export type ValidationOpts = {
    strict: boolean;
};

type LocalizationEntries = { [locale: string]: { [fieldPath: string]: unknown } };

type LocalizationValidationOpts = {
    parentLocalization?: LocalizationEntries;
    // "Key territory": path to this field relative to the type that owns
    // `parentLocalization`, accumulated through `object` nesting. Joined with
    // "." it forms the key the schema's `localization` block uses for the
    // per-locale default (e.g. ["contactInfo", "phoneNumber"] ->
    // "contactInfo.phoneNumber"). Undefined once a non-`object` container
    // (array, per_*) has been crossed.
    localizationPath?: string[];
    // "Value territory": set once we descend into a per_locale field whose
    // child is an object and that field ships a localization default. `key` is
    // the (frozen) localization key for that per_locale field; `locale` is the
    // locale of the entry being validated; `subPath` is the path within the
    // default object to the current field. A missing sub-field is satisfied
    // only when the entry's own locale's default supplies it, mirroring the
    // CMS encoder's per-locale deep-merge bake (applyPerLocaleSchemaDefaults
    // in server/cms/encode.go).
    valueScope?: { key: string; locale: string; subPath: string[] };
};

function shouldShowField(
    field: { showIf?: ShowIfCondition },
    currentPath: string[],
    rootValue: { [key: string]: unknown }
): boolean {
    const showIf = field.showIf;
    if (!showIf) {
        return true;
    }
    return evaluateShowIfCondition(showIf, currentPath, rootValue);
}

function evaluateShowIfCondition(
    condition: ShowIfCondition,
    currentPath: string[],
    rootValue: { [key: string]: unknown }
): boolean {
    switch (condition.type) {
        case "constant":
            return condition.value;

        case "and":
            return condition.conditions.every(c =>
                evaluateShowIfCondition(c, currentPath, rootValue)
            );

        case "or":
            return condition.conditions.some(c =>
                evaluateShowIfCondition(c, currentPath, rootValue)
            );

        case "field": {
            const fieldValue = getFieldValue(condition.field, currentPath, rootValue);
            if (fieldValue === undefined) {
                return false;
            }
            return evaluateComparison(condition.comparison, fieldValue);
        }

        case "environment":
            // No active environment in this validator, so an environment condition can't be
            // evaluated here; treat the field as shown so its value is still validated.
            return true;
    }
}

function getFieldValue(
    fieldPath: string,
    currentPath: string[],
    rootValue: { [key: string]: unknown }
): unknown {
    let parts: string[];

    if (fieldPath.startsWith(".")) {
        // Relative path - remove the leading "." and resolve relative to current path
        const relativeParts = fieldPath.split(".").filter(p => p !== "");
        parts = [...currentPath, ...relativeParts];
    } else {
        // Absolute path - use as-is
        parts = fieldPath.split(".");
    }

    let value: unknown = rootValue;
    for (const part of parts) {
        if (part === "") continue;
        if (typeof value === "object" && value !== null) {
            const asObj = value as { [key: string]: unknown };
            if (asObj["$type"] === "per_environment" || asObj["$type"] === "per_locale") {
                // per_environment and per_locale both wrap entries as { value } objects
                value = (asObj[part] as { value?: unknown } | undefined)?.value;
            } else {
                value = asObj[part];
            }
        } else {
            return undefined;
        }
    }
    return value;
}

function evaluateComparison(
    comparison: ShowIfCondition & { type: "field" } extends { comparison: infer C } ? C : never,
    fieldValue: unknown
): boolean {
    switch (comparison.type) {
        case "equals":
            return fieldValue === comparison.value;
        case "notEquals":
            return fieldValue !== comparison.value;
        case "oneOf":
            return comparison.values.includes(fieldValue as boolean | string | number);
        case "contains":
            return Array.isArray(fieldValue) && fieldValue.includes(comparison.value);
        case "greaterThan":
            return typeof fieldValue === "number" && fieldValue > comparison.value;
        case "lessThan":
            return typeof fieldValue === "number" && fieldValue < comparison.value;
    }
}

export function validateContent(
    schema: ContentSchema,
    content: { [key: string]: unknown },
    opts: ValidationOpts = { strict: false }
): ValidationResult[] {
    return schema.contentEntries.flatMap(e =>
        opts.strict || e.name in content
            ? addToPath(e.name, validateEntry(schema, e, content[e.name], opts))
            : []
    );
}

export function assertValidContent(
    schema: ContentSchema,
    content: { [key: string]: unknown },
    opts: ValidationOpts = { strict: false }
) {
    const errors = validateContent(schema, content, opts);
    if (errors.length > 0) {
        throw new Error(
            `Invalid content: ${errors.map(e => [e.path?.join("/"), e.message].join(": ")).join("\n")}`
        );
    }
}

function validateEntry(
    schema: ContentSchema,
    entry: DocumentEntry,
    content: any,
    opts: ValidationOpts
): ValidationResult[] {
    if (typeof content !== "object" || content === null || content === undefined) {
        return [{ message: "Entry is not an object" }];
    }
    switch (entry.type) {
        case "constant": {
            if (Array.isArray(content) && content.length !== 1) {
                return [{ message: "Entry must have exactly one value" }];
            }
            if (Array.isArray(content)) {
                content = content[0];
            }
            return validateTypeByName(schema, entry.typeName, content, opts);
        }
        case "list": {
            if (!Array.isArray(content)) {
                return [{ message: "Entry is not an array" }];
            }
            return content.flatMap((v, index) =>
                addToPath(`${index}`, validateTypeByName(schema, entry.typeName, v, opts))
            );
        }
    }
}

export function validateTypeByName(
    schema: ContentSchema,
    typeName: string,
    content: any,
    opts: ValidationOpts
): ValidationResult[] {
    const contentType = schema.contentTypes.find(x => x.name === typeName);
    if (!contentType) {
        // TODO: validate integrations or other dynamically loaded types
        return [];
    }
    return validateType(schema, contentType, content, opts, content, []);
}

function validateType(
    schema: ContentSchema,
    type: ContentType,
    content: any,
    opts: ValidationOpts,
    rootValue: { [key: string]: unknown },
    currentPath: string[]
): ValidationResult[] {
    // TODO: validate canned types
    if (type.type === "canned") {
        return [];
    }
    if (typeof content !== "object" || content === null || content === undefined) {
        return [{ message: "Entry is not an object" }];
    }
    const localization = type.localization;
    const results = type.fields.flatMap(field => {
        // Skip validation for fields that are hidden due to showIf condition
        if (!shouldShowField(field, currentPath, rootValue)) {
            return [];
        }
        return addToPath(
            field.name,
            validateTypeField(
                schema,
                field,
                (content as { [key: string]: any })[field.name],
                opts,
                rootValue,
                [...currentPath, field.name],
                {
                    parentLocalization: localization,
                    localizationPath: [field.name],
                }
            )
        );
    });
    return [...results, ...validateConstraints(type, content)];
}

function validateOAuthValue(contentValue: unknown): ValidationResult[] {
    if (typeof contentValue !== "object" || contentValue === null || Array.isArray(contentValue)) {
        return [{ message: "Value is not an oauth object" }];
    }

    const oauthValue = contentValue as { [key: string]: unknown };
    const errors: ValidationResult[] = [];

    if (
        "$type" in oauthValue &&
        oauthValue["$type"] !== undefined &&
        oauthValue["$type"] !== "oauth"
    ) {
        errors.push({ path: ["$type"], message: 'Value must be "oauth"' });
    }

    if (typeof oauthValue["providerId"] !== "string" || oauthValue["providerId"] === "") {
        errors.push({ path: ["providerId"], message: "OAuth providerId is required" });
    }

    if (
        "url" in oauthValue &&
        oauthValue["url"] !== undefined &&
        typeof oauthValue["url"] !== "string"
    ) {
        errors.push({ path: ["url"], message: "Value is not text" });
    }

    if (
        "tokenUrl" in oauthValue &&
        oauthValue["tokenUrl"] !== undefined &&
        typeof oauthValue["tokenUrl"] !== "string"
    ) {
        errors.push({ path: ["tokenUrl"], message: "Value is not text" });
    }

    if ("urlTemplateParams" in oauthValue && oauthValue["urlTemplateParams"] !== undefined) {
        const urlTemplateParams = oauthValue["urlTemplateParams"];
        if (
            typeof urlTemplateParams !== "object" ||
            urlTemplateParams === null ||
            Array.isArray(urlTemplateParams)
        ) {
            errors.push({ path: ["urlTemplateParams"], message: "Value is not an object" });
        } else {
            errors.push(
                ...Object.entries(urlTemplateParams).flatMap(([key, value]) =>
                    typeof value === "string"
                        ? []
                        : [{ path: ["urlTemplateParams", key], message: "Value is not text" }]
                )
            );
        }
    }

    if ("scopes" in oauthValue && oauthValue["scopes"] !== undefined) {
        const scopes = oauthValue["scopes"];
        if (!Array.isArray(scopes)) {
            errors.push({ path: ["scopes"], message: "Value is not an array" });
        } else {
            errors.push(
                ...scopes.flatMap((scope, index) =>
                    typeof scope === "string"
                        ? []
                        : [{ path: ["scopes", `${index}`], message: "Value is not text" }]
                )
            );
        }
    }

    return errors;
}

function validateResourceValue(
    contentValue: unknown,
    expectedResource: string
): ValidationResult[] {
    if (typeof contentValue !== "object" || contentValue === null || Array.isArray(contentValue)) {
        return [{ message: "Value is not a resource selector" }];
    }

    const resourceValue = contentValue as { [key: string]: unknown };
    const errors: ValidationResult[] = [];
    if (resourceValue["$type"] !== "resource") {
        errors.push({ path: ["$type"], message: "Resource selector is missing $type" });
    }
    if (resourceValue["resource"] !== expectedResource) {
        errors.push({
            path: ["resource"],
            message: `Resource selector is not a ${expectedResource}`,
        });
    }
    if (typeof resourceValue["id"] !== "string" || resourceValue["id"] === "") {
        errors.push({ path: ["id"], message: "Resource selector is missing id" });
    }
    return errors;
}

function validateTypeField(
    schema: ContentSchema,
    contentField: ContentCoreType,
    contentValue: unknown,
    opts: ValidationOpts,
    rootValue: { [key: string]: unknown },
    currentPath: string[],
    localization?: LocalizationValidationOpts
): ValidationResult[] {
    const {
        parentLocalization,
        localizationPath,
        valueScope: localizationValueScope,
    } = localization ?? {};

    // TODO: unify type validations and constraints
    function checkType() {
        switch (contentField.type) {
            case "picklist": {
                const ids = contentField.items.map(x => x.id);
                if (contentField.multiselect) {
                    if (!Array.isArray(contentValue)) {
                        return [{ message: `Value is not an array` }];
                    }
                    for (const v of contentValue as string[]) {
                        if (!ids.includes(v)) {
                            return [{ message: `Invalid picklist value ${v}` }];
                        }
                    }
                } else {
                    if (!ids.includes(contentValue as string)) {
                        return [{ message: `Invalid picklist value ${contentValue as string}` }];
                    }
                }
                return [];
            }
            case "object":
                return contentField.fields.flatMap(field => {
                    // Skip validation for fields that are hidden due to showIf condition
                    if (!shouldShowField(field, currentPath, rootValue)) {
                        return [];
                    }
                    return addToPath(
                        field.name,
                        validateTypeField(
                            schema,
                            field,
                            (contentValue as { [key: string]: any })[field.name],
                            opts,
                            rootValue,
                            [...currentPath, field.name],
                            // Keep threading the owning type's localization so
                            // nested fields can find their default, either via
                            // the dotted key (key territory) or the per_locale
                            // field's default object (value territory).
                            {
                                parentLocalization,
                                localizationPath:
                                    localizationValueScope === undefined &&
                                    localizationPath !== undefined
                                        ? [...localizationPath, field.name]
                                        : undefined,
                                valueScope:
                                    localizationValueScope !== undefined
                                        ? {
                                              ...localizationValueScope,
                                              subPath: [
                                                  ...localizationValueScope.subPath,
                                                  field.name,
                                              ],
                                          }
                                        : undefined,
                            }
                        )
                    );
                });
            case "array": {
                if (!Array.isArray(contentValue)) {
                    return [{ message: `Value is not an array` }];
                }
                return contentValue.flatMap((value, index) =>
                    addToPath(
                        `${index}`,
                        validateTypeField(schema, contentField.childType, value, opts, rootValue, [
                            ...currentPath,
                            `${index}`,
                        ])
                    )
                );
            }
            case "text":
            case "multiline":
            case "code":
            case "markdown":
            case "constant":
            case "date":
                return typeof contentValue === "string" ? [] : [{ message: `Value is not text` }];
            case "checkbox":
                return typeof contentValue === "boolean"
                    ? []
                    : [{ message: `Value is not a boolean` }];
            case "number": {
                if (typeof contentValue !== "number") {
                    return [{ message: `Value is not a number` }];
                }
                if (contentField.minValue !== undefined && contentValue < contentField.minValue) {
                    return [{ message: `Value must be at least ${contentField.minValue}` }];
                }
                if (contentField.maxValue !== undefined && contentValue > contentField.maxValue) {
                    return [{ message: `Value must be at most ${contentField.maxValue}` }];
                }
                return [];
            }
            case "file":
                return typeof contentValue === "string" ? [] : [{ message: `Value is not a file` }];
            case "reference":
                return typeof contentValue === "string"
                    ? []
                    : [{ message: `Value is not a reference` }];
            case "resource":
                return validateResourceValue(contentValue, contentField.resource);
            case "per_environment":
                const perEnvValue = contentValue as {
                    [key: string]: { enabled?: boolean; value: unknown } | undefined;
                };
                return Object.entries(perEnvValue).flatMap(([key, value]) => {
                    if (value?.enabled ?? false) {
                        return addToPath(
                            key,
                            validateTypeField(
                                schema,
                                contentField.childType,
                                value?.value,
                                opts,
                                rootValue,
                                [...currentPath, key]
                            )
                        );
                    }
                    return [];
                });
            case "per_resource": {
                const perResValue = contentValue as {
                    [key: string]: { enabled?: boolean; value: unknown } | undefined;
                };
                return Object.entries(perResValue).flatMap(([key, value]) => {
                    if (value?.enabled ?? false) {
                        return addToPath(
                            key,
                            validateTypeField(
                                schema,
                                contentField.childType,
                                value?.value,
                                opts,
                                rootValue,
                                [...currentPath, key]
                            )
                        );
                    }
                    return [];
                });
            }
            case "per_locale": {
                if (
                    typeof contentValue !== "object" ||
                    contentValue === null ||
                    Array.isArray(contentValue) ||
                    (contentValue as { $type?: unknown }).$type !== "per_locale"
                ) {
                    return [{ message: "Value is not a per_locale object" }];
                }
                // If this per_locale field ships a localization default, thread
                // it into the child so a partially specified object value can
                // inherit the remaining sub-field defaults at runtime (matching
                // the CMS encoder's bake). Only meaningful in key territory; a
                // per_locale nested inside another per_locale's value carries no
                // registered default, so localization is dropped there.
                const localeDefaultKey =
                    localizationValueScope === undefined ? localizationPath?.join(".") : undefined;
                const childHasDefault =
                    localeDefaultKey !== undefined &&
                    parentLocalization !== undefined &&
                    Object.values(parentLocalization).some(
                        localeEntry => localeDefaultKey in localeEntry
                    );
                const childLocalization = childHasDefault ? parentLocalization : undefined;
                const perLocaleValue = contentValue as { [key: string]: unknown };
                return Object.entries(perLocaleValue).flatMap(([key, entry]) => {
                    if (key === "$type") {
                        return [];
                    }
                    if (entry === undefined) {
                        return [];
                    }
                    if (typeof entry !== "object" || entry === null || Array.isArray(entry)) {
                        return addToPath(key, [{ message: "Locale entry is not an object" }]);
                    }
                    const localeEntry = entry as { value?: unknown };
                    if (localeEntry.value === undefined) {
                        return [];
                    }
                    return addToPath(
                        key,
                        validateTypeField(
                            schema,
                            contentField.childType,
                            localeEntry.value,
                            opts,
                            rootValue,
                            [...currentPath, key],
                            {
                                parentLocalization: childLocalization,
                                valueScope:
                                    childHasDefault && localeDefaultKey !== undefined
                                        ? { key: localeDefaultKey, locale: key, subPath: [] }
                                        : undefined,
                            }
                        )
                    );
                });
            }
            case "secret":
                return [];
            case "oauth":
                return validateOAuthValue(contentValue);
            case "provider":
                return typeof contentValue === "string"
                    ? []
                    : [{ message: `Value is not a provider selector` }];
        }
    }

    let errors: ValidationResult[] = [];
    if (contentValue === undefined || contentValue === null) {
        // A field is satisfied by a schema-shipped localization default when:
        //  - value territory: it is a sub-field of a per_locale -> object field
        //    and that field's default object supplies it (the runtime
        //    deep-merge backfills it), or
        //  - key territory: it is a per_locale field whose dotted path is keyed
        //    in the `localization` block (top-level: bare name; nested under
        //    objects: "parent.child"), so an empty stored record is valid.
        let hasSchemaLocalizationDefault = false;
        if (localizationValueScope !== undefined && parentLocalization !== undefined) {
            // Only the entry's own locale's default can backfill it: the
            // encoder bake (lookupLocalizationForCodeVariant) resolves
            // `<code>-<variant>` then `<code>` then any `<code>-*`, never a
            // different locale's entry.
            hasSchemaLocalizationDefault = localizationEntriesForLocale(
                parentLocalization,
                localizationValueScope.locale
            ).some(localeEntry =>
                hasLocalizationDefaultAtPath(
                    localeEntry[localizationValueScope.key],
                    localizationValueScope.subPath
                )
            );
        } else if (
            contentField.type === "per_locale" &&
            parentLocalization !== undefined &&
            localizationPath !== undefined
        ) {
            const localizationKey = localizationPath.join(".");
            hasSchemaLocalizationDefault = Object.values(parentLocalization).some(
                localeEntry => localizationKey in localeEntry
            );
        }
        if (
            opts.strict &&
            contentField.type !== "constant" &&
            contentField.type !== "markdown" &&
            !allowsMissingValue(contentField) &&
            !hasSchemaLocalizationDefault
        ) {
            const fieldLabel =
                contentField.label || contentField.name || currentPath[currentPath.length - 1];
            errors = [{ message: `${fieldLabel ?? "Value"} is required` }];
        } else {
            errors = [];
        }
    } else {
        errors = checkType();
    }
    if (errors.length > 0) {
        return errors;
    }
    return validateConstraints(contentField as { constraints?: Constraint }, contentValue);
}

// Returns the localization entries the encoder could bake for `locale`:
// the exact code plus gender-variant keys (`<code>-feminine` etc.), matched
// case-insensitively per BCP 47. Mirrors lookupLocalizationForCodeVariant in
// server/cms/encode.go.
function localizationEntriesForLocale(
    localization: LocalizationEntries,
    locale: string
): { [fieldPath: string]: unknown }[] {
    const lower = locale.toLowerCase();
    return Object.entries(localization)
        .filter(([key]) => {
            const keyLower = key.toLowerCase();
            return keyLower === lower || keyLower.startsWith(`${lower}-`);
        })
        .map(([, entry]) => entry);
}

// Walks `subPath` into a per_locale field's localization default object and
// reports whether it bottoms out at a defined value, i.e. whether the default
// supplies the sub-field the customer omitted.
function hasLocalizationDefaultAtPath(defaultValue: unknown, subPath: string[]): boolean {
    let cursor = defaultValue;
    for (const segment of subPath) {
        if (typeof cursor !== "object" || cursor === null || Array.isArray(cursor)) {
            return false;
        }
        cursor = (cursor as { [key: string]: unknown })[segment];
    }
    return cursor !== undefined;
}

function allowsMissingValue(contentField: ContentCoreType): boolean {
    if ("optional" in contentField && contentField.optional === true) {
        return true;
    }
    return contentField.type === "per_locale" && allowsMissingValue(contentField.childType);
}

function validateConstraints(contentNode: { [key: string]: unknown }, contentValue: unknown) {
    if ("constraints" in contentNode && contentNode["constraints"]) {
        return validate(contentNode["constraints"] as Constraint, contentValue, {});
    }
    return [];
}

function addToPath(fieldName: string, results: ValidationResult[]): ValidationResult[] {
    return results.map(x => ({ ...x, path: [fieldName, ...(x.path ?? [])] }));
}
