import type { ProgressIndicatorModeId } from "../agent-config-options";

export type InactivityMode = "static" | "adaptive";
export type VoiceSynthesisRewrite = {
    pattern: string;
    replacement: string;
};

export type LocaleDefaults = {
    defaultVoicePersona: string;
    defaultVoiceKeywords: string[];
    defaultVoiceSynthesisRewrites: VoiceSynthesisRewrite[];

    defaultOrganizationName: string;
    defaultAgentName: string;

    defaultVoiceGreeting: string;
    uninterruptibleGreeting: boolean;

    errorMessage: string;
    abuseDetectedTransferMessage: string;
    abuseDetectedTerminationMessage: string;

    inactivityMode: InactivityMode | undefined;
    inactivityTimeoutSeconds: number | undefined;
    inactivityMaxCount: number | undefined;
    inactivityPromptMessage: string;
    inactivityHangupMessage: string;
    adaptiveMinWaitSeconds: number | undefined;
    adaptiveMaxWaitSeconds: number | undefined;

    progressIndicatorMode: ProgressIndicatorModeId;
    progressIndicatorInitialDelayMs: number | undefined;
    progressIndicatorTrailingSilenceMs: number | undefined;
    progressIndicatorChatEnabled: boolean;
    progressIndicatorAdditionalInstructions: string | undefined;

    // Default personality trait IDs the locale package recommends. Sourced
    // from each locale-package's `responseGuidanceDefaults.defaultTraitIds`.
    // Same set across gendered variants — locale packages don't vary the
    // recommended trait set per gender today.
    personaConfigDefaultTraitIds: readonly string[];

    // Full trait registry the locale package exposes. Sourced from each
    // locale-package's `responseGuidanceDefaults.traits`. Read by the SDK
    // base layer to resolve operator-supplied trait IDs (including
    // locale-only IDs like `style-british-wording`) into runtime trait
    // records without importing the locale-package object graph.
    responseGuidanceTraits: readonly LocaleResponseGuidanceTrait[];
};

// Mirrors `VoiceLocaleResponseGuidanceTrait` from the integrations-builtin
// locale package. Defined locally to keep `LocaleDefaults` independent of
// the locale-package module — the agent runtime needs the trait records
// but should not depend on the package object graph.
export type LocaleResponseGuidanceTrait = {
    id: string;
    label: string;
    description?: string;
    promptContextHeading?: string;
    promptContent?: string | readonly string[];
    promptContentByChannel?: {
        voice?: string | readonly string[];
        text?: string | readonly string[];
    };
    category?: "base" | "behavior" | "demeanor" | "verbosity" | "delivery" | "tone";
    exclusiveGroup?: string;
    personalityTraitIDs?: readonly string[];
    progressIndicatorPrompt?: string;
    progressIndicatorExamples?: readonly string[];
};

// Voice persona definition in a locale's curated catalog. Mirrors
// `VoiceLocalePersonaDefinition` from the integrations-builtin locale
// package; defined locally so the catalog (and its UI consumers) do not
// depend on the locale-package object graph.
export type LocalePersonaDefinition<
    TPersona extends string = string,
    TVariant extends string = string,
> = {
    id: TPersona;
    label: string;
    variant: TVariant;
    description?: string;
    popular?: boolean;
    default?: boolean;
};

// Hand-curated description/popular overlays for a locale's generated
// persona definitions, authored in each locale's personas-metadata.ts.
export type LocalePersonaMetadata<TPersona extends string = string> = {
    [personaId in TPersona]?: {
        description?: string;
        popular?: boolean;
    };
};

export type GenderVariant = "feminine" | "masculine";

// Fields that vary across gendered variants. Sourced from each locale
// package's persona definitions and gendered copy maps (createDefaults
// output). Numeric/timing fields are shared (see LocaleSharedFields).
export type LocaleVariantFields = Pick<
    LocaleDefaults,
    | "defaultVoicePersona"
    | "defaultVoiceKeywords"
    | "defaultVoiceSynthesisRewrites"
    | "defaultVoiceGreeting"
    | "errorMessage"
    | "abuseDetectedTransferMessage"
    | "abuseDetectedTerminationMessage"
    | "inactivityPromptMessage"
    | "inactivityHangupMessage"
>;

// Fields shared across variants. Imported by gendered locale directories'
// shared.ts to avoid duplicating timing/PI/disabled config across both
// variant entries.
export type LocaleSharedFields = Omit<LocaleDefaults, keyof LocaleVariantFields>;

// Variant-aware default shape for gendered locales. The encoder consults
// the agent's stored variant on each supported locale to pick the right
// entry; the runtime SDK resolver never sees this shape — only the baked
// {<code>: {value: ...}} wire output.
export type LocaleDefaultsByVariant = {
    [V in GenderVariant]: LocaleDefaults;
};

// Discriminated union covering both shapes. Single-variant locales
// continue exporting a flat LocaleDefaults; gendered locales export
// {feminine, masculine}.
export type LocaleDefaultsExport = LocaleDefaults | LocaleDefaultsByVariant;

export function isLocaleDefaultsByVariant(
    value: LocaleDefaultsExport
): value is LocaleDefaultsByVariant {
    return (
        typeof value === "object" && value !== null && "feminine" in value && "masculine" in value
    );
}
