// Strict Gregorian date validity check used by locale-specific date synthesis
// rewrites. Returns false for invalid combinations (e.g. February 30, June 31)
// in addition to out-of-range months and days.
export function isValidGregorianDate(year: number, month: number, day: number): boolean {
    if (month < 1 || month > 12 || day < 1 || day > 31) {
        return false;
    }
    const date = new Date(Date.UTC(year, month - 1, day));
    return (
        date.getUTCFullYear() === year &&
        date.getUTCMonth() === month - 1 &&
        date.getUTCDate() === day
    );
}
