// ---------------------------------------------------------------------------
// Regexes (identical across dialects)
// ---------------------------------------------------------------------------

// Bare `$` is intentionally excluded; USD or other foreign currencies (e.g.
// `$500`, `US$500`) should not be rewritten as 港币 / 港幣.
const HKD_CURRENCY_REGEX =
    /(?:HKD|HK\$)\s*(?:(?:\d{1,3}(?:(?:,\d{3})+|\d*)(?:\.\d{1,2})?)|(?:\.\d{1,2}))(?![\d,.])/i;
// `¥` is technically also the JPY symbol; in a zh locale we treat it as RMB.
const RMB_CURRENCY_REGEX =
    /(?:RMB|CNY|￥|¥)\s*(?:(?:\d{1,3}(?:(?:,\d{3})+|\d*)(?:\.\d{1,2})?)|(?:\.\d{1,2}))(?![\d,.])/i;
// 8-digit Hong Kong local number, optional +852 country code.
const HK_PHONE_REGEX = /(?<!\d)(?:\+?852[ -]?)?[2-9]\d{3}[ -]?\d{4}(?!\d)/;
// 11-digit Mainland China mobile (1[3-9]XXXXXXXXX), optional +86 country code.
const MAINLAND_PHONE_REGEX = /(?<!\d)(?:\+?86[ -]?)?1[3-9]\d[ -]?\d{4}[ -]?\d{4}(?!\d)/;
// HK day-first: dd/mm/yyyy; falls back to mm/dd when dd/mm fails validation,
// matching th-TH's pattern.
const DAYFIRST_DATE_REGEX = /\b\d{1,2}[/-]\d{1,2}[/-](?:\d{4}|\d{2})\b/;
// Mainland / ISO year-first: yyyy-mm-dd or yyyy/mm/dd.
const YEARFIRST_DATE_REGEX = /\b\d{4}[/-]\d{1,2}[/-]\d{1,2}\b/;

// ---------------------------------------------------------------------------
// Number / date / amount helpers
// ---------------------------------------------------------------------------

function spellDigits(group: string): string {
    return [...group].map(d => DIGIT_WORDS[d] ?? d).join("");
}

// 10-19 uses 一十 after 百/千/万/萬 (e.g. 110 → 一百一十, not 一百十).
function spellUnder10k(n: number, inSubPosition: boolean = false): string {
    if (n === 0) {
        return "";
    }
    if (n < 10) {
        return DIGIT_WORDS[n.toString()];
    }
    if (n < 20) {
        const tensWord = inSubPosition ? "一十" : "十";
        return n === 10 ? tensWord : `${tensWord}${DIGIT_WORDS[(n - 10).toString()]}`;
    }
    if (n < 100) {
        const tens = Math.floor(n / 10);
        const ones = n % 10;
        const head = `${DIGIT_WORDS[tens.toString()]}十`;
        return ones === 0 ? head : `${head}${DIGIT_WORDS[ones.toString()]}`;
    }
    if (n < 1000) {
        const hundreds = Math.floor(n / 100);
        const rest = n % 100;
        const head = `${DIGIT_WORDS[hundreds.toString()]}百`;
        if (rest === 0) {
            return head;
        }
        if (rest < 10) {
            return `${head}零${spellUnder10k(rest, true)}`;
        }
        return `${head}${spellUnder10k(rest, true)}`;
    }
    const thousands = Math.floor(n / 1000);
    const rest = n % 1000;
    const head = `${DIGIT_WORDS[thousands.toString()]}千`;
    if (rest === 0) {
        return head;
    }
    if (rest < 100) {
        return `${head}零${spellUnder10k(rest, true)}`;
    }
    return `${head}${spellUnder10k(rest, true)}`;
}

function spellInteger(n: number, tenThousand: string): string {
    if (n === 0) {
        return "零";
    }
    if (n < 10000) {
        return spellUnder10k(n);
    }
    const wan = Math.floor(n / 10000);
    const rest = n % 10000;
    const head = `${spellInteger(wan, tenThousand)}${tenThousand}`;
    if (rest === 0) {
        return head;
    }
    if (rest < 1000) {
        return `${head}零${spellUnder10k(rest, true)}`;
    }
    return `${head}${spellUnder10k(rest, true)}`;
}

function spellNumberBelow100(n: number): string {
    if (n < 0 || n > 99) {
        return n.toString();
    }
    if (n === 0) {
        return "零";
    }
    if (n < 10) {
        return DIGIT_WORDS[n.toString()];
    }
    if (n === 10) {
        return "十";
    }
    if (n < 20) {
        return `十${DIGIT_WORDS[(n - 10).toString()]}`;
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    const tensWord = `${DIGIT_WORDS[tens.toString()]}十`;
    return ones === 0 ? tensWord : `${tensWord}${DIGIT_WORDS[ones.toString()]}`;
}

function spellAmount(
    intPart: number,
    cents: number,
    dialect: ZhDialectConfig,
    denoms: ZhCurrencyDenominations
): string {
    const parts: string[] = [];
    if (intPart > 0) {
        parts.push(`${spellInteger(intPart, dialect.tenThousand)}${denoms.dollar}`);
    }
    if (cents > 0) {
        const tens = Math.floor(cents / 10);
        const ones = cents % 10;
        if (tens > 0) {
            parts.push(`${DIGIT_WORDS[tens.toString()]}${denoms.tenCent}`);
        } else if (intPart > 0) {
            parts.push("零");
        }
        if (ones > 0) {
            parts.push(`${DIGIT_WORDS[ones.toString()]}${denoms.cent}`);
        }
    }
    if (parts.length === 0) {
        return denoms.zeroOnly;
    }
    return parts.join("");
}

function parseAmount(numeric: string): { integerPart: number; decimalCents: number } | null {
    const dotIdx = numeric.indexOf(".");
    const integerPartStr = dotIdx === -1 ? numeric : numeric.slice(0, dotIdx);
    const integerPart = integerPartStr === "" ? 0 : Number.parseInt(integerPartStr, 10);
    if (Number.isNaN(integerPart) || integerPart >= MAX_SPOKEN_AMOUNT) {
        return null;
    }
    let decimalCents = 0;
    if (dotIdx !== -1) {
        const decimalStr = numeric
            .slice(dotIdx + 1)
            .padEnd(2, "0")
            .slice(0, 2);
        decimalCents = Number.parseInt(decimalStr, 10);
        if (Number.isNaN(decimalCents)) {
            return null;
        }
    }
    return { integerPart, decimalCents };
}

function spellGregorianDate(year: number, month: number, day: number): string {
    const yearSpoken = year
        .toString()
        .split("")
        .map(d => DIGIT_WORDS[d])
        .join("");
    const monthSpoken = spellNumberBelow100(month);
    const daySpoken = spellNumberBelow100(day);
    return `${yearSpoken}年${monthSpoken}月${daySpoken}日`;
}

// ---------------------------------------------------------------------------
// Rewriter functions
// ---------------------------------------------------------------------------

function rewriteHkd(text: string, dialect: ZhDialectConfig): string {
    const numeric = text.replace(/^(?:HKD|HK\$)\s*/i, "").replace(/,/g, "");
    const parsed = parseAmount(numeric);
    if (parsed === null) {
        return text;
    }
    return `${dialect.hkdPrefix}${spellAmount(parsed.integerPart, parsed.decimalCents, dialect, dialect.hkdDenominations)}`;
}

function rewriteRmb(text: string, dialect: ZhDialectConfig): string {
    const numeric = text.replace(/^(?:RMB|CNY|￥|¥)\s*/i, "").replace(/,/g, "");
    const parsed = parseAmount(numeric);
    if (parsed === null) {
        return text;
    }
    return `${dialect.rmbPrefix}${spellAmount(parsed.integerPart, parsed.decimalCents, dialect, RMB_DENOMINATIONS)}`;
}

function rewriteHkPhone(text: string, dialect: ZhDialectConfig): string {
    const normalized = text.replace(/[ +-]/g, "");
    // Only treat a leading "852" as a country code when 3 extra digits were
    // supplied beyond the local 8-digit form (e.g. "8523 4567" is local).
    const hasCountryCode = normalized.length === 11 && normalized.startsWith("852");
    const trimmed = hasCountryCode ? normalized.slice(3) : normalized;
    if (trimmed.length !== 8 || !/^\d+$/.test(trimmed)) {
        return text;
    }
    const left = spellDigits(trimmed.slice(0, 4));
    const right = spellDigits(trimmed.slice(4, 8));
    return hasCountryCode
        ? `${dialect.internationalCallPrefix}八五二，${left}，${right}`
        : `${left}，${right}`;
}

function rewriteMainlandPhone(text: string, dialect: ZhDialectConfig): string {
    const normalized = text.replace(/[ +-]/g, "");
    const hasCountryCode = normalized.length === 13 && normalized.startsWith("86");
    const trimmed = hasCountryCode ? normalized.slice(2) : normalized;
    if (trimmed.length !== 11 || !/^1[3-9]\d{9}$/.test(trimmed)) {
        return text;
    }
    const head = spellDigits(trimmed.slice(0, 3));
    const mid = spellDigits(trimmed.slice(3, 7));
    const tail = spellDigits(trimmed.slice(7, 11));
    return hasCountryCode
        ? `${dialect.internationalCallPrefix}八六，${head}，${mid}，${tail}`
        : `${head}，${mid}，${tail}`;
}

function rewriteDayFirstDate(text: string): string {
    const separator = text.includes("/") ? "/" : "-";
    const [firstStr, secondStr, yearStr] = text.split(separator);
    const firstValue = Number.parseInt(firstStr, 10);
    const secondValue = Number.parseInt(secondStr, 10);
    const rawYear = Number.parseInt(yearStr, 10);
    if (Number.isNaN(firstValue) || Number.isNaN(secondValue) || Number.isNaN(rawYear)) {
        return text;
    }
    const year = yearStr.length === 2 ? (rawYear < 30 ? 2000 + rawYear : 1900 + rawYear) : rawYear;
    if (year < 1900 || year > 2099) {
        return text;
    }
    const dayMonth = isValidGregorianDate(year, secondValue, firstValue)
        ? { day: firstValue, month: secondValue }
        : isValidGregorianDate(year, firstValue, secondValue)
          ? { day: secondValue, month: firstValue }
          : null;
    if (!dayMonth) {
        return text;
    }
    return spellGregorianDate(year, dayMonth.month, dayMonth.day);
}

function rewriteYearFirstDate(text: string): string {
    const separator = text.includes("/") ? "/" : "-";
    const [yearStr, monthStr, dayStr] = text.split(separator);
    const year = Number.parseInt(yearStr, 10);
    const month = Number.parseInt(monthStr, 10);
    const day = Number.parseInt(dayStr, 10);
    if (Number.isNaN(year) || Number.isNaN(month) || Number.isNaN(day)) {
        return text;
    }
    if (year < 1900 || year > 2099 || !isValidGregorianDate(year, month, day)) {
        return text;
    }
    return spellGregorianDate(year, month, day);
}

// ---------------------------------------------------------------------------
// Rule-array factory
// ---------------------------------------------------------------------------

export function createZhSynthesisRules(dialect: ZhDialectConfig): LocaleSynthesisRewriteRuleImpl[] {
    return [
        {
            label: "HKD currency",
            description: `Replaces HKD/HK$ prefix with ${dialect.hkdPrefix} so ${dialect.dialectName} TTS reads the symbol naturally.`,
            playgroundSample: dialect.samples.hkdCurrency,
            pattern: HKD_CURRENCY_REGEX,
            replacement: t => rewriteHkd(t, dialect),
        },
        {
            label: "RMB currency",
            description: `Replaces RMB / CNY / ¥ prefix with ${dialect.rmbPrefix} so ${dialect.dialectName} TTS reads the symbol naturally. RMB amounts always use formal denominations 元/角/分.`,
            playgroundSample: dialect.samples.rmbCurrency,
            pattern: RMB_CURRENCY_REGEX,
            replacement: t => rewriteRmb(t, dialect),
        },
        {
            label: "ID acronym",
            description: `Spells out the standalone acronym 'ID' so ${dialect.dialectName} TTS doesn't read it as a Chinese character.`,
            playgroundSample: dialect.samples.idAcronym,
            pattern: /\bID\b/,
            replacement: "I D",
        },
        {
            label: "Hong Kong phone numbers",
            description: `Reads 8-digit Hong Kong phone numbers digit-by-digit in 4-4 blocks (${dialect.dialectName} digits).`,
            playgroundSample: dialect.samples.hkPhone,
            pattern: HK_PHONE_REGEX,
            replacement: t => rewriteHkPhone(t, dialect),
        },
        {
            label: "Mainland phone numbers",
            description: `Reads 11-digit Mainland China mobile numbers digit-by-digit in 3-4-4 blocks (${dialect.dialectName} digits), with optional +86 country code.`,
            playgroundSample: dialect.samples.mainlandPhone,
            pattern: MAINLAND_PHONE_REGEX,
            replacement: t => rewriteMainlandPhone(t, dialect),
        },
        {
            // Overrides the global `system:date` rule. Without this override,
            // the system rule's dash-form alternative — which only anchors `\b`
            // at the end — would match `26-12-31` inside `2026-12-31`,
            // splitting the chunk before our year-first rewriter sees the
            // leading `2026`.
            id: "system:date",
            label: "Year-first dates",
            description:
                "Converts yyyy-mm-dd / yyyy/mm/dd (Mainland and ISO convention) to spoken Chinese date (年月日).",
            playgroundSample: dialect.samples.yearFirstDate,
            pattern: YEARFIRST_DATE_REGEX,
            replacement: rewriteYearFirstDate,
        },
        {
            label: "Day-first dates",
            description: "Converts dd/mm/yyyy to spoken Chinese date (年月日).",
            playgroundSample: dialect.samples.dayFirstDate,
            pattern: DAYFIRST_DATE_REGEX,
            replacement: rewriteDayFirstDate,
        },
    ];
}
