import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";
import { spellNumberUnder100, spellWholeNumber } from "./numbers";

const AMOUNT_PATTERN = String.raw`\d{1,3}(?:(?:,\d{3})+|\d*)(?:\.\d{2})?`;
// Keep lowercase handling code-specific; a blanket case-insensitive [A-Z]{3}
// would block ordinary phrases like "$10 per month".
const COMMON_NON_AUD_CURRENCY_CODES = [
    "CAD",
    "CNY",
    "EUR",
    "GBP",
    "HKD",
    "JPY",
    "NZD",
    "SGD",
    "USD",
] as const;

function caseInsensitiveCodePattern(code: string): string {
    return [...code].map(char => `[${char}${char.toLowerCase()}]`).join("");
}

const AUD_CODE_PATTERN = caseInsensitiveCodePattern("AUD");
const COMMON_NON_AUD_CURRENCY_CODE_PATTERN = COMMON_NON_AUD_CURRENCY_CODES.map(
    caseInsensitiveCodePattern
).join("|");
const NON_AUD_PREFIX_GUARD = String.raw`(?<![A-Z]{3}\s)(?<!(?:${COMMON_NON_AUD_CURRENCY_CODE_PATTERN})\s)`;
const NON_AUD_SUFFIX_GUARD = String.raw`(?!\s?(?!${AUD_CODE_PATTERN}\b)(?:[A-Z]{3}|${COMMON_NON_AUD_CURRENCY_CODE_PATTERN})\b)`;
const CURRENCY_REGEX = new RegExp(
    String.raw`(?<![\p{L}\d])${NON_AUD_PREFIX_GUARD}-?(?:${AUD_CODE_PATTERN}\s?\$?${AMOUNT_PATTERN}|\$${AMOUNT_PATTERN}\s?${AUD_CODE_PATTERN}|(?:A\$|AU\$|\$)${AMOUNT_PATTERN}${NON_AUD_SUFFIX_GUARD})(?![\p{L}\d])`,
    "u"
);

function unitName(singular: string, amount: number): string {
    return amount === 1 ? singular : `${singular}s`;
}

function rewriteCurrencyForSynthesis(text: string): string {
    let remaining = text.trim();

    const negative = remaining.startsWith("-");
    if (negative) {
        remaining = remaining.slice(1);
    }

    const hasExplicitAudMarker =
        /^(?:AUD\b|A\$|AU\$)/i.test(remaining) || /\bAUD$/i.test(remaining);

    remaining = remaining.replace(/^AUD\s?/i, "");
    remaining = remaining.replace(/\s?AUD$/i, "");
    remaining = remaining.replace(/^(?:A\$|AU\$|\$)/i, "");

    if (!/^\d/.test(remaining)) {
        return text;
    }

    const dotIndex = remaining.indexOf(".");
    const wholePart = dotIndex === -1 ? remaining : remaining.slice(0, dotIndex);
    const whole = Number.parseInt(wholePart.replace(/,/g, ""), 10);
    const fraction = dotIndex === -1 ? 0 : Number.parseInt(remaining.slice(dotIndex + 1), 10);

    if (Number.isNaN(whole) || Number.isNaN(fraction)) {
        return text;
    }

    const parts: string[] = [];

    if (whole > 0) {
        const spokenWhole = spellWholeNumber(whole);
        if (!spokenWhole) {
            return text;
        }
        const dollarUnit = hasExplicitAudMarker ? "Australian dollar" : "dollar";
        parts.push(`${spokenWhole} ${unitName(dollarUnit, whole)}`);
    }

    if (fraction > 0) {
        const spokenFraction = spellNumberUnder100(fraction);
        if (!spokenFraction) {
            return text;
        }
        const centUnit = hasExplicitAudMarker && whole === 0 ? "Australian cent" : "cent";
        parts.push(`${spokenFraction} ${unitName(centUnit, fraction)}`);
    }

    if (parts.length === 0) {
        parts.push(`zero ${hasExplicitAudMarker ? "Australian dollars" : "dollars"}`);
    }

    return `${negative ? "minus " : ""}${parts.join(" and ")}`;
}

export const EN_AU_CURRENCY_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    id: "system:price",
    label: "Currency",
    description:
        "Converts AUD dollar amounts ($, A$, AU$, AUD) into fully spoken Australian English.",
    playgroundSample: "Your premium is $1,234.56, or AUD 1,234.56.",
    pattern: CURRENCY_REGEX,
    replacement: rewriteCurrencyForSynthesis,
};

// @visibleForTesting - exported for unit tests only; not part of the public API.
export {
    rewriteCurrencyForSynthesis as _rewriteCurrencyForSynthesis,
    CURRENCY_REGEX as _CURRENCY_REGEX,
};
