type BaseConstraint =
    | {
          type: "custom";
          validator: (value: any, ctx: any) => ValidationResult[] | boolean;
      }
    | {
          type: "message";
          message: string;
          severity: "error" | "warning";
          constraint: Constraint;
      }
    | {
          type: "type";
          of: "string" | "number" | "boolean" | "object" | "array" | "any";
          constraint: Constraint;
      }
    | {
          type: "list";
          constraints: Constraint[];
      }
    | {
          type: "optional";
          constraint: Constraint;
      };

type StringConstraint =
    | BaseConstraint
    | {
          type: "minLength";
          number: number;
      }
    | {
          type: "maxLength";
          number: number;
      }
    | {
          type: "regex";
          regex: string;
      };

type NumberConstraint =
    | BaseConstraint
    | {
          type: "min";
          number: number;
      }
    | {
          type: "max";
          number: number;
      };

type ArrayConstraint =
    | BaseConstraint
    | {
          type: "minLength";
          number: number;
      }
    | {
          type: "maxLength";
          number: number;
      };

export type Constraint = BaseConstraint | StringConstraint | NumberConstraint | ArrayConstraint;

export type ValidationResult = {
    severity?: "error" | "warning";
    message: string;
    path?: string[];
};

export interface Rule<T, FieldValue = unknown> {
    /**
     * Mark this rule as optional.
     */
    optional(): T;
    /**
     * Add a custom constraint.
     */
    custom(validator: (value: FieldValue, ctx: any) => ValidationResult[] | boolean): T;
    /**
     * When this rule is violated, yield an error message.
     */
    error(message: string): T;
    /**
     * When this rule is violated, yield a warning message.
     */
    warn(message: string): T;
    /**
     * Build the rule's constraints.
     */
    build(): Constraint;
}

export interface StringRule extends Rule<StringRule, string> {
    /**
     * Ensure the string is at least the given length.
     */
    minLength(value: number): StringRule;
    /**
     * Ensure the string is at most the given length.
     */
    maxLength(value: number): StringRule;
    /**
     * Ensure the string matches the given regex.
     */
    regex(value: RegExp): StringRule;
}

export interface NumberRule extends Rule<NumberRule, number> {
    /**
     * Ensure the number is at least the given value.
     */
    min(value: number): NumberRule;
    /**
     * Ensure the number is at most the given value.
     */
    max(value: number): NumberRule;
}

export interface ArrayRule extends Rule<ArrayRule, unknown[]> {
    minLength(value: number): ArrayRule;
    maxLength(value: number): ArrayRule;
}

export interface ObjectRule extends Rule<ObjectRule, { [key: string]: unknown }> {}

export interface GenericRule extends Rule<GenericRule, unknown> {}

interface CommonRuleOptions {
    constraints?: Constraint[];
    severity?: "error" | "warning";
    message?: string | null;
    optional?: boolean;
}

/**
 * A base class for building validation rules.
 */
export class CommonBuilder implements Rule<CommonBuilder> {
    protected constraints: Constraint[];
    protected severity: "error" | "warning" = "error";
    protected message: string | null;
    protected type?: "string" | "number" | "boolean" | "object" | "array" | "any";
    protected isOptional = false;

    constructor({ constraints, severity, message, optional }: CommonRuleOptions = {}) {
        this.constraints = constraints ?? [];
        this.severity = severity ?? "error";
        this.message = message ?? null;
        this.isOptional = optional ?? false;
    }

    protected clone(patch: Partial<CommonRuleOptions>): this {
        const Constructor = this.constructor as new (options: CommonRuleOptions) => this;
        const newInstance = new Constructor({
            constraints: patch.constraints ?? this.constraints,
            severity: patch.severity ?? this.severity,
            message: patch.message ?? this.message,
            optional: patch.optional ?? this.isOptional,
        });
        return newInstance;
    }

    protected addConstraint(constraint: Constraint): this {
        return this.clone({ constraints: [...this.constraints, constraint] });
    }

    optional(): this {
        return this.clone({ optional: true });
    }

    error(message: string): this {
        return this.clone({ severity: "error", message });
    }

    warn(message: string): this {
        return this.clone({ severity: "warning", message });
    }

    custom(validator: (value: any, ctx: any) => ValidationResult[] | boolean): this {
        return this.addConstraint({ type: "custom", validator });
    }

    build(): Constraint {
        let result: Constraint = {
            type: "list",
            constraints: this.constraints,
        };

        if (this.type) {
            result = {
                type: "type",
                of: this.type,
                constraint: result,
            };
        }

        if (this.message) {
            result = {
                type: "message",
                message: this.message,
                severity: this.severity,
                constraint: result,
            };
        }

        if (this.isOptional) {
            result = {
                type: "optional",
                constraint: result,
            };
        }

        return result;
    }
}

/**
 * A builder for string-specific validation rules.
 */
export class StringBuilder extends CommonBuilder implements StringRule {
    protected override type = "string" as const;

    minLength(value: number): this {
        return this.addConstraint({ type: "minLength", number: value });
    }
    maxLength(value: number): this {
        return this.addConstraint({ type: "maxLength", number: value });
    }
    regex(value: RegExp): this {
        return this.addConstraint({ type: "regex", regex: value.source });
    }
}

/**
 * A builder for number-specific validation rules.
 */
export class NumberBuilder extends CommonBuilder implements NumberRule {
    protected override type = "number" as const;

    min(value: number): this {
        return this.addConstraint({ type: "min", number: value });
    }
    max(value: number): this {
        return this.addConstraint({ type: "max", number: value });
    }
}

/**
 * A builder for array-specific validation rules.
 */
export class ArrayBuilder extends CommonBuilder implements ArrayRule {
    protected override type = "array" as const;

    minLength(value: number): this {
        return this.addConstraint({ type: "minLength", number: value });
    }
    maxLength(value: number): this {
        return this.addConstraint({ type: "maxLength", number: value });
    }
}

/**
 * A builder for object-specific validation rules.
 */
export class ObjectBuilder extends CommonBuilder implements ObjectRule {
    protected override type = "object" as const;
}

/**
 * A builder for generic validation rules.
 */
export class GenericBuilder extends CommonBuilder implements GenericRule {
    protected override type = "any" as const;
}

/** Dispatch table for validating constraints. */
type Validator = {
    [K in Constraint["type"]]?: (
        validator: Validator,
        constraint: Extract<Constraint, { type: K }>,
        value: any,
        document: any
    ) => ValidationResult[];
};

const genericValidator: Validator = {
    list: (validator, constraint, value, document) => {
        return constraint.constraints.reduce((acc: ValidationResult[], constraint) => {
            return [...acc, ...validateConstraint(validator, constraint, value, document)];
        }, []);
    },
    optional: (validator, constraint, value, document) => {
        if (value === undefined || value === null) {
            return [];
        }
        return validateConstraint(validator, constraint.constraint, value, document);
    },
    custom: (_, constraint, value, document) => {
        const res = constraint.validator(value, document);
        if (Array.isArray(res)) {
            return res;
        }
        return res ? [] : [{ message: "Validation failed" }];
    },
    message: (validator, constraint, value, document) => {
        const results = validateConstraint(validator, constraint.constraint, value, document);
        if (results.length > 0) {
            return [
                {
                    message: constraint.message,
                    severity: constraint.severity,
                },
            ];
        } else {
            return [];
        }
    },
    type: (_, constraint, value, document) => {
        if (!typeChecks[constraint.of](value)) {
            return [
                {
                    message: `Value is not a ${constraint.of}`,
                    severity: "error",
                },
            ];
        }
        return validateConstraint(
            typeValidators[constraint.of] ?? genericValidator,
            constraint.constraint,
            value,
            document
        );
    },
};

const typeChecks = {
    string: (value: any) => typeof value === "string",
    number: (value: any) => typeof value === "number",
    boolean: (value: any) => typeof value === "boolean",
    object: (value: any) => typeof value === "object",
    array: (value: any) => Array.isArray(value),
    any: (value: any) => true,
};

function validateConstraint(
    validator: Validator,
    constraint: Constraint,
    value: any,
    document: any
): ValidationResult[] {
    return validator[constraint.type]!(validator, constraint as any, value, document);
}

const stringValidator: Validator = {
    ...genericValidator,
    minLength: (_, constraint, value) => {
        if ((value as string).length < constraint.number) {
            return [
                {
                    message: `Must be at least ${constraint.number} characters`,
                    severity: "error",
                },
            ];
        }
        return [];
    },
    maxLength: (_, constraint, value) => {
        if ((value as string).length > constraint.number) {
            return [
                {
                    message: `Must be at most ${constraint.number} characters`,
                    severity: "error",
                },
            ];
        }
        return [];
    },
    regex: (_, constraint, value) => {
        const regex = new RegExp(constraint.regex);
        if (!regex.test(value as string)) {
            return [
                {
                    message: `Must match regex ${constraint.regex}`,
                    severity: "error",
                },
            ];
        }
        return [];
    },
};

const numberValidator: Validator = {
    ...genericValidator,
    min: (_, constraint, value) => {
        if (value < constraint.number) {
            return [
                {
                    message: `Must be at least ${constraint.number}`,
                    severity: "error",
                },
            ];
        }
        return [];
    },
    max: (_, constraint, value) => {
        if (value > constraint.number) {
            return [
                {
                    message: `Must be at most ${constraint.number}`,
                    severity: "error",
                },
            ];
        }
        return [];
    },
};

const arrayValidator: Validator = {
    ...genericValidator,
    minLength: (_, constraint, value) => {
        if ((value as any[]).length < constraint.number) {
            return [
                {
                    message: `Must be at least ${constraint.number} items`,
                    severity: "error",
                },
            ];
        }
        return [];
    },
    maxLength: (_, constraint, value) => {
        if ((value as any[]).length > constraint.number) {
            return [
                {
                    message: `Must be at most ${constraint.number} items`,
                    severity: "error",
                },
            ];
        }
        return [];
    },
};

const typeValidators = {
    string: stringValidator,
    number: numberValidator,
    boolean: null,
    object: genericValidator,
    array: arrayValidator,
    any: genericValidator,
};

export type ValidationBuilder<T extends Rule<T, FieldValue>, FieldValue = unknown> = (
    rule: T
) => T | T[];

export function validate(constraint: Constraint, value: any, document: any): ValidationResult[] {
    return validateConstraint(genericValidator, constraint, value, document);
}
