import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

// ---------------------------------------------------------------------------
// Shared French digit / number words
//
// Metropolitan and Canadian French share the same number rules, so the
// helpers below — DIGIT_WORDS, BELOW_SEVENTEEN, TENS, spellFrBelowHundred,
// spellFrBelowThousand, spellFrInteger — mirror the ones in
// `locale-fr-ca/synthesis-rewrites.ts`. Keep the two copies in sync when you
// touch French number spelling.
//
// `synthesis-rewrite-definitions.ts` registers the same digit/letter/symbol
// vocabulary with the SDK so any `<platform-spell>` tag that appears in
// fr-FR content (emitted directly by the LLM, or by future rule migrations)
// renders with the right per-locale words. The rules below still emit literal
// French words today because TTS pacing of `<platform-spell>` digit blocks
// reads less naturally than open prose on the providers we ship to.
// ---------------------------------------------------------------------------

const MONTH_NAMES = [
    "janvier",
    "février",
    "mars",
    "avril",
    "mai",
    "juin",
    "juillet",
    "août",
    "septembre",
    "octobre",
    "novembre",
    "décembre",
] as const;

const DIGIT_WORDS = [
    "zéro",
    "un",
    "deux",
    "trois",
    "quatre",
    "cinq",
    "six",
    "sept",
    "huit",
    "neuf",
] as const;

const BELOW_SEVENTEEN = [
    "zéro",
    "un",
    "deux",
    "trois",
    "quatre",
    "cinq",
    "six",
    "sept",
    "huit",
    "neuf",
    "dix",
    "onze",
    "douze",
    "treize",
    "quatorze",
    "quinze",
    "seize",
] as const;

const TENS = {
    20: "vingt",
    30: "trente",
    40: "quarante",
    50: "cinquante",
    60: "soixante",
} as const;

function spellFrBelowHundred(value: number): string | null {
    if (!Number.isInteger(value) || value < 0 || value >= 100) {
        return null;
    }

    if (value <= 16) {
        return BELOW_SEVENTEEN[value] ?? null;
    }

    if (value < 20) {
        return `dix-${BELOW_SEVENTEEN[value - 10]}`;
    }

    if (value < 70) {
        const tens = Math.floor(value / 10) * 10;
        const ones = value % 10;
        const tensWord = TENS[tens as keyof typeof TENS];
        if (ones === 0) {
            return tensWord;
        }
        if (ones === 1) {
            return `${tensWord} et un`;
        }
        const onesWord = spellFrBelowHundred(ones);
        return onesWord ? `${tensWord}-${onesWord}` : null;
    }

    if (value < 80) {
        const remainder = value - 60;
        if (remainder === 11) {
            return "soixante et onze";
        }
        const remainderWord = spellFrBelowHundred(remainder);
        return remainderWord ? `soixante-${remainderWord}` : null;
    }

    if (value === 80) {
        return "quatre-vingts";
    }

    const remainder = value - 80;
    if (remainder === 1) {
        return "quatre-vingt-un";
    }
    const remainderWord = spellFrBelowHundred(remainder);
    return remainderWord ? `quatre-vingt-${remainderWord}` : null;
}

function spellFrBelowThousand(value: number): string | null {
    if (!Number.isInteger(value) || value < 0 || value >= 1000) {
        return null;
    }

    if (value < 100) {
        return spellFrBelowHundred(value);
    }

    const hundreds = Math.floor(value / 100);
    const remainder = value % 100;
    const hundredsPrefix =
        hundreds === 1 ? "cent" : `${spellFrBelowHundred(hundreds) ?? ""} cent`.trim();
    if (!hundredsPrefix) {
        return null;
    }

    if (remainder === 0) {
        return hundreds > 1 ? `${hundredsPrefix}s` : hundredsPrefix;
    }

    const remainderWord = spellFrBelowHundred(remainder);
    return remainderWord ? `${hundredsPrefix} ${remainderWord}` : null;
}

// French grammar: "cent" and "vingt" take a final -s when multiplied
// ("deux cents", "quatre-vingts") UNLESS they are followed by another
// numeral adjective like "mille". They KEEP the -s before nouns such as
// "million" and "milliard", which are nouns rather than adjectives. So
// "cinq cent mille" (no -s) but "cinq cents millions" (with -s).
function stripFinalSBeforeMille(word: string): string {
    return word.replace(/(cent|vingt)s$/, "$1");
}

function spellFrInteger(value: number): string | null {
    if (!Number.isSafeInteger(value) || value < 0 || value >= 1_000_000_000_000) {
        return null;
    }

    if (value < 1000) {
        return spellFrBelowThousand(value);
    }

    if (value < 1_000_000) {
        const thousands = Math.floor(value / 1000);
        const remainder = value % 1000;
        let thousandsWord: string;
        if (thousands === 1) {
            thousandsWord = "mille";
        } else {
            const thousandsRoot = spellFrBelowThousand(thousands);
            if (!thousandsRoot) {
                return null;
            }
            thousandsWord = `${stripFinalSBeforeMille(thousandsRoot)} mille`;
        }
        if (remainder === 0) {
            return thousandsWord;
        }
        const remainderWord = spellFrBelowThousand(remainder);
        return remainderWord ? `${thousandsWord} ${remainderWord}` : null;
    }

    if (value < 1_000_000_000) {
        const millions = Math.floor(value / 1_000_000);
        const remainder = value % 1_000_000;
        const millionsRoot = spellFrBelowThousand(millions);
        if (!millionsRoot) {
            return null;
        }
        const millionsWord = `${millions === 1 ? "un" : millionsRoot} million${millions > 1 ? "s" : ""}`;
        if (remainder === 0) {
            return millionsWord;
        }
        const remainderWord = spellFrInteger(remainder);
        return remainderWord ? `${millionsWord} ${remainderWord}` : null;
    }

    // 10^9 – 10^12 - 1: French "milliard" (= short-scale billion).
    // "million" and "milliard" are nouns, so "cent" keeps the -s before
    // them ("deux cents milliards"). No `stripFinalSBeforeMille` here.
    const billions = Math.floor(value / 1_000_000_000);
    const remainder = value % 1_000_000_000;
    const billionsRoot = spellFrBelowThousand(billions);
    if (!billionsRoot) {
        return null;
    }
    const billionsWord = `${billions === 1 ? "un" : billionsRoot} milliard${billions > 1 ? "s" : ""}`;
    if (remainder === 0) {
        return billionsWord;
    }
    const remainderWord = spellFrInteger(remainder);
    return remainderWord ? `${billionsWord} ${remainderWord}` : null;
}

function isValidGregorianDate(year: number, month: number, day: number): boolean {
    if (month < 1 || month > 12 || day < 1 || day > 31) {
        return false;
    }

    const date = new Date(Date.UTC(year, month - 1, day));
    return (
        date.getUTCFullYear() === year &&
        date.getUTCMonth() === month - 1 &&
        date.getUTCDate() === day
    );
}

function spellDateDay(day: number): string | null {
    if (day < 1 || day > 31) {
        return null;
    }
    if (day === 1) {
        return "premier";
    }
    return spellFrInteger(day);
}

// Spell a 2-digit pair. Pairs starting with '0' are read digit-by-digit
// ("zéro un", "zéro six"); other pairs are spoken as a 2-digit French
// number ("vingt-trois", "soixante-sept"). Used by both the phone-number
// reading and the postal-code département pair.
function spellTwoDigitPair(pair: string): string | null {
    if (pair.length !== 2 || /\D/.test(pair)) {
        return null;
    }
    if (pair.startsWith("0")) {
        return `${DIGIT_WORDS[0]} ${DIGIT_WORDS[Number.parseInt(pair[1], 10)]}`;
    }
    return spellFrBelowHundred(Number.parseInt(pair, 10)) ?? null;
}

// ---------------------------------------------------------------------------
// Date normalisation (Metropolitan French day-first dates)
//
// Mirrors the UK day-first date coverage: slash and dash separators, with
// either a four-digit or two-digit year. Two-digit years resolve against a
// 1940 cutoff (00..39 → 2000..2039; 40..99 → 1940..1999). We override the
// SDK's `system:date` rule by id because the SDK regex (1) lacks a leading
// word-boundary needed for dash forms and (2) no-ops for non-`en-*` locales
// anyway. Without the override, dates like "24/06/2021" would either be
// fragmented by the SDK or pass through unrewritten.
// ---------------------------------------------------------------------------

const FR_FR_DATE_REGEX = /(?:\ble\s+)?\b\d{1,2}([/-])\d{1,2}\1\d{2}(?:\d{2})?\b/iu;
const FR_FR_TWO_DIGIT_YEAR_CUTOFF = 40;

function maybeStripLeadingLe(text: string): { hadLeadingLe: boolean; raw: string } {
    const normalized = text.trimStart();
    if (/^le\s+/iu.test(normalized)) {
        return { hadLeadingLe: true, raw: normalized.replace(/^le\s+/iu, "") };
    }
    return { hadLeadingLe: false, raw: normalized };
}

function resolveYear(yearText: string): number | null {
    if (!/^\d{2}(?:\d{2})?$/.test(yearText)) {
        return null;
    }
    const year = Number.parseInt(yearText, 10);
    if (Number.isNaN(year)) {
        return null;
    }
    if (yearText.length === 4) {
        return year;
    }
    return year < FR_FR_TWO_DIGIT_YEAR_CUTOFF ? 2000 + year : 1900 + year;
}

function rewriteFrFrDateForSynthesis(text: string): string {
    const { hadLeadingLe, raw } = maybeStripLeadingLe(text);
    const separator = raw.includes("/") ? "/" : raw.includes("-") ? "-" : null;
    if (!separator) {
        return text;
    }
    const parts = raw.split(separator);
    if (parts.length !== 3) {
        return text;
    }

    const day = Number.parseInt(parts[0], 10);
    const month = Number.parseInt(parts[1], 10);
    const year = resolveYear(parts[2]);
    if (Number.isNaN(day) || Number.isNaN(month) || year === null) {
        return text;
    }
    if (!isValidGregorianDate(year, month, day)) {
        return text;
    }

    const spokenDay = spellDateDay(day);
    const spokenYear = spellFrInteger(year);
    const monthName = MONTH_NAMES[month - 1];
    if (!spokenDay || !spokenYear) {
        return text;
    }

    // Preserve the leading "le" article from the input. Adding "le" when the
    // input didn't have it produces ungrammatical French after contractive
    // prepositions ("du 24/06/2021" would become "du le vingt-quatre juin…").
    const prefix = hadLeadingLe ? "le " : "";
    return `${prefix}${spokenDay} ${monthName} ${spokenYear}`;
}

// ---------------------------------------------------------------------------
// Phone number normalisation (Metropolitan French)
//
// Matches:
// - Local 10-digit form starting with 0 (e.g. 0123456789, 01 23 45 67 89,
//   01.23.45.67.89, 01-23-45-67-89). Read as five 2-digit groups: a pair
//   starting with '0' is read digit-by-digit ("zéro un") because that's how
//   French speakers pronounce it; the other pairs are spoken as 2-digit
//   numbers ("vingt-trois", "soixante-sept", "quatre-vingt-neuf").
// - International +33 form (e.g. +33 6 12 34 56 78). The prefix is preserved
//   and spoken as "plus trente-trois"; the 9 national digits that follow are
//   read as one single-digit group ("six") then four 2-digit groups.
// - International 0033 form (e.g. 0033 6 60 12 34 56). The prefix is spoken
//   as "zéro zéro, trente-trois"; the 9 national digits are read the same
//   way as the +33 form.
//
// We don't distinguish mobile (06/07), landline (01-05), or special numbers
// (08/09) in the spoken output.
// ---------------------------------------------------------------------------

const FR_FR_PHONE_REGEX =
    /(?<!\d)(?:(?:\+33|0033)[ .-]?[1-9](?:[ .-]?\d{2}){4}|0[1-9](?:[ .-]?\d{2}){4})(?!\d)/;

function spellNationalDigits(nationalDigits: string): string[] | null {
    // International form: read first national digit as its own group, then
    // four 2-digit groups.
    if (nationalDigits.length !== 9 || /\D/.test(nationalDigits)) {
        return null;
    }
    const first = nationalDigits[0];
    const firstDigit = Number.parseInt(first, 10);
    if (Number.isNaN(firstDigit)) {
        return null;
    }
    const groups: string[] = [DIGIT_WORDS[firstDigit]];
    for (let i = 1; i < nationalDigits.length; i += 2) {
        const spoken = spellTwoDigitPair(nationalDigits.slice(i, i + 2));
        if (!spoken) {
            return null;
        }
        groups.push(spoken);
    }
    return groups;
}

function rewriteFrFrPhoneForSynthesis(text: string): string {
    const digits = text.replace(/[ .-]/g, "");

    if (digits.startsWith("+33")) {
        const national = digits.slice(3);
        const groups = spellNationalDigits(national);
        if (!groups) {
            return text;
        }
        return ["plus trente-trois", ...groups].join(", ");
    }

    if (digits.startsWith("0033")) {
        const national = digits.slice(4);
        const groups = spellNationalDigits(national);
        if (!groups) {
            return text;
        }
        return ["zéro zéro, trente-trois", ...groups].join(", ");
    }

    // Local 10-digit form.
    if (digits.length !== 10 || !digits.startsWith("0") || /\D/.test(digits)) {
        return text;
    }
    const pairs: string[] = [];
    for (let i = 0; i < digits.length; i += 2) {
        const spoken = spellTwoDigitPair(digits.slice(i, i + 2));
        if (!spoken) {
            return text;
        }
        pairs.push(spoken);
    }
    return pairs.join(", ");
}

// ---------------------------------------------------------------------------
// Postal code normalisation (5-digit French postal codes, "2 + 3" with pause)
//
// The first two digits are spoken as a 2-digit number ("soixante-quinze")
// because they identify the département, which French speakers pronounce as a
// number. The last three digits preserve meaningful leading zeros, but still
// use a natural pair when possible ("59030" → ".. zéro trente", "75001" →
// ".. zéro zéro un").
//
// To avoid overmatching unrelated 5-digit identifiers (order numbers,
// reference codes, vouchers), the regex only matches the voice-only
// `<PostCode>...</PostCode>` marker emitted by fr-FR response guidance.
// ---------------------------------------------------------------------------

const FR_FR_POSTAL_CODE_REGEX = /<PostCode>\s*\d{5}\s*<\/PostCode>/iu;
const FR_FR_POSTAL_CODE_WITH_CAPTURE_REGEX = /<PostCode>\s*(\d{5})\s*<\/PostCode>/iu;

function rewriteFrFrPostalCodeForSynthesis(text: string): string {
    if (!/^\d{5}$/.test(text)) {
        return text;
    }
    const department = spellTwoDigitPair(text.slice(0, 2));
    if (!department) {
        return text;
    }
    // If the 3-digit commune suffix has no leading zero (i.e. it reads as a
    // number from 100–999), say it as the compound French number: "432" →
    // "quatre cent trente-deux", "400" → "quatre cents", "100" → "cent".
    // Suffixes with a meaningful leading zero preserve that zero. For the
    // common 0YY shape, say "zéro" plus the final two-digit pair ("030" →
    // "zéro trente"). For 00Y / 000, fall back to digit-by-digit below.
    const commune = text.slice(2);
    if (!commune.startsWith("0")) {
        const communeWord = spellFrBelowThousand(Number.parseInt(commune, 10));
        if (communeWord) {
            return `${department}, ${communeWord}`;
        }
    }
    if (/^0[1-9]\d$/.test(commune)) {
        const pair = spellTwoDigitPair(commune.slice(1));
        if (pair) {
            return `${department}, zéro ${pair}`;
        }
    }
    // Otherwise the 3-digit commune code preserves meaningful leading zeros
    // ("75001" Paris 1er, "01000" Bourg-en-Bresse). Wrap the digits in a
    // `<platform-spell>` tag so the SDK renders each digit using the fr-FR
    // digit definitions registered in `synthesis-rewrite-definitions.ts`,
    // giving Cartesia/Azure provider-native spell+break pacing and plain-
    // text providers the spelled-out French words.
    return `${department}, <platform-spell>${commune}</platform-spell>`;
}

function rewriteFrFrPostalCodeTagForSynthesis(text: string): string {
    const match = text.match(FR_FR_POSTAL_CODE_WITH_CAPTURE_REGEX);
    if (!match) {
        return text;
    }

    return rewriteFrFrPostalCodeForSynthesis(match[1]);
}

// ---------------------------------------------------------------------------
// Currency normalisation
//
// Matches the common French-written forms:
//   - suffix symbol/code/word with optional comma decimal:
//     "1 234,56 €", "1234 EUR", "49,99 euros", "123,45 $"
//   - prefix symbol: "€1 234", "$123,45", "£1 234,56"
//
// Uses Unicode-aware non-letter assertions `(?<![\p{L}\d])` and
// `(?![\p{L}])` instead of `\b` because JavaScript's `\b` is ASCII-only and
// would fire false boundaries adjacent to accented French letters — making
// the regex match inside words like "crédit", "crémeux", "EUREKA", or
// "europe".
// ---------------------------------------------------------------------------

const FR_FR_CURRENCY_REGEX =
    /(?<![\p{L}\d.,])(?:-?(?:\d{1,3}(?:[ \u00A0.]\d{3})+|\d+)(?:,\d{1,2})?\s?(?:[€$£]|EUR|euros?)|[€$£]\s?-?(?:\d{1,3}(?:[ \u00A0.]\d{3})+|\d+)(?:,\d{1,2})?)(?![\p{L}])/iu;

type CurrencySymbol = "€" | "$" | "£";

type CurrencyNames = {
    singular: string;
    plural: string;
    partitivePlural: string;
    subunitSingular: string;
    subunitPlural: string;
};

const CURRENCY_NAMES: { [key in CurrencySymbol]: CurrencyNames } = {
    "€": {
        singular: "euro",
        plural: "euros",
        partitivePlural: "d'euros",
        subunitSingular: "centime",
        subunitPlural: "centimes",
    },
    $: {
        singular: "dollar",
        plural: "dollars",
        partitivePlural: "de dollars",
        subunitSingular: "cent",
        subunitPlural: "cents",
    },
    "£": {
        singular: "livre sterling",
        plural: "livres sterling",
        partitivePlural: "de livres sterling",
        subunitSingular: "penny",
        subunitPlural: "pence",
    },
};

function normalizeCurrencySymbol(raw: string): CurrencySymbol {
    if (raw === "$" || raw === "£") {
        return raw;
    }
    return "€";
}

function rewriteFrFrCurrencyForSynthesis(text: string): string {
    let body = text.trim();

    // The minus may sit before or after the currency symbol — pick it up
    // from whichever side it appears on.
    let negative = false;
    if (body.startsWith("-")) {
        negative = true;
        body = body.slice(1).trim();
    }
    let currencySymbol: CurrencySymbol | null = null;
    const prefixCurrency = body.match(/^[€$£]/u);
    if (prefixCurrency) {
        currencySymbol = normalizeCurrencySymbol(prefixCurrency[0]);
        body = body.slice(1).trim();
        if (body.startsWith("-")) {
            negative = true;
            body = body.slice(1).trim();
        }
    }
    const suffixCurrency = body.match(/\s?([€$£]|EUR|euros?)$/iu);
    if (suffixCurrency) {
        currencySymbol = currencySymbol ?? normalizeCurrencySymbol(suffixCurrency[1]);
        body = body.slice(0, suffixCurrency.index).trim();
    }
    if (!currencySymbol) {
        return text;
    }
    const currencyNames = CURRENCY_NAMES[currencySymbol];

    // Strip thousands separators (regular space, NBSP, period).
    body = body.replace(/[ \u00A0.]/g, "");

    const [wholePart, fractionPart = ""] = body.split(",");
    const whole = Number.parseInt(wholePart, 10);
    if (Number.isNaN(whole)) {
        return text;
    }

    let fraction = 0;
    if (fractionPart) {
        const padded = fractionPart.length === 1 ? `${fractionPart}0` : fractionPart;
        fraction = Number.parseInt(padded, 10);
        if (Number.isNaN(fraction)) {
            return text;
        }
    }

    const parts: string[] = [];
    if (whole > 0) {
        const spokenWhole = spellFrInteger(whole);
        if (!spokenWhole) {
            return text;
        }
        // "million" and "milliard" are nouns, so when the spoken integer ends
        // in one of them ("un million", "deux milliards"), French inserts the
        // preposition before the unit: "un million d'euros",
        // "un million de dollars". Plain "mille" is an adjective and doesn't
        // take "de".
        const unit = whole === 1 ? currencyNames.singular : currencyNames.plural;
        const needsElision = /\b(?:millions?|milliards?)$/.test(spokenWhole);
        parts.push(`${spokenWhole} ${needsElision ? currencyNames.partitivePlural : unit}`);
    }
    if (fraction > 0) {
        const spokenFraction = spellFrInteger(fraction);
        if (!spokenFraction) {
            return text;
        }
        parts.push(
            `${spokenFraction} ${
                fraction === 1 ? currencyNames.subunitSingular : currencyNames.subunitPlural
            }`
        );
    }
    if (parts.length === 0) {
        parts.push(`zéro ${currencyNames.singular}`);
    }

    return `${negative ? "moins " : ""}${parts.join(" et ")}`;
}

// ---------------------------------------------------------------------------
// Rule ordering matters
//
// Date → Phone → Currency → Postal code. Postal codes are gated behind an
// explicit `<PostCode>...</PostCode>` marker, so bare 5-digit phones,
// currency amounts, and reference numbers pass through their own rules.
// ---------------------------------------------------------------------------

