import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

function caseAwareReplacement(replacement: string): (match: string) => string {
    return (match: string) => {
        if (/^\p{Lu}/u.test(match)) {
            return `${replacement.charAt(0).toUpperCase()}${replacement.slice(1)}`;
        }
        return replacement;
    };
}

// ---------------------------------------------------------------------------
// Currency normalisation (Finnish euros / cents)
// ---------------------------------------------------------------------------

// Matches Finnish euro amounts with optional minus, optional thousands
// separators, optional comma decimals, and either a trailing "€" / "EUR" or a
// leading "€". This deliberately does not match the full word "euroa", which
// is already the long spoken form we want the model to emit when possible.
const FI_FI_CURRENCY_REGEX =
    /(?<![\d–—-])-?(?:(?:\d{1,3}(?:[ .]\d{3})+|\d{1,9})(?:,\d{1,2})?\s?(?:€|[eE][uU][rR](?![\p{L}]))|€\s?(?:\d{1,3}(?:[ .]\d{3})+|\d{1,9})(?:,\d{1,2})?)/u;

function rewriteFiFiCurrencyForSynthesis(text: string): string {
    let body = text.trim();
    const negative = body.startsWith("-");
    if (negative) {
        body = body.slice(1).trimStart();
    }
    body = body
        .replace(/^€\s?/, "")
        .replace(/\s?(?:€|EUR)$/i, "")
        .trim();
    body = body.replace(/[ .]/g, "");

    const [wholePart, fractionPart = ""] = body.split(",");
    const whole = Number.parseInt(wholePart, 10);
    if (Number.isNaN(whole)) {
        return text;
    }

    let fraction = 0;
    if (fractionPart) {
        const padded = fractionPart.length === 1 ? `${fractionPart}0` : fractionPart;
        fraction = Number.parseInt(padded, 10);
        if (Number.isNaN(fraction)) {
            return text;
        }
    }

    const parts: string[] = [];
    if (whole > 0) {
        parts.push(`${whole} ${whole === 1 ? "euro" : "euroa"}`);
    }
    if (fraction > 0) {
        parts.push(`${fraction} ${fraction === 1 ? "sentti" : "senttiä"}`);
    }
    if (parts.length === 0) {
        parts.push("nolla euroa");
    }

    return `${negative ? "miinus " : ""}${parts.join(" ja ")}`;
}

// ---------------------------------------------------------------------------
// Percentage normalisation
// ---------------------------------------------------------------------------

const FI_FI_PERCENTAGE_REGEX =
    /(?<![\d–—-])(?<sign>[+-])?(?<amount>\d+(?:[,.]\d+)?)\s?%(?::(?<suffix>n|iin|sta))?(?![\p{L}-])/u;

function rewriteFiFiPercentageForSynthesis(text: string): string {
    const match = FI_FI_PERCENTAGE_REGEX.exec(text);
    const amount = match?.groups?.["amount"];
    if (!amount) {
        return text;
    }

    const sign = match.groups?.["sign"];
    const prefix = sign === "-" ? "miinus " : sign === "+" ? "plus " : "";
    const normalizedAmount = amount.replace(".", ",");
    const value = Number.parseFloat(amount.replace(",", "."));

    switch (match.groups?.["suffix"]) {
        case "n":
            return `${prefix}${normalizedAmount} prosentin`;
        case "iin":
            return `${prefix}${normalizedAmount} prosenttiin`;
        case "sta":
            return `${prefix}${normalizedAmount} prosentista`;
        default:
            return `${prefix}${normalizedAmount} ${value === 1 ? "prosentti" : "prosenttia"}`;
    }
}

// ---------------------------------------------------------------------------
// Common abbreviation normalisation
// ---------------------------------------------------------------------------

const FI_FI_TIME_ABBREVIATION_REGEX = /(?<![\p{L}])klo\.?(?![\p{L}])/giu;
const FI_FI_HOUSING_COMPANY_ABBREVIATION_REGEX =
    /(?<![\p{L}])(?:as\.?\s+oy|asunto\s+oy)(?::(?<suffix>n|lle|ssä))?(?![\p{L}])/giu;

function rewriteFiFiHousingCompanyAbbreviationForSynthesis(text: string): string {
    const suffix = /:(n|lle|ssä)$/iu.exec(text)?.[1]?.toLowerCase();
    const replacement =
        suffix === "n"
            ? "asunto-osakeyhtiön"
            : suffix === "lle"
              ? "asunto-osakeyhtiölle"
              : suffix === "ssä"
                ? "asunto-osakeyhtiössä"
                : "asunto-osakeyhtiö";
    return caseAwareReplacement(replacement)(text);
}

const FI_FI_VAT_ABBREVIATION_REGEX = /(?<![\p{L}])alv(?::(?<suffix>n|ia|ssa|tä))?(?![\p{L}-])/giu;

function rewriteFiFiVatAbbreviationForSynthesis(text: string): string {
    switch (/:(n|ia|ssa|tä)$/iu.exec(text)?.[1]?.toLowerCase()) {
        case "n":
            return "alvin";
        case "ia":
        case "tä":
            return "alvia";
        case "ssa":
            return "alvissa";
        default:
            return "alvi";
    }
}

