import { isValidGregorianDate } from "../../common/synthesis-rewrites/gregorian-date";
import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

const ARGENTINA_NUMERIC_DATE_REGEX =
    /\b(?:(\d{1,2}\/\d{1,2}\/(\d{4}|\d{2}))|(\d{1,2}-\d{1,2}-(\d{4}|\d{2})))\b/;
const SPANISH_MONTH_NAMES = [
    "enero",
    "febrero",
    "marzo",
    "abril",
    "mayo",
    "junio",
    "julio",
    "agosto",
    "septiembre",
    "octubre",
    "noviembre",
    "diciembre",
] as const;
const SPANISH_ONES = [
    "",
    "uno",
    "dos",
    "tres",
    "cuatro",
    "cinco",
    "seis",
    "siete",
    "ocho",
    "nueve",
] as const;
const SPANISH_TEENS = [
    "diez",
    "once",
    "doce",
    "trece",
    "catorce",
    "quince",
    "dieciséis",
    "diecisiete",
    "dieciocho",
    "diecinueve",
] as const;
const SPANISH_TENS = [
    "",
    "",
    "veinte",
    "treinta",
    "cuarenta",
    "cincuenta",
    "sesenta",
    "setenta",
    "ochenta",
    "noventa",
] as const;
const SPANISH_TWENTIES = [
    "",
    "veintiuno",
    "veintidós",
    "veintitrés",
    "veinticuatro",
    "veinticinco",
    "veintiséis",
    "veintisiete",
    "veintiocho",
    "veintinueve",
] as const;

function spellSpanishNumberBelow100(value: number): string | null {
    if (value < 0 || value >= 100) {
        return null;
    }
    if (value < 10) {
        return SPANISH_ONES[value] || null;
    }
    if (value < 20) {
        return SPANISH_TEENS[value - 10] || null;
    }
    if (value < 30) {
        return value === 20 ? "veinte" : SPANISH_TWENTIES[value - 20] || null;
    }

    const tens = Math.floor(value / 10);
    const ones = value % 10;
    if (ones === 0) {
        return SPANISH_TENS[tens] || null;
    }

    return `${SPANISH_TENS[tens]} y ${SPANISH_ONES[ones]}`;
}

function spellSpanishDay(day: number): string | null {
    if (day < 1 || day > 31) {
        return null;
    }
    if (day === 1) {
        return "primero";
    }
    return spellSpanishNumberBelow100(day);
}

function spellSpanishYear(year: number): string | null {
    if (year === 2000) {
        return "dos mil";
    }
    if (year > 2000 && year < 2100) {
        const suffix = spellSpanishNumberBelow100(year - 2000);
        return suffix ? `dos mil ${suffix}` : null;
    }
    if (year === 1900) {
        return "mil novecientos";
    }
    if (year > 1900 && year < 2000) {
        const suffix = spellSpanishNumberBelow100(year - 1900);
        return suffix ? `mil novecientos ${suffix}` : null;
    }
    return null;
}

function rewriteSpanishArgentinaDateForSynthesis(text: string): string {
    const separator = text.includes("/") ? "/" : text.includes("-") ? "-" : null;
    if (!separator) {
        return text;
    }

    const [firstPart, secondPart, yearPart] = text.split(separator);
    const firstValue = Number.parseInt(firstPart, 10);
    const secondValue = Number.parseInt(secondPart, 10);
    const rawYear = Number.parseInt(yearPart, 10);

    if (Number.isNaN(firstValue) || Number.isNaN(secondValue) || Number.isNaN(rawYear)) {
        return text;
    }

    const year = yearPart.length === 2 ? 2000 + rawYear : rawYear;
    const dayMonthYear = isValidGregorianDate(year, secondValue, firstValue)
        ? { day: firstValue, month: secondValue }
        : isValidGregorianDate(year, firstValue, secondValue)
          ? { day: secondValue, month: firstValue }
          : null;

    if (!dayMonthYear) {
        return text;
    }

    const spokenDay = spellSpanishDay(dayMonthYear.day);
    const spokenMonth = SPANISH_MONTH_NAMES[dayMonthYear.month - 1];
    const spokenYear = spellSpanishYear(year);
    if (!spokenDay || !spokenYear) {
        return text;
    }

    return `${spokenDay} de ${spokenMonth} de ${spokenYear}`;
}

export const ES_AR_DEFAULT_SYNTHESIS_REWRITE_RULES: LocaleSynthesisRewriteRuleImpl[] = [
    {
        label: "Date normalization",
        description:
            "Converts numeric dates into fully spoken Spanish, assuming Argentinian standard formatting of DD/MM/YYYY. Falls back to MM/DD/YYYY if only valid option.",
        playgroundSample: "La reunión será el 04/02/2026 en la oficina de Buenos Aires.",
        pattern: ARGENTINA_NUMERIC_DATE_REGEX,
        replacement: rewriteSpanishArgentinaDateForSynthesis,
    },
];
