import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

const EN_US_PRICE_REGEX = /(^|\s)(-?[$£€]\d{1,3}((,\d{3})*|\d*)(\.\d{2})?)\b/;
const EN_US_DATE_REGEX = /\b(\d{1,2}\/\d{1,2}\/(\d{4}|\d{2}))|(\d{1,2}-\d{1,2}-(\d{4}|\d{2}))\b/;
const EN_US_DAY_RANGE_REGEX =
    /\b(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)\s*-\s*(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)\b/;
const EN_US_TIME_RANGE_REGEX =
    /\b(1[0-2]|0?[1-9])(:[0-5][0-9])?\s?(AM|PM)?\s*-\s*(1[0-2]|0?[1-9])(:[0-5][0-9])?\s?(AM|PM)?\b/i;
const EN_US_EMAIL_REGEX = /([\w.+-]+)@([a-zA-Z\d.-]+)\.([a-zA-Z]{2,6})/;

type RewriteOptions = { [key: string]: unknown };

type CurrencyName = {
    singular: string;
    plural: string;
    subunitSingular: string;
    subunitPlural: string;
};

const CURRENCY_NAMES: { [key: string]: CurrencyName | undefined } = {
    $: { singular: "dollar", plural: "dollars", subunitSingular: "cent", subunitPlural: "cents" },
    "£": { singular: "pound", plural: "pounds", subunitSingular: "penny", subunitPlural: "pence" },
    "€": { singular: "euro", plural: "euros", subunitSingular: "cent", subunitPlural: "cents" },
};

const LESS_THAN_TWENTY = [
    "zero",
    "one",
    "two",
    "three",
    "four",
    "five",
    "six",
    "seven",
    "eight",
    "nine",
    "ten",
    "eleven",
    "twelve",
    "thirteen",
    "fourteen",
    "fifteen",
    "sixteen",
    "seventeen",
    "eighteen",
    "nineteen",
] as const;

const TENS = ["", "", "twenty", "thirty", "forty", "fifty", "sixty", "seventy", "eighty", "ninety"];
const THOUSANDS = ["", "thousand", "million", "billion"];
const TWENTY_FIRST_CENTURY_THRESHOLD = 30;
const MONTHS = [
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
] as const;

function optionString(options: RewriteOptions, key: string): string | undefined {
    const value = options[key];
    return typeof value === "string" ? value : undefined;
}

function isSupportedEnglishLocale(locale: string = ""): boolean {
    return locale.length === 0 || locale.startsWith("en");
}

function spellOutSmallNumber(num: number): string {
    if (num === 0) {
        return "";
    } else if (num < 20) {
        return `${LESS_THAN_TWENTY[num]} `;
    } else if (num < 100) {
        return `${TENS[Math.floor(num / 10)]} ${spellOutSmallNumber(num % 10)}`;
    }
    return `${LESS_THAN_TWENTY[Math.floor(num / 100)]} hundred ${spellOutSmallNumber(num % 100)}`;
}

function spellOutNumber(num: number): string {
    let result = "";
    for (let i = 0; num > 0; i++) {
        num = Math.round(num);
        if (num % 1000 !== 0) {
            result = `${spellOutSmallNumber(num % 1000) + THOUSANDS[i]} ${result}`;
        }
        num = Math.floor(num / 1000);
    }
    return result.trim();
}

function rewriteEnUsPriceForSynthesis(origPrice: string, options: RewriteOptions): string {
    if (!isSupportedEnglishLocale(optionString(options, "locale"))) {
        return origPrice;
    }
    const submatches = EN_US_PRICE_REGEX.exec(origPrice);
    if (!submatches || submatches.length < 3) {
        return origPrice;
    }
    const leadingSpace = submatches[1];
    let trimmedPrice = submatches[2];
    if (trimmedPrice.length < 1) {
        return origPrice;
    }
    let negative = false;
    if (trimmedPrice.startsWith("-")) {
        negative = true;
        trimmedPrice = trimmedPrice.slice(1);
    }
    const prefix = trimmedPrice[0];
    const currencyName = CURRENCY_NAMES[prefix];
    if (!currencyName) {
        return origPrice;
    }
    const priceParts = trimmedPrice.slice(prefix.length).split(".");
    const whole = Number.parseInt(priceParts[0].replace(/,/g, ""), 10);
    if (Number.isNaN(whole)) {
        return origPrice;
    }

    let unit = whole === 1 ? currencyName.singular : currencyName.plural;
    let rewrittenPriceParts: string[] = [];
    if (whole > 0) {
        rewrittenPriceParts.push(`${spellOutNumber(whole)} ${unit}`);
    }
    if (priceParts.length > 1) {
        const fraction = Number.parseInt(priceParts[1], 10);
        if (Number.isNaN(fraction)) {
            return origPrice;
        }
        if (fraction > 0) {
            if (fraction === 99 && whole > 0) {
                rewrittenPriceParts = [`${spellOutNumber(whole)} ninety-nine`];
            } else {
                unit = fraction === 1 ? currencyName.subunitSingular : currencyName.subunitPlural;
                rewrittenPriceParts.push(`${spellOutNumber(fraction)} ${unit}`);
            }
        }
    }

    let pricePrefix = leadingSpace;
    if (rewrittenPriceParts.length === 0) {
        rewrittenPriceParts.push(`zero ${unit}`);
    } else if (negative) {
        pricePrefix += "negative ";
    }
    return pricePrefix + rewrittenPriceParts.join(" and ");
}

function normalizeEnUsDate(dateParts: string[]): Date | null {
    const month = Number.parseInt(dateParts[0], 10);
    const day = Number.parseInt(dateParts[1], 10);
    let year = Number.parseInt(dateParts[2], 10);
    if (Number.isNaN(month) || Number.isNaN(day) || Number.isNaN(year)) {
        return null;
    }
    if (year < 100) {
        year = year < TWENTY_FIRST_CENTURY_THRESHOLD ? 2000 + year : 1900 + year;
    }
    if (year < 1900) {
        return null;
    }

    const date = new Date(year, month - 1, day);
    if (date.getFullYear() !== year || date.getMonth() !== month - 1 || date.getDate() !== day) {
        return null;
    }
    return date;
}

function rewriteEnUsDateForSynthesis(origDate: string, options: RewriteOptions): string {
    if (!isSupportedEnglishLocale(optionString(options, "locale"))) {
        return origDate;
    }
    const parts = origDate.includes("/") ? origDate.split("/") : origDate.split("-");
    const date = normalizeEnUsDate(parts);
    if (date === null) {
        return origDate;
    }
    return `${MONTHS[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`;
}

function rewriteEnUsRangeForSynthesis(origRange: string, options: RewriteOptions): string {
    if (!isSupportedEnglishLocale(optionString(options, "locale"))) {
        return origRange;
    }
    const rangeParts = origRange.split("-");
    return `${rangeParts[0].trimEnd()} to ${rangeParts[1].trimStart()}`;
}

function spellOutPunctuation(text: string): string {
    return text
        .replace(/\+/g, " plus ")
        .replace(/_/g, " underscore ")
        .replace(/-/g, " hyphen ")
        .replace(/\./g, " dot ");
}

function rewriteEnUsEmailForSynthesis(text: string, options: RewriteOptions): string {
    if (!isSupportedEnglishLocale(optionString(options, "locale"))) {
        return text;
    }
    const emailParts = text.split("@");
    if (emailParts.length < 2) {
        return text;
    }
    return `${spellOutPunctuation(emailParts[0])} at ${spellOutPunctuation(emailParts[1])}`;
}

export const EN_US_DATE_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "Date",
    description: "Reads numeric month/day/year dates as spoken US English dates.",
    playgroundSample: "Your subscription will be active until 10/08/2025.",
    pattern: EN_US_DATE_REGEX,
    replacement: rewriteEnUsDateForSynthesis,
};

export const EN_US_DAY_RANGE_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "Day range",
    description: 'Reads weekday ranges with "to" instead of a hyphen.',
    playgroundSample: "Our associates are available Monday-Friday.",
    pattern: EN_US_DAY_RANGE_REGEX,
    replacement: rewriteEnUsRangeForSynthesis,
};

export const EN_US_TIME_RANGE_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "Time range",
    description: 'Reads time ranges with "to" instead of a hyphen.',
    playgroundSample: "We are open 9AM-5PM.",
    pattern: EN_US_TIME_RANGE_REGEX,
    replacement: rewriteEnUsRangeForSynthesis,
};

export const EN_US_PRICE_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "Price",
    description: "Reads common dollar, pound, and euro prices as spoken amounts.",
    playgroundSample: "Your order total was $1,137.09.",
    pattern: EN_US_PRICE_REGEX,
    replacement: rewriteEnUsPriceForSynthesis,
};

export const EN_US_EMAIL_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "Email",
    description: "Reads email punctuation as words.",
    playgroundSample: "The order email is julie+second_t@test.com.",
    pattern: EN_US_EMAIL_REGEX,
    replacement: rewriteEnUsEmailForSynthesis,
};

// Rewrites the US retirement-account term so synthesizers read it as
// "four oh one kay" instead of "four hundred one k" or "four zero one k".
// Matches 401k, 401K, 401(k), 401(K), and "401 k".
export const EN_US_401K_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    label: "401(k)",
    description: 'Reads "401k" and "401(k)" as "four oh one kay".',
    playgroundSample: "Your 401k contribution is on track.",
    pattern: /(?<![$\w])401(?:\s?\(\s*k\s*\)|\s?k)(?=s\b|[^\w]|$)/gi,
    replacement: "four oh one kay",
};

export const EN_US_DEFAULT_SYNTHESIS_REWRITE_RULES: LocaleSynthesisRewriteRuleImpl[] = [
    EN_US_DATE_REWRITE,
    EN_US_DAY_RANGE_REWRITE,
    EN_US_TIME_RANGE_REWRITE,
    EN_US_PRICE_REWRITE,
    EN_US_EMAIL_REWRITE,
    EN_US_401K_REWRITE,
];
