// Synthesis-rewrite rule types owned by locale-defaults. These are intentionally
// independent of core/voice and of the legacy integrations-builtin locale-package
// layer: @sierra/content-schema is a leaf package imported by the generated public
// SDK bundle and by web (via the @sdk/* alias), so importing core/voice here would
// drag the entire core SDK + JSX namespace into those compilations. The rules still
// flow into core's voice engine by structural compatibility with core/voice's
// SynthesisRewriteRule (enforced at the base-agent consumption sites).

export type LocaleSynthesisRewriteReplacement =
    | string
    | ((text: string, options: { [key: string]: unknown }) => string);

// Raw rule implementation shape. `id` is optional here; the canonical id is
// assigned by defineLocaleSynthesisRewriteRules.
export type LocaleSynthesisRewriteRuleImpl = {
    id?: string;
    label?: string;
    description?: string;
    playgroundSample?: string;
    pattern: string | RegExp;
    replacement: LocaleSynthesisRewriteReplacement;
};

export type LocaleSynthesisRewriteRule = LocaleSynthesisRewriteRuleImpl & {
    id: string;
};

export type LocaleSynthesisRewriteRuleDefinition = {
    id: string;
    rule: LocaleSynthesisRewriteRuleImpl;
    expectedLabel?: string;
};

export function defineLocaleSynthesisRewriteRules(
    definitions: LocaleSynthesisRewriteRuleDefinition[]
): LocaleSynthesisRewriteRule[] {
    const seen = new Set<string>();
    return definitions.map(({ id, rule, expectedLabel }) => {
        if (seen.has(id)) {
            throw new Error(`Duplicate synthesis rewrite rule ID "${id}"`);
        }
        seen.add(id);
        if (rule.id && rule.id !== id) {
            throw new Error(
                `Synthesis rewrite rule "${expectedLabel ?? id}" has id "${rule.id}", expected "${id}"`
            );
        }
        if (expectedLabel && rule.label !== expectedLabel) {
            throw new Error(
                `Synthesis rewrite rule "${id}" has label "${rule.label ?? ""}", expected "${expectedLabel}"`
            );
        }
        return { ...rule, id };
    });
}

export function getLocaleSynthesisRewriteRuleIds(
    rules: readonly LocaleSynthesisRewriteRule[]
): string[] {
    return rules.map(rule => rule.id);
}
