import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";
import { ES_ES_SYNTHESIS_REWRITE_DEFINITIONS } from "../synthesis-rewrite-definitions";

type SpellDefinitions = {
    letters: { [letter: string]: string | undefined };
    digits: { [digit: string]: { text: string } | undefined };
    spokenSymbols: { [symbol: string]: string | undefined };
};

const DIGITS = [
    "cero",
    "uno",
    "dos",
    "tres",
    "cuatro",
    "cinco",
    "seis",
    "siete",
    "ocho",
    "nueve",
] as const;

const MONTHS = [
    "enero",
    "febrero",
    "marzo",
    "abril",
    "mayo",
    "junio",
    "julio",
    "agosto",
    "septiembre",
    "octubre",
    "noviembre",
    "diciembre",
] as const;

const ONES = [
    "",
    "uno",
    "dos",
    "tres",
    "cuatro",
    "cinco",
    "seis",
    "siete",
    "ocho",
    "nueve",
] as const;

const TEENS = [
    "diez",
    "once",
    "doce",
    "trece",
    "catorce",
    "quince",
    "dieciséis",
    "diecisiete",
    "dieciocho",
    "diecinueve",
] as const;

const TENS = [
    "",
    "",
    "veinte",
    "treinta",
    "cuarenta",
    "cincuenta",
    "sesenta",
    "setenta",
    "ochenta",
    "noventa",
] as const;

const TWENTIES = [
    "",
    "veintiuno",
    "veintidós",
    "veintitrés",
    "veinticuatro",
    "veinticinco",
    "veintiséis",
    "veintisiete",
    "veintiocho",
    "veintinueve",
] as const;

const HUNDREDS = [
    "",
    "ciento",
    "doscientos",
    "trescientos",
    "cuatrocientos",
    "quinientos",
    "seiscientos",
    "setecientos",
    "ochocientos",
    "novecientos",
] as const;

function spellNumberBelow100(value: number): string | null {
    if (value < 0 || value >= 100) {
        return null;
    }
    if (value < 10) {
        return DIGITS[value];
    }
    if (value < 20) {
        return TEENS[value - 10];
    }
    if (value < 30) {
        return value === 20 ? "veinte" : TWENTIES[value - 20];
    }
    const tens = Math.floor(value / 10);
    const ones = value % 10;
    return ones === 0 ? TENS[tens] : `${TENS[tens]} y ${ONES[ones]}`;
}

function spellWholeNumber(value: number): string | null {
    if (value < 0 || value >= 1_000_000) {
        return null;
    }
    if (value < 100) {
        return spellNumberBelow100(value);
    }
    if (value === 100) {
        return "cien";
    }
    if (value < 1000) {
        const hundreds = Math.floor(value / 100);
        const rest = value % 100;
        const prefix = HUNDREDS[hundreds];
        if (!prefix) {
            return null;
        }
        return rest === 0 ? prefix : `${prefix} ${spellNumberBelow100(rest)}`;
    }
    if (value === 1000) {
        return "mil";
    }
    if (value < 1_000_000) {
        const thousands = Math.floor(value / 1000);
        const rest = value % 1000;
        const thousandsText = spellWholeNumber(thousands);
        if (!thousandsText) {
            return null;
        }
        const prefix = thousands === 1 ? "mil" : `${masculineCountText(thousandsText)} mil`;
        return rest === 0 ? prefix : `${prefix} ${spellWholeNumber(rest)}`;
    }
    return null;
}

const SPELL_DEFINITIONS: SpellDefinitions = ES_ES_SYNTHESIS_REWRITE_DEFINITIONS.spell;

function spellIdentifierChar(ch: string): string {
    const digit = Number.parseInt(ch, 10);
    if (!Number.isNaN(digit) && digit >= 0 && digit <= 9) {
        return SPELL_DEFINITIONS.digits[ch]?.text ?? DIGITS[digit];
    }
    return SPELL_DEFINITIONS.letters[ch.toUpperCase()] ?? ch.toUpperCase();
}

function spellIdentifier(value: string): string {
    return value.replace(/[\s-]/g, "").split("").map(spellIdentifierChar).join(" ");
}

const ES_ES_DATE_REGEX = /\b(?:\d{1,2}[/-]\d{1,2}[/-]\d{2,4}|\d{4}-\d{1,2}-\d{1,2})\b/g;
const ES_ES_SLASH_DATE_REGEX = /\b(\d{1,2})[/-](\d{1,2})[/-](\d{2,4})\b/;
const ES_ES_ISO_DATE_REGEX = /\b(\d{4})-(\d{1,2})-(\d{1,2})\b/;

function rewriteDate(text: string): string {
    const slashMatch = text.match(ES_ES_SLASH_DATE_REGEX);
    const isoMatch = slashMatch ? null : text.match(ES_ES_ISO_DATE_REGEX);
    if (!slashMatch && !isoMatch) {
        return text;
    }
    const day = Number.parseInt(slashMatch ? slashMatch[1] : isoMatch![3], 10);
    const month = Number.parseInt(slashMatch ? slashMatch[2] : isoMatch![2], 10);
    const rawYear = Number.parseInt(slashMatch ? slashMatch[3] : isoMatch![1], 10);
    if (month < 1 || month > 12) {
        return text;
    }
    const year = rawYear < 100 ? 2000 + rawYear : rawYear;
    const dayText = spellWholeNumber(day);
    const yearText = spellWholeNumber(year);
    const monthText = MONTHS[month - 1];
    if (!dayText || !yearText) {
        return text;
    }
    return `${dayText} de ${monthText} de ${yearText}`;
}

const ES_ES_TIME_REGEX = /(?:(?:a\s+)?las\s+)?\b(?:[01]?\d|2[0-3]):[0-5]\d\b/gi;
const ES_ES_PARSE_TIME_REGEX = /^(?:(a\s+)?las\s+)?([01]?\d|2[0-3]):([0-5]\d)$/i;

function clockHourText(hour24: number): string | null {
    const hour12 = hour24 % 12 || 12;
    return hour12 === 1 ? "una" : spellWholeNumber(hour12);
}

function clockPrefix({
    hour24,
    hasArticlePrefix,
    hasPrepositionPrefix,
}: {
    hour24: number;
    hasArticlePrefix: boolean;
    hasPrepositionPrefix: boolean;
}): string {
    if (hasPrepositionPrefix) {
        return hour24 % 12 === 1 ? "a la " : "a las ";
    }
    if (hasArticlePrefix) {
        return hour24 % 12 === 1 ? "la " : "las ";
    }
    return "";
}

function dayPartForHour(hour24: number): string {
    if (hour24 < 6) {
        return " de la madrugada";
    }
    if (hour24 < 20) {
        return "";
    }
    return " de la noche";
}

function rewriteTime(text: string): string {
    const match = text.match(ES_ES_PARSE_TIME_REGEX);
    if (!match) {
        return text;
    }
    const hasArticlePrefix = /\blas\s+/i.test(match[0]);
    const hasPrepositionPrefix = /^a\s+las\s+/i.test(match[0]);
    const hour24 = Number.parseInt(match[2], 10);
    const minute = Number.parseInt(match[3], 10);

    if (hour24 === 0 && minute === 0) {
        return hasPrepositionPrefix ? "a medianoche" : "medianoche";
    }
    if (hour24 === 12 && minute === 0) {
        return hasPrepositionPrefix ? "a mediodía" : "mediodía";
    }

    const hourText = clockHourText(hour24);
    if (!hourText) {
        return text;
    }
    const prefix = clockPrefix({ hour24, hasArticlePrefix, hasPrepositionPrefix });
    const dayPart = dayPartForHour(hour24);

    if (minute === 0) {
        return `${prefix}${hourText} en punto${dayPart}`;
    }
    if (minute === 15) {
        return `${prefix}${hourText} y cuarto${dayPart}`;
    }
    if (minute === 30) {
        return `${prefix}${hourText} y media${dayPart}`;
    }
    if (minute < 30) {
        const minuteText = spellWholeNumber(minute);
        return minuteText ? `${prefix}${hourText} y ${minuteText}${dayPart}` : text;
    }

    const nextHour24 = (hour24 + 1) % 24;
    const nextHourText = clockHourText(nextHour24);
    const remainingMinutes = 60 - minute;
    const remainingText = remainingMinutes === 15 ? "cuarto" : spellWholeNumber(remainingMinutes);
    if (!nextHourText || !remainingText) {
        return text;
    }
    const nextPrefix = clockPrefix({
        hour24: nextHour24,
        hasArticlePrefix,
        hasPrepositionPrefix,
    });
    return `${nextPrefix}${nextHourText} menos ${remainingText}${dayPart}`;
}

const ES_ES_EURO_REGEX =
    /-?(?:€\s?\d{1,3}(?:(?:\.\d{3})+|\d*)(?:,\d{1,2})?(?![\d,]|\.\d)|\d{1,3}(?:(?:\.\d{3})+|\d*)(?:,\d{1,2})?(?![\d,]|\.\d)\s?€)/g;

function parseSpanishAmount(raw: string): { euros: number; cents: number } | null {
    const numeric = raw.replace(/[€\s]/g, "").replace(/\.(?=\d{3}(?:\D|$))/g, "");
    const normalized = numeric.replace(",", ".");
    const [eurosPart, centsPart = ""] = normalized.split(".");
    const euros = Number.parseInt(eurosPart, 10);
    const cents = Number.parseInt(centsPart.padEnd(2, "0").slice(0, 2) || "0", 10);
    if (Number.isNaN(euros) || Number.isNaN(cents)) {
        return null;
    }
    return { euros: Math.abs(euros), cents };
}

function masculineCountText(text: string): string {
    if (text === "uno") {
        return "un";
    }
    if (text.endsWith("veintiuno")) {
        return `${text.slice(0, -"veintiuno".length)}veintiún`;
    }
    if (text.endsWith(" y uno")) {
        return `${text.slice(0, -" y uno".length)} y un`;
    }
    if (text.endsWith(" uno")) {
        return `${text.slice(0, -" uno".length)} un`;
    }
    return text;
}

function rewriteEuroAmount(text: string): string {
    const negative = text.trim().startsWith("-");
    const amount = parseSpanishAmount(text);
    if (!amount) {
        return text;
    }
    const euroText = spellWholeNumber(amount.euros);
    const centText = spellWholeNumber(amount.cents);
    if (!euroText || !centText) {
        return text;
    }
    const parts: string[] = [];
    if (amount.euros > 0) {
        parts.push(`${masculineCountText(euroText)} ${amount.euros === 1 ? "euro" : "euros"}`);
    }
    if (amount.cents > 0) {
        parts.push(
            `${masculineCountText(centText)} ${amount.cents === 1 ? "céntimo" : "céntimos"}`
        );
    }
    if (parts.length === 0) {
        parts.push("cero euros");
    }
    return `${negative ? "menos " : ""}${parts.join(" con ")}`;
}

const ES_ES_IDENTIFIER_REGEX =
    /\b(?:\d{8}[- ]?[A-Z]|[XYZ][- ]?\d{7}[- ]?[A-Z]|[ABCDEFGHJKLMNPQRSUVW][- ]?\d{7}[- ]?[0-9A-J])\b/gi;

const ES_ES_PHONE_REGEX = /(?<!\d)(?:(?:\+34|0034|34)[ -]?)?[6789](?:[ -]?\d){8}(?!\d)/g;

function rewritePhoneNumber(text: string): string {
    const normalized = text.replace(/[ -]/g, "");
    const hasPlusPrefix = normalized.startsWith("+34");
    const hasInternationalPrefix =
        hasPlusPrefix || normalized.startsWith("0034") || normalized.startsWith("34");
    const digits = hasPlusPrefix
        ? normalized.slice(3)
        : normalized.startsWith("0034")
          ? normalized.slice(4)
          : normalized.startsWith("34")
            ? normalized.slice(2)
            : normalized;
    if (digits.length !== 9 || /\D/.test(digits)) {
        return text;
    }
    const groups = [digits.slice(0, 3), digits.slice(3, 6), digits.slice(6, 9)];
    const spoken = groups.map(spellIdentifier).join(", ");
    return hasInternationalPrefix ? `más treinta y cuatro, ${spoken}` : spoken;
}

const ES_ES_DATA_AMOUNT_REGEX = /\b\d{1,3}\s?GBs?\b/gi;
const ES_ES_PARSE_DATA_AMOUNT_REGEX = /\b(\d{1,3})\s?GBs?\b/i;

function rewriteDataAmount(text: string): string {
    const match = text.match(ES_ES_PARSE_DATA_AMOUNT_REGEX);
    const amount = match ? Number.parseInt(match[1], 10) : Number.NaN;
    const amountText = Number.isNaN(amount) ? null : spellWholeNumber(amount);
    return amountText ? `${amountText} gigas` : text;
}

const ES_ES_LONG_DIGIT_REGEX = /(?<![+\d])\d(?:[ -]?\d){6,}(?!\d)/g;

function rewriteLongDigits(text: string): string {
    const digits = text.replace(/[ -]/g, "");
    if (digits.length < 7 || /\D/.test(digits)) {
        return text;
    }
    return digits.split("").map(spellIdentifierChar).join(" ");
}

const ES_ES_STANDALONE_NUMBER_REGEX = /(?<![\w@.,/:-])\d{1,6}(?![\w@./:-]|,\d)/g;

function rewriteStandaloneNumber(text: string): string {
    const value = Number.parseInt(text.replace(/\./g, ""), 10);
    if (!Number.isFinite(value)) {
        return text;
    }
    return spellWholeNumber(value) ?? text;
}

