import { isValidGregorianDate } from "../../common/synthesis-rewrites/gregorian-date";
import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

// ---------------------------------------------------------------------------
// Shared Norwegian digit / number words
// ---------------------------------------------------------------------------

const NB_NO_DIGIT_WORDS = [
    "null",
    "en",
    "to",
    "tre",
    "fire",
    "fem",
    "seks",
    "sju",
    "åtte",
    "ni",
] as const;

// "ett" / "to" / ... / "ni" — used for the "X tusen" / "Y hundre" prefixes
// where Norwegian neuter agreement requires "ett tusen" (not "en tusen").
const NB_NO_ONES: { readonly [key: number]: string | undefined } = {
    1: "ett",
    2: "to",
    3: "tre",
    4: "fire",
    5: "fem",
    6: "seks",
    7: "sju",
    8: "åtte",
    9: "ni",
};

const NB_NO_TEENS: { readonly [key: number]: string | undefined } = {
    10: "ti",
    11: "elleve",
    12: "tolv",
    13: "tretten",
    14: "fjorten",
    15: "femten",
    16: "seksten",
    17: "sytten",
    18: "atten",
    19: "nitten",
};

const NB_NO_TENS: { readonly [key: number]: string | undefined } = {
    2: "tjue",
    3: "tretti",
    4: "førti",
    5: "femti",
    6: "seksti",
    7: "sytti",
    8: "åtti",
    9: "nitti",
};

// Spell 1..99 in Norwegian using modern compound forms ("tjuefem"). Used ONLY
// for year readouts in dates. The ones digit takes the common-gender cardinal
// form (NB_NO_DIGIT_WORDS — "en", "tjueen"), NOT the neuter "ett" that the
// "ett tusen" / "ett hundre" prefixes use: 2001 reads "to tusen og en" and
// 2021 reads "to tusen og tjueen". The currency and large-number rules
// deliberately keep 2-digit remainders as digits — Norwegian TTS stresses
// compound number words incorrectly ("førtini" lands wrong), so amounts and
// reference numbers should never be spelled with compounds. Years are an
// exception because they're well-rehearsed in TTS training data. Do not extend
// compound spelling to the currency or large-number paths.
function spellNbNoOneToNinetyNine(n: number): string | null {
    if (n < 1 || n > 99) {
        return null;
    }
    if (n < 10) {
        return NB_NO_DIGIT_WORDS[n];
    }
    if (n < 20) {
        return NB_NO_TEENS[n] ?? null;
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    const tensWord = NB_NO_TENS[tens];
    if (!tensWord) {
        return null;
    }
    if (ones === 0) {
        return tensWord;
    }
    return `${tensWord}${NB_NO_DIGIT_WORDS[ones]}`;
}

// Caller guarantees `ch` is an ASCII digit (the postcode and phone rewrites
// strip whitespace and check the length / digit-only invariant before calling).
function spellDigit(ch: string): string {
    return NB_NO_DIGIT_WORDS[Number.parseInt(ch, 10)];
}

// ---------------------------------------------------------------------------
// Date normalisation (dd.mm.yyyy, Norwegian convention)
// ---------------------------------------------------------------------------

// Norwegian dates use dots: "14.05.2026". The SDK's `system:date` rule only
// matches slash and dash separators, so we register this rule WITHOUT the
// `id: "system:date"` override — it complements the SDK rule rather than
// replacing it. (sv-SE differs: ISO yyyy-mm-dd collides with the SDK's
// dash-form regex and must override by id.)
const NB_NO_DATE_REGEX = /\b\d{1,2}\.\d{1,2}\.\d{4}\b/;

const NB_NO_MONTH_NAMES = [
    "januar",
    "februar",
    "mars",
    "april",
    "mai",
    "juni",
    "juli",
    "august",
    "september",
    "oktober",
    "november",
    "desember",
] as const;

const NB_NO_ORDINAL_DAYS = [
    "",
    "første",
    "andre",
    "tredje",
    "fjerde",
    "femte",
    "sjette",
    "sjuende",
    "åttende",
    "niende",
    "tiende",
    "ellevte",
    "tolvte",
    "trettende",
    "fjortende",
    "femtende",
    "sekstende",
    "syttende",
    "attende",
    "nittende",
    "tjuende",
    "tjueførste",
    "tjueandre",
    "tjuetredje",
    "tjuefjerde",
    "tjuefemte",
    "tjuesjette",
    "tjuesjuende",
    "tjueåttende",
    "tjueniende",
    "trettiende",
    "trettiførste",
] as const;

// Norwegian year convention: "to tusen og tjueseks" for 2026, "nitten hundre
// og nitti" for 1990, "to tusen" for 2000. The leading "og" before the
// remainder is the canonical nb-vs-sv divergence (Swedish drops it).
function spellNbNoYear(year: number): string | null {
    if (year < 1900 || year > 2099) {
        return null;
    }
    if (year === 2000) {
        return "to tusen";
    }
    const century = Math.floor(year / 100);
    const remainder = year % 100;
    const centuryWord = century === 19 ? "nitten hundre" : century === 20 ? "to tusen" : null;
    if (!centuryWord) {
        return null;
    }
    if (remainder === 0) {
        return centuryWord;
    }
    const remainderWord = spellNbNoOneToNinetyNine(remainder);
    if (!remainderWord) {
        return null;
    }
    return `${centuryWord} og ${remainderWord}`;
}

function rewriteNbNoDateForSynthesis(text: string): string {
    const parts = text.split(".");
    if (parts.length !== 3) {
        return text;
    }
    const day = Number.parseInt(parts[0], 10);
    const month = Number.parseInt(parts[1], 10);
    const year = Number.parseInt(parts[2], 10);

    if (Number.isNaN(day) || Number.isNaN(month) || Number.isNaN(year)) {
        return text;
    }
    if (!isValidGregorianDate(year, month, day)) {
        return text;
    }

    const ordinal = NB_NO_ORDINAL_DAYS[day];
    const monthName: string | undefined = NB_NO_MONTH_NAMES[month - 1];
    const spokenYear = spellNbNoYear(year);
    if (!ordinal || !monthName || !spokenYear) {
        return text;
    }

    return `${ordinal} ${monthName} ${spokenYear}`;
}

// ---------------------------------------------------------------------------
// Phone number normalisation (Norwegian local 8-digit form)
// ---------------------------------------------------------------------------

// Local Norwegian format: 8 digits with no leading zero, optionally split by
// spaces or dashes (e.g. 41234567, 412 34 567, 412-34-567). International
// "+47…" is left untouched because the lookbehind on a non-digit / non-plus
// boundary fails when "+47" precedes the 8 digits. The leading digit must be
// 2–9 (Norwegian mobile / landline prefixes never start with 0 or 1 in the
// local form).
const NB_NO_PHONE_REGEX = /(?<![\d+])(?<!\+47\s?)[2-9](?:[ -]?\d){7}(?!\d)/;

function rewriteNbNoPhoneForSynthesis(text: string): string {
    const digits = text.replace(/[ -]/g, "");
    if (digits.length !== 8 || /\D/.test(digits)) {
        return text;
    }
    const groups: string[] = [];
    for (let i = 0; i < digits.length; i += 2) {
        groups.push([...digits.slice(i, i + 2)].map(spellDigit).join(" "));
    }
    return groups.join(", ");
}

// ---------------------------------------------------------------------------
// Postcode normalisation (Norwegian 4-digit postal codes)
// ---------------------------------------------------------------------------

// Norwegian postcodes are 4 digits with no internal space, which makes them
// indistinguishable from generic 4-digit numbers like "1590 kroner". The only
// reliable lexical signal is the leading zero — Oslo and Akershus postcodes
// (~0001-1295) carry it, and generic Norwegian numbers in narrative are
// virtually never written with a leading zero (numbers parse and print without
// one). So we only claim leading-0 postcodes here; postcodes from Bergen,
// Trondheim, Tromsø and other regions without a leading zero fall through to
// the large-number rule, and the `style-norwegian-wording` trait guidance
// asks the LLM to read them digit-by-digit anyway.
const NB_NO_POSTCODE_REGEX = /(?<!\d)0\d{3}(?!\d)/;

function rewriteNbNoPostcodeForSynthesis(text: string): string {
    if (text.length !== 4 || /\D/.test(text)) {
        return text;
    }
    return [...text].map(spellDigit).join(" ");
}

// ---------------------------------------------------------------------------
// Currency normalisation (Norwegian kroner / øre)
// ---------------------------------------------------------------------------

// Matches Norwegian currency: optional minus, an integer part (either an
// unseparated digit run like "1000" or comma-/period-grouped thousands like
// "1 000" / "1.000"), optional comma decimal (1 or 2 digits), optional space,
// then "kr" (case-insensitive) or "NOK" (uppercase only — lowercase "nok"
// is the common Norwegian word for "enough").
// - Leading (?<!\d) prevents mid-number matches like "000 kr" inside
//   "10000 kr" (would otherwise garble to "0null kroner").
// - The integer alternation accepts unseparated runs (`\d{1,9}`) so common
//   LLM outputs like "1000 kr" / "2500 kr" match cleanly. Without this, they
//   fell through to the large-number rule, which only rewrote the digits and
//   left the "kr" suffix as raw text (TTS would spell it out).
// - Trailing (?![\p{L}]) uses a Unicode-aware non-letter assertion rather
//   than \b, which is ASCII-only and would let "kr" match inside Norwegian
//   words starting with kr + diacritic ("kråker", "krønike").
const NB_NO_CURRENCY_REGEX =
    /(?<!\d)-?(?:\d{1,3}(?:[ .]\d{3})+|\d{1,9})(?:,\d{1,2})?\s?(?:[kK][rR](?![\p{L}])|NOK(?![\p{L}]))/u;

function rewriteNbNoCurrencyForSynthesis(text: string): string {
    let body = text.trim();
    const negative = body.startsWith("-");
    if (negative) {
        body = body.slice(1).trimStart();
    }
    body = body.replace(/\s?(?:kr|NOK)$/i, "").trim();
    body = body.replace(/[ .]/g, "");

    const [wholePart, fractionPart = ""] = body.split(",");
    const whole = Number.parseInt(wholePart, 10);
    if (Number.isNaN(whole)) {
        return text;
    }

    let fraction = 0;
    if (fractionPart) {
        const padded = fractionPart.length === 1 ? `${fractionPart}0` : fractionPart;
        fraction = Number.parseInt(padded, 10);
        if (Number.isNaN(fraction)) {
            return text;
        }
    }

    const parts: string[] = [];
    if (whole > 0) {
        parts.push(`${whole} ${whole === 1 ? "krone" : "kroner"}`);
    }
    if (fraction > 0) {
        parts.push(`${fraction} øre`);
    }
    if (parts.length === 0) {
        parts.push("null kroner");
    }

    return `${negative ? "minus " : ""}${parts.join(" og ")}`;
}

// ---------------------------------------------------------------------------
// Large-number decomposition (100–99999)
// ---------------------------------------------------------------------------

// TTS mispronounces multi-digit Norwegian numbers: 4-digit numbers drop
// "hundre", compound forms like "førtini" get the wrong stress, and digits
// before "tusen"/"hundre" pick the wrong gender. Decompose into
//   [X tusen] [Y hundre] [og Z]
// where X and Y are spelled words for 1–19 (digits 20–99 stay numeric — TTS
// handles those correctly) and Z is the 2-digit remainder kept as digits.
// The "og" before the remainder is the canonical Norwegian-vs-Swedish
// divergence (Swedish drops it).
//
// `\b` excludes digit-adjacent context (handles 6+ digit runs). The extra
// lookarounds reject digit runs that sit between dots in a date-shaped
// context — protecting dates whose rewrite no-oped (invalid month like
// "1.0.2026", year outside the 1900–2099 support range like "14.05.2100")
// from being garbled when the large-number rule otherwise consumes their
// year component and emits "1.0.to tusen og 26".
//
// The lookbehind is asymmetric on purpose: a preceding `\d.` indicates the
// year position in a date, but a trailing `.` alone is fine (sentence-end —
// "Beløpet er 1590." needs to keep matching). The trailing lookahead only
// fires when `.` is followed by another digit (decimal or further date
// component), which is the IP-address / decimal / mid-date case.
const NB_NO_LARGE_NUMBER_REGEX = /(?<!\d\.)\b\d{3,5}\b(?!\.\d)/;

function smallNorwegianWord(n: number): string | null {
    return NB_NO_ONES[n] ?? NB_NO_TEENS[n] ?? null;
}

function rewriteNbNoLargeNumberForSynthesis(text: string): string {
    const value = Number.parseInt(text, 10);
    if (Number.isNaN(value) || value < 100 || value > 99999) {
        return text;
    }

    const parts: string[] = [];
    const thousands = Math.floor(value / 1000);
    const remainder = value % 1000;
    const hundreds = Math.floor(remainder / 100);
    const tensOnes = remainder % 100;

    if (thousands > 0) {
        parts.push(`${smallNorwegianWord(thousands) ?? String(thousands)} tusen`);
    }
    if (hundreds > 0) {
        parts.push(`${smallNorwegianWord(hundreds) ?? String(hundreds)} hundre`);
    }
    if (tensOnes > 0) {
        parts.push(`og ${tensOnes}`);
    }
    return parts.join(" ");
}

// Rule ordering rationale (and a known gotcha):
//
//   1. Dates first — consumes "14.05.2026" before any 4-digit substring
//      ("2026") can match the postcode rule.
//   2. Phone before postcode — Norwegian phones contain 4-digit runs that
//      the postcode regex would otherwise eat (e.g. inside "412 34 567").
//      Phone consumes the digits first.
//   3. Postcode before large-number — 4-digit postcodes (e.g. "0150") would
//      otherwise be misread by the large-number rule as "one hundred and 50".
//   4. Currency before large-number — "1234 kr" should parse as kroner,
//      not as a bare "ett tusen to hundre og 34".
//   5. Large numbers last — only fires on 3–5 digit runs that nothing else
//      claimed.
export const NB_NO_DEFAULT_SYNTHESIS_REWRITE_RULES: LocaleSynthesisRewriteRuleImpl[] = [
    {
        label: "Dates",
        description: "Converts dates in dd.mm.yyyy format to fully spoken Norwegian.",
        playgroundSample: "Avtalen fornyes 01.01.2021 og utløper 14.05.2026.",
        pattern: NB_NO_DATE_REGEX,
        replacement: rewriteNbNoDateForSynthesis,
    },
    {
        label: "Phone numbers",
        description:
            "Reads Norwegian local 8-digit phone numbers in 2-digit groups. International +47 numbers are left untouched.",
        playgroundSample: "Du når oss på 41234567, eller +47 22 00 00 00 fra utlandet.",
        pattern: NB_NO_PHONE_REGEX,
        replacement: rewriteNbNoPhoneForSynthesis,
    },
    {
        label: "Postcodes",
        description: "Spells Norwegian 4-digit postal codes digit by digit.",
        playgroundSample: "Er postnummeret 0150?",
        pattern: NB_NO_POSTCODE_REGEX,
        replacement: rewriteNbNoPostcodeForSynthesis,
    },
    {
        label: "Currency",
        description: "Converts Norwegian kroner amounts (kr, NOK) to spoken form.",
        playgroundSample: "Saldoen er 1 234,56 kr, og gebyret er 1000 kr.",
        pattern: NB_NO_CURRENCY_REGEX,
        replacement: rewriteNbNoCurrencyForSynthesis,
    },
    {
        label: "Large numbers",
        description:
            "Decomposes 3–5 digit numbers into a TTS-friendly '[X tusen] [Y hundre] [og Z]' hybrid form to avoid misstress and dropped 'hundre' on multi-digit numbers.",
        playgroundSample: "Beløpet er 1590 kroner.",
        pattern: NB_NO_LARGE_NUMBER_REGEX,
        replacement: rewriteNbNoLargeNumberForSynthesis,
    },
    {
        label: "SMS acronym",
        description:
            "Reads 'SMS' as the Norwegian phonetic 'essemess'. Otherwise the TTS spells the individual letters in an English-like cadence.",
        playgroundSample: "Du får en bekreftelse via SMS.",
        // Unicode-aware non-letter boundaries (ASCII \b would fire false
        // boundaries adjacent to Norwegian å/ø/æ). The compound form "SMS-en"
        // (with the definite-article suffix) keeps the literal "SMS" because
        // the trailing letter blocks the lookahead — accepted limitation.
        pattern: /(?<![\p{L}])sms(?![\p{L}])/giu,
        replacement: "essemess",
    },
];

