export {
    rewriteNbNoDateForSynthesis as _rewriteNbNoDateForSynthesis,
    rewriteNbNoPhoneForSynthesis as _rewriteNbNoPhoneForSynthesis,
    rewriteNbNoPostcodeForSynthesis as _rewriteNbNoPostcodeForSynthesis,
    rewriteNbNoCurrencyForSynthesis as _rewriteNbNoCurrencyForSynthesis,
    rewriteNbNoLargeNumberForSynthesis as _rewriteNbNoLargeNumberForSynthesis,
    NB_NO_DATE_REGEX as _NB_NO_DATE_REGEX,
    NB_NO_PHONE_REGEX as _NB_NO_PHONE_REGEX,
    NB_NO_POSTCODE_REGEX as _NB_NO_POSTCODE_REGEX,
    NB_NO_CURRENCY_REGEX as _NB_NO_CURRENCY_REGEX,
    NB_NO_LARGE_NUMBER_REGEX as _NB_NO_LARGE_NUMBER_REGEX,
};
