// Shared DD/MM/YYYY → "the Xth of Month, YEAR" rewrite for English-speaking
// day-first locales. Locale packages opt in by adding
// `ENGLISH_DAY_FIRST_DATE_REWRITE` to `defaultSynthesisRewriteRules`; the
// rule's `id: "system:date"` makes the system rewrite short-circuit.

import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";
import { isValidGregorianDate } from "./gregorian-date";

const NUMERIC_DATE_REGEX =
    /\b(?:(\d{1,2}\/\d{1,2}\/(\d{4}|\d{2}))|(\d{1,2}-\d{1,2}-(\d{4}|\d{2})))\b/;

const MONTH_NAMES = [
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
] as const;

const ORDINAL_DAYS = [
    "",
    "first",
    "second",
    "third",
    "fourth",
    "fifth",
    "sixth",
    "seventh",
    "eighth",
    "ninth",
    "tenth",
    "eleventh",
    "twelfth",
    "thirteenth",
    "fourteenth",
    "fifteenth",
    "sixteenth",
    "seventeenth",
    "eighteenth",
    "nineteenth",
    "twentieth",
    "twenty-first",
    "twenty-second",
    "twenty-third",
    "twenty-fourth",
    "twenty-fifth",
    "twenty-sixth",
    "twenty-seventh",
    "twenty-eighth",
    "twenty-ninth",
    "thirtieth",
    "thirty-first",
] as const;

const ONES = [
    "",
    "one",
    "two",
    "three",
    "four",
    "five",
    "six",
    "seven",
    "eight",
    "nine",
    "ten",
    "eleven",
    "twelve",
    "thirteen",
    "fourteen",
    "fifteen",
    "sixteen",
    "seventeen",
    "eighteen",
    "nineteen",
] as const;

const TENS = [
    "",
    "",
    "twenty",
    "thirty",
    "forty",
    "fifty",
    "sixty",
    "seventy",
    "eighty",
    "ninety",
] as const;

const TWENTY_FIRST_CENTURY_THRESHOLD = 30;

function spellNumberUnder100(n: number): string | null {
    if (n < 0 || n > 99) {
        return null;
    }
    if (n < 20) {
        return ONES[n] || null;
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    if (ones === 0) {
        return TENS[tens] || null;
    }
    return `${TENS[tens]}-${ONES[ones]}`;
}

function spellYear(year: number): string | null {
    if (year < 1900 || year > 2099) {
        return null;
    }
    if (year === 2000) {
        return "two thousand";
    }
    const centuryPair = Math.floor(year / 100);
    const yearPair = year % 100;
    const centuryWord = spellNumberUnder100(centuryPair);
    if (!centuryWord) {
        return null;
    }
    if (yearPair === 0) {
        return `${centuryWord} hundred`;
    }
    if (yearPair < 10) {
        return `${centuryWord} oh ${ONES[yearPair]}`;
    }
    const yearPairWord = spellNumberUnder100(yearPair);
    if (!yearPairWord) {
        return null;
    }
    return `${centuryWord} ${yearPairWord}`;
}

function rewriteDate(text: string): string {
    const separator = text.includes("/") ? "/" : "-";
    const parts = text.split(separator);
    if (parts.length !== 3) {
        return text;
    }

    const dayValue = Number.parseInt(parts[0], 10);
    const monthValue = Number.parseInt(parts[1], 10);
    const rawYear = Number.parseInt(parts[2], 10);

    if (Number.isNaN(dayValue) || Number.isNaN(monthValue) || Number.isNaN(rawYear)) {
        return text;
    }

    const year =
        parts[2].length === 2
            ? rawYear < TWENTY_FIRST_CENTURY_THRESHOLD
                ? 2000 + rawYear
                : 1900 + rawYear
            : rawYear;

    if (!isValidGregorianDate(year, monthValue, dayValue)) {
        return text;
    }

    const ordinalDay = ORDINAL_DAYS[dayValue];
    const monthName: string | undefined = MONTH_NAMES[monthValue - 1];
    const spokenYear = spellYear(year);
    if (!ordinalDay || !monthName || !spokenYear) {
        return text;
    }

    return `the ${ordinalDay} of ${monthName}, ${spokenYear}`;
}

export const ENGLISH_DAY_FIRST_DATE_REWRITE: LocaleSynthesisRewriteRuleImpl = {
    id: "system:date",
    label: "Dates",
    description: "Converts DD/MM/YYYY dates into spoken English (day-first locales).",
    playgroundSample: "Your policy was issued on 24/06/2021.",
    pattern: NUMERIC_DATE_REGEX,
    replacement: rewriteDate,
};
