import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

const FR_CA_ISO_DATE_REGEX = /(?:\ble\s+)?\d{4}-\d{2}-\d{2}\b/iu;
const FR_CA_POSTAL_CODE_REGEX =
    /\b[ABCEGHJ-NPRSTVXY]\d[ABCEGHJ-NPRSTV-Z][ -]?\d[ABCEGHJ-NPRSTV-Z]\d\b/i;
const FR_CA_PHONE_NUMBER_REGEX =
    /(?<!\w)(?:\+?1[ -]?)?(?:\([2-9]\d{2}\)[ -]?|[2-9]\d{2}[ -])[2-9]\d{2}[ -]\d{4}(?:[ -]?(?:poste|ext\.?|x)\s*\d{1,6})?(?!\w)/i;
const FR_CA_CURRENCY_REGEX =
    /(?<!\w)(?:-?\$\s*\d{1,3}(?:(?:[ ,]\d{3})+|\d*)(?:[.,]\d{2})?|-?\d{1,3}(?:(?:[ ,]\d{3})+|\d*)(?:[.,]\d{2})?\s*(?:\$|CAD))(?!\w)/i;
const FR_CA_TIME_H_REGEX = /\b(?:[01]?\d|2[0-3])\s*h(?:\s*[0-5]\d)?\b/i;

const MONTH_NAMES = [
    "janvier",
    "février",
    "mars",
    "avril",
    "mai",
    "juin",
    "juillet",
    "août",
    "septembre",
    "octobre",
    "novembre",
    "décembre",
] as const;

const DIGIT_WORDS = [
    "zéro",
    "un",
    "deux",
    "trois",
    "quatre",
    "cinq",
    "six",
    "sept",
    "huit",
    "neuf",
] as const;

const BELOW_SEVENTEEN = [
    "zéro",
    "un",
    "deux",
    "trois",
    "quatre",
    "cinq",
    "six",
    "sept",
    "huit",
    "neuf",
    "dix",
    "onze",
    "douze",
    "treize",
    "quatorze",
    "quinze",
    "seize",
] as const;

const TENS = {
    20: "vingt",
    30: "trente",
    40: "quarante",
    50: "cinquante",
    60: "soixante",
} as const;

function spellFrBelowHundred(value: number): string | null {
    if (!Number.isInteger(value) || value < 0 || value >= 100) {
        return null;
    }

    if (value <= 16) {
        return BELOW_SEVENTEEN[value] ?? null;
    }

    if (value < 20) {
        return `dix-${BELOW_SEVENTEEN[value - 10]}`;
    }

    if (value < 70) {
        const tens = Math.floor(value / 10) * 10;
        const ones = value % 10;
        const tensWord = TENS[tens as keyof typeof TENS];
        if (ones === 0) {
            return tensWord;
        }
        if (ones === 1) {
            return `${tensWord} et un`;
        }
        const onesWord = spellFrBelowHundred(ones);
        return onesWord ? `${tensWord}-${onesWord}` : null;
    }

    if (value < 80) {
        const remainder = value - 60;
        if (remainder === 11) {
            return "soixante et onze";
        }
        const remainderWord = spellFrBelowHundred(remainder);
        return remainderWord ? `soixante-${remainderWord}` : null;
    }

    if (value === 80) {
        return "quatre-vingts";
    }

    const remainder = value - 80;
    if (remainder === 1) {
        return "quatre-vingt-un";
    }
    const remainderWord = spellFrBelowHundred(remainder);
    return remainderWord ? `quatre-vingt-${remainderWord}` : null;
}

function spellFrBelowThousand(value: number): string | null {
    if (!Number.isInteger(value) || value < 0 || value >= 1000) {
        return null;
    }

    if (value < 100) {
        return spellFrBelowHundred(value);
    }

    const hundreds = Math.floor(value / 100);
    const remainder = value % 100;
    const hundredsPrefix =
        hundreds === 1 ? "cent" : `${spellFrBelowHundred(hundreds) ?? ""} cent`.trim();
    if (!hundredsPrefix) {
        return null;
    }

    if (remainder === 0) {
        return hundreds > 1 ? `${hundredsPrefix}s` : hundredsPrefix;
    }

    const remainderWord = spellFrBelowHundred(remainder);
    return remainderWord ? `${hundredsPrefix} ${remainderWord}` : null;
}

function spellFrInteger(value: number): string | null {
    if (!Number.isSafeInteger(value) || value < 0 || value >= 1_000_000_000) {
        return null;
    }

    if (value < 1000) {
        return spellFrBelowThousand(value);
    }

    if (value < 1_000_000) {
        const thousands = Math.floor(value / 1000);
        const remainder = value % 1000;
        const thousandsWord =
            thousands === 1 ? "mille" : `${spellFrBelowThousand(thousands)} mille`;
        if (!thousandsWord) {
            return null;
        }
        if (remainder === 0) {
            return thousandsWord;
        }
        const remainderWord = spellFrBelowThousand(remainder);
        return remainderWord ? `${thousandsWord} ${remainderWord}` : null;
    }

    const millions = Math.floor(value / 1_000_000);
    const remainder = value % 1_000_000;
    const millionsRoot = spellFrBelowThousand(millions);
    if (!millionsRoot) {
        return null;
    }
    const millionsWord = `${millions === 1 ? "un" : millionsRoot} million${millions > 1 ? "s" : ""}`;
    if (remainder === 0) {
        return millionsWord;
    }
    const remainderWord = spellFrInteger(remainder);
    return remainderWord ? `${millionsWord} ${remainderWord}` : null;
}

function isValidGregorianDate(year: number, month: number, day: number): boolean {
    if (month < 1 || month > 12 || day < 1 || day > 31) {
        return false;
    }

    const date = new Date(Date.UTC(year, month - 1, day));
    return (
        date.getUTCFullYear() === year &&
        date.getUTCMonth() === month - 1 &&
        date.getUTCDate() === day
    );
}

function spellDateDay(day: number): string | null {
    if (day < 1 || day > 31) {
        return null;
    }
    if (day === 1) {
        return "premier";
    }
    return spellFrInteger(day);
}

function maybeStripLeadingLe(text: string): { hadLeadingLe: boolean; raw: string } {
    const normalized = text.trimStart();
    if (/^le\s+/iu.test(normalized)) {
        return { hadLeadingLe: true, raw: normalized.replace(/^le\s+/iu, "") };
    }
    return { hadLeadingLe: false, raw: normalized };
}

function rewriteFrCaIsoDateForSynthesis(text: string): string {
    const { raw } = maybeStripLeadingLe(text);
    const parts = raw.split("-");
    if (parts.length !== 3) {
        return text;
    }

    const year = Number.parseInt(parts[0], 10);
    const month = Number.parseInt(parts[1], 10);
    const day = Number.parseInt(parts[2], 10);
    if (Number.isNaN(year) || Number.isNaN(month) || Number.isNaN(day)) {
        return text;
    }
    if (!isValidGregorianDate(year, month, day)) {
        return text;
    }

    const spokenDay = spellDateDay(day);
    const spokenYear = spellFrInteger(year);
    const monthName = MONTH_NAMES[month - 1];
    if (!spokenDay || !spokenYear) {
        return text;
    }

    return `le ${spokenDay} ${monthName} ${spokenYear}`;
}

function rewriteFrCaPostalCodeForSynthesis(text: string): string {
    const normalized = text.toUpperCase().replace(/[ -]/g, "");
    if (normalized.length !== 6) {
        return text;
    }

    const chars = [...normalized];
    const firstDigit = Number.parseInt(chars[1], 10);
    const secondDigit = Number.parseInt(chars[3], 10);
    const thirdDigit = Number.parseInt(chars[5], 10);
    if (Number.isNaN(firstDigit) || Number.isNaN(secondDigit) || Number.isNaN(thirdDigit)) {
        return text;
    }

    return `${chars[0]} ${DIGIT_WORDS[firstDigit]} ${chars[2]} ${DIGIT_WORDS[secondDigit]} ${chars[4]} ${DIGIT_WORDS[thirdDigit]}`;
}

function rewriteFrCaPhoneForSynthesis(text: string): string {
    const extMatch = text.match(/(?:poste|ext\.?|x)\s*(\d{1,6})/i);
    const extensionDigits = extMatch?.[1] ?? null;
    const withoutExtension = extMatch ? text.slice(0, extMatch.index).trim() : text;

    const digits = withoutExtension.replace(/\D/g, "");
    const normalized = digits.length === 11 && digits.startsWith("1") ? digits.slice(1) : digits;
    if (normalized.length !== 10) {
        return text;
    }

    const groups = [normalized.slice(0, 3), normalized.slice(3, 6), normalized.slice(6, 10)];
    const base = groups
        .map(group => [...group].map(ch => DIGIT_WORDS[Number.parseInt(ch, 10)] ?? ch).join(" "))
        .join(", ");

    if (!extensionDigits) {
        return base;
    }

    const spokenExtension = [...extensionDigits]
        .map(ch => DIGIT_WORDS[Number.parseInt(ch, 10)] ?? ch)
        .join(" ");
    return `${base}, poste ${spokenExtension}`;
}

function parseFrCaCurrency(
    text: string
): { negative: boolean; dollars: number; cents: number } | null {
    const hasCurrencyMarker = /\$|\bCAD\b/i.test(text);
    if (!hasCurrencyMarker) {
        return null;
    }

    const trimmed = text.trim();
    const strictPrefixPattern =
        /^-?\$\s*(?:\d+|\d{1,3}(?:(?:,\d{3})+|(?: \d{3})+))(?:[.,]\d{2})?$/u;
    const strictSuffixPattern =
        /^-?(?:\d+|\d{1,3}(?:(?:,\d{3})+|(?: \d{3})+))(?:[.,]\d{2})?\s*(?:\$|CAD)$/iu;
    if (!strictPrefixPattern.test(trimmed) && !strictSuffixPattern.test(trimmed)) {
        return null;
    }

    let normalized = text.toUpperCase().replace(/\s+/g, "").replace(/CAD/g, "").replace(/\$/g, "");
    if (!normalized) {
        return null;
    }

    const negative = normalized.startsWith("-");
    if (negative) {
        normalized = normalized.slice(1);
    }

    const lastComma = normalized.lastIndexOf(",");
    const lastDot = normalized.lastIndexOf(".");
    let decimalIdx = -1;
    if (lastComma !== -1 && lastDot !== -1) {
        decimalIdx = Math.max(lastComma, lastDot);
    } else if (lastComma !== -1) {
        decimalIdx = normalized.length - lastComma - 1 === 2 ? lastComma : -1;
    } else if (lastDot !== -1) {
        decimalIdx = normalized.length - lastDot - 1 === 2 ? lastDot : -1;
    }

    const wholeRaw =
        decimalIdx === -1
            ? normalized.replace(/\D/g, "")
            : normalized.slice(0, decimalIdx).replace(/\D/g, "");
    const fractionRaw =
        decimalIdx === -1
            ? ""
            : normalized
                  .slice(decimalIdx + 1)
                  .replace(/\D/g, "")
                  .slice(0, 2)
                  .padEnd(2, "0");

    if (!wholeRaw && !fractionRaw) {
        return null;
    }

    if (wholeRaw.length > 9) {
        return null;
    }

    const dollars = wholeRaw ? Number.parseInt(wholeRaw, 10) : 0;
    const cents = fractionRaw ? Number.parseInt(fractionRaw, 10) : 0;
    if (Number.isNaN(dollars) || Number.isNaN(cents) || cents < 0 || cents > 99) {
        return null;
    }

    return { negative, dollars, cents };
}

function rewriteFrCaCurrencyForSynthesis(text: string): string {
    const amount = parseFrCaCurrency(text);
    if (!amount) {
        return text;
    }

    const spokenDollars = spellFrInteger(amount.dollars);
    const spokenCents = amount.cents > 0 ? spellFrInteger(amount.cents) : null;
    if (!spokenDollars || (amount.cents > 0 && !spokenCents)) {
        return text;
    }

    const pieces = [
        `${spokenDollars} ${amount.dollars <= 1 ? "dollar" : "dollars"}`,
        ...(amount.cents > 0 ? [`${spokenCents} ${amount.cents === 1 ? "cent" : "cents"}`] : []),
    ];
    const spoken = pieces.join(" et ");
    return amount.negative ? `moins ${spoken}` : spoken;
}

function rewriteFrCaTimeForSynthesis(text: string): string {
    const normalized = text.trim().toLowerCase();
    const match = normalized.match(/^(\d{1,2})\s*h(?:\s*(\d{2}))?$/);
    if (!match) {
        return text;
    }

    const hour = Number.parseInt(match[1], 10);
    const minute = match[2] ? Number.parseInt(match[2], 10) : 0;
    if (
        Number.isNaN(hour) ||
        Number.isNaN(minute) ||
        hour < 0 ||
        hour > 23 ||
        minute < 0 ||
        minute > 59
    ) {
        return text;
    }

    const hourWord = hour === 1 ? "une" : hour === 21 ? "vingt et une" : spellFrBelowHundred(hour);
    const minuteWord = spellFrBelowHundred(minute);
    if (!hourWord || minuteWord === null) {
        return text;
    }

    const hourUnit = hour === 0 || hour === 1 ? "heure" : "heures";

    if (minute === 0) {
        return `${hourWord} ${hourUnit}`;
    }

    return `${hourWord} ${hourUnit} ${minuteWord}`;
}

