import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

// ---------------------------------------------------------------------------
// Shared Swedish digit/number words
// ---------------------------------------------------------------------------

const SV_SE_DIGIT_WORDS = [
    "noll",
    "ett",
    "två",
    "tre",
    "fyra",
    "fem",
    "sex",
    "sju",
    "åtta",
    "nio",
] as const;

// "ett" / "två" / ... / "nio" — used for the "X tusen" / "Y hundra" prefixes
// where TTS otherwise picks the wrong gender ("en" vs. "ett").
const SV_SE_ONES: { readonly [key: number]: string | undefined } = {
    1: "ett",
    2: "två",
    3: "tre",
    4: "fyra",
    5: "fem",
    6: "sex",
    7: "sju",
    8: "åtta",
    9: "nio",
};

const SV_SE_TEENS: { readonly [key: number]: string | undefined } = {
    10: "tio",
    11: "elva",
    12: "tolv",
    13: "tretton",
    14: "fjorton",
    15: "femton",
    16: "sexton",
    17: "sjutton",
    18: "arton",
    19: "nitton",
};

const SV_SE_TENS: { readonly [key: number]: string | undefined } = {
    2: "tjugo",
    3: "trettio",
    4: "fyrtio",
    5: "femtio",
    6: "sextio",
    7: "sjuttio",
    8: "åttio",
    9: "nittio",
};

// Spell 1..99 in Swedish using compound forms ("tjugofem"). Used ONLY for
// year readouts in dates. The currency and large-number rules deliberately
// keep 2-digit remainders as digits — Swedish TTS stresses compound number
// words incorrectly ("fyrtionio" lands wrong), so amounts and reference
// numbers should never be spelled with compounds. Years are an exception
// because they're well-rehearsed in TTS training data. Do not extend
// compound spelling to the currency or large-number paths.
function spellSvSeOneToNinetyNine(n: number): string | null {
    if (n < 1 || n > 99) {
        return null;
    }
    if (n < 10) {
        return SV_SE_ONES[n] ?? null;
    }
    if (n < 20) {
        return SV_SE_TEENS[n] ?? null;
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    const tensWord = SV_SE_TENS[tens];
    if (!tensWord) {
        return null;
    }
    if (ones === 0) {
        return tensWord;
    }
    const onesWord = SV_SE_ONES[ones];
    if (!onesWord) {
        return null;
    }
    return `${tensWord}${onesWord}`;
}

// Caller guarantees `ch` is an ASCII digit (the postcode and phone rewrites
// strip whitespace and check the length / digit-only invariant before calling).
function spellDigit(ch: string): string {
    return SV_SE_DIGIT_WORDS[Number.parseInt(ch, 10)];
}

// ---------------------------------------------------------------------------
// Date normalisation (yyyy-mm-dd, Swedish ISO convention)
// ---------------------------------------------------------------------------

const SV_SE_DATE_REGEX = /\b\d{4}-\d{1,2}-\d{1,2}\b/;

const SV_SE_MONTH_NAMES = [
    "januari",
    "februari",
    "mars",
    "april",
    "maj",
    "juni",
    "juli",
    "augusti",
    "september",
    "oktober",
    "november",
    "december",
] as const;

const SV_SE_ORDINAL_DAYS = [
    "",
    "första",
    "andra",
    "tredje",
    "fjärde",
    "femte",
    "sjätte",
    "sjunde",
    "åttonde",
    "nionde",
    "tionde",
    "elfte",
    "tolfte",
    "trettonde",
    "fjortonde",
    "femtonde",
    "sextonde",
    "sjuttonde",
    "artonde",
    "nittonde",
    "tjugonde",
    "tjugoförsta",
    "tjugoandra",
    "tjugotredje",
    "tjugofjärde",
    "tjugofemte",
    "tjugosjätte",
    "tjugosjunde",
    "tjugoåttonde",
    "tjugonionde",
    "trettionde",
    "trettioförsta",
] as const;

function isValidGregorianDate(year: number, month: number, day: number): boolean {
    if (month < 1 || month > 12 || day < 1 || day > 31) {
        return false;
    }
    const date = new Date(Date.UTC(year, month - 1, day));
    return (
        date.getUTCFullYear() === year &&
        date.getUTCMonth() === month - 1 &&
        date.getUTCDate() === day
    );
}

// Swedish year convention: "tjugohundratjugosex" for 2026, "nittonhundranittio"
// for 1990, "tvåtusen" for 2000.
function spellSvSeYear(year: number): string | null {
    if (year < 1900 || year > 2099) {
        return null;
    }
    if (year === 2000) {
        return "tvåtusen";
    }
    const century = Math.floor(year / 100);
    const remainder = year % 100;
    const centuryWord = century === 19 ? "nittonhundra" : century === 20 ? "tjugohundra" : null;
    if (!centuryWord) {
        return null;
    }
    if (remainder === 0) {
        return centuryWord;
    }
    const remainderWord = spellSvSeOneToNinetyNine(remainder);
    if (!remainderWord) {
        return null;
    }
    return `${centuryWord}${remainderWord}`;
}

function rewriteSvSeDateForSynthesis(text: string): string {
    const parts = text.split("-");
    if (parts.length !== 3) {
        return text;
    }
    const year = Number.parseInt(parts[0], 10);
    const month = Number.parseInt(parts[1], 10);
    const day = Number.parseInt(parts[2], 10);

    if (Number.isNaN(year) || Number.isNaN(month) || Number.isNaN(day)) {
        return text;
    }
    if (!isValidGregorianDate(year, month, day)) {
        return text;
    }

    const ordinal = SV_SE_ORDINAL_DAYS[day];
    const monthName: string | undefined = SV_SE_MONTH_NAMES[month - 1];
    const spokenYear = spellSvSeYear(year);
    if (!ordinal || !monthName || !spokenYear) {
        return text;
    }

    return `den ${ordinal} ${monthName} ${spokenYear}`;
}

// ---------------------------------------------------------------------------
// Postcode normalisation (Swedish 5-digit postal codes, "XXX XX")
// ---------------------------------------------------------------------------

// Require the canonical 3+2 space — the unspaced form is ambiguous against
// other 5-digit numbers (e.g. years, reference codes).
const SV_SE_POSTCODE_REGEX = /\b\d{3} \d{2}\b/;

function rewriteSvSePostcodeForSynthesis(text: string): string {
    const digits = text.replace(/\s+/g, "");
    if (digits.length !== 5) {
        return text;
    }
    const firstGroup = [...digits.slice(0, 3)].map(spellDigit).join(" ");
    const secondGroup = [...digits.slice(3)].map(spellDigit).join(" ");
    return `${firstGroup}, ${secondGroup}`;
}

// ---------------------------------------------------------------------------
// Currency normalisation (Swedish kronor / öre)
// ---------------------------------------------------------------------------

// Matches Swedish currency: optional minus, digit groups with optional space
// or period thousands-separators, optional comma decimal (1 or 2 digits),
// optional space, then "kr" or "SEK".
// - Leading (?<!\d) prevents mid-number matches like "000 kr" inside "1000 kr"
//   (would otherwise garble to "1noll kronor").
// - Trailing (?![\p{L}]) uses a Unicode-aware non-letter assertion rather than
//   \b, which is ASCII-only and would let "kr" match inside Swedish words
//   starting with kr + diacritic ("kräftor", "krönika", "kräva").
const SV_SE_CURRENCY_REGEX =
    /(?<!\d)-?\d{1,3}(?:[ .]\d{3})*(?:,\d{1,2})?\s?(?:kr|SEK)(?![\p{L}])/iu;

function rewriteSvSeCurrencyForSynthesis(text: string): string {
    let body = text.trim();
    const negative = body.startsWith("-");
    if (negative) {
        body = body.slice(1).trimStart();
    }
    body = body.replace(/\s?(?:kr|SEK)$/i, "").trim();
    body = body.replace(/[ .]/g, "");

    const [wholePart, fractionPart = ""] = body.split(",");
    const whole = Number.parseInt(wholePart, 10);
    if (Number.isNaN(whole)) {
        return text;
    }

    let fraction = 0;
    if (fractionPart) {
        const padded = fractionPart.length === 1 ? `${fractionPart}0` : fractionPart;
        fraction = Number.parseInt(padded, 10);
        if (Number.isNaN(fraction)) {
            return text;
        }
    }

    const parts: string[] = [];
    if (whole > 0) {
        parts.push(`${whole} ${whole === 1 ? "krona" : "kronor"}`);
    }
    if (fraction > 0) {
        parts.push(`${fraction} öre`);
    }
    if (parts.length === 0) {
        parts.push("noll kronor");
    }

    return `${negative ? "minus " : ""}${parts.join(" och ")}`;
}

// ---------------------------------------------------------------------------
// Phone number normalisation (Swedish local 10-digit form)
// ---------------------------------------------------------------------------

// Local Swedish format: leading 0 + 9 more digits, optionally split by spaces
// or dashes (e.g. 0701234567, 070-123 45 67). International "+46…" is left
// untouched because the lookbehind on the leading 0 fails.
const SV_SE_PHONE_REGEX = /(?<!\d)0(?:[ -]?\d){9}(?!\d)/;

function rewriteSvSePhoneForSynthesis(text: string): string {
    const digits = text.replace(/[ -]/g, "");
    if (digits.length !== 10 || !digits.startsWith("0") || /\D/.test(digits)) {
        return text;
    }
    const groups: string[] = [];
    for (let i = 0; i < digits.length; i += 2) {
        groups.push([...digits.slice(i, i + 2)].map(spellDigit).join(" "));
    }
    return groups.join(", ");
}

// ---------------------------------------------------------------------------
// Large-number decomposition (100–99999)
// ---------------------------------------------------------------------------

// TTS mispronounces multi-digit Swedish numbers: 4-digit numbers drop "hundra",
// compound forms like "fyrtionio" get the wrong stress, and digits before
// "tusen"/"hundra" pick the wrong gender. Decompose into
//   [X tusen] [Y hundra] [Z]
// where X and Y are spelled words for 1–19 (digits 20–99 stay numeric — TTS
// handles those correctly) and Z is the 2-digit remainder kept as digits.
// No "och" before the remainder (Swedish convention, unlike Norwegian).
const SV_SE_LARGE_NUMBER_REGEX = /\b\d{3,5}\b/;

function smallSwedishWord(n: number): string | null {
    return SV_SE_ONES[n] ?? SV_SE_TEENS[n] ?? null;
}

function rewriteSvSeLargeNumberForSynthesis(text: string): string {
    const value = Number.parseInt(text, 10);
    if (Number.isNaN(value) || value < 100 || value > 99999) {
        return text;
    }

    const parts: string[] = [];
    const thousands = Math.floor(value / 1000);
    const remainder = value % 1000;
    const hundreds = Math.floor(remainder / 100);
    const tensOnes = remainder % 100;

    if (thousands > 0) {
        parts.push(`${smallSwedishWord(thousands) ?? String(thousands)} tusen`);
    }
    if (hundreds > 0) {
        parts.push(`${smallSwedishWord(hundreds) ?? String(hundreds)} hundra`);
    }
    if (tensOnes > 0) {
        parts.push(String(tensOnes));
    }
    return parts.join(" ");
}

// The SDK ships a `system:date` rule whose regex treats `dd-mm-yy` forms as
// dates and fragments ISO `yyyy-mm-dd` strings before any locale-package rule
// runs. The SDK rule also no-ops for non-`en-*` locales, so for sv-SE it both
// fails to rewrite and prevents this package from rewriting. We override it by
// id so our ISO-date rule runs in place of the SDK default.
