// ---------------------------------------------------------------------------
// Camilla Bard persona-specific rewrites
// ---------------------------------------------------------------------------
//
// These rules cover written-vs-spoken Swedish quirks and acronym readouts
// that Camilla Bard's voice mispronounces. They are layered onto the base
// sv-SE rules by `createDefaults` when the configured persona is
// `camilla-bard` (see shared.ts). Other Swedish personas don't get them —
// they may or may not need them, and we don't want to assume.
//
// All patterns use a Unicode-aware non-letter boundary `(?<![\p{L}])` /
// `(?![\p{L}])` instead of `\b`. JavaScript's `\b` is ASCII-only, so it
// fires false boundaries adjacent to Swedish letters (`å`, `ä`, `ö`) and
// would match inside compound words.

// Title-case the replacement when the matched input starts with an
// uppercase letter (covers Swedish sentence-initial capitalisation, e.g.
// "Dem" → "Dom"). All-caps inputs ("DE" / "DEM") are rare enough that we
// keep the lowercase form rather than over-engineering.
function caseAwareReplacement(replacement: string): (match: string) => string {
    return (match: string) => {
        if (/^\p{Lu}/u.test(match)) {
            return replacement.charAt(0).toUpperCase() + replacement.slice(1);
        }
        return replacement;
    };
}

