/** Full NRIC regex: [S/T/F/G/M] + 7 digits + checksum letter. */
export const fullNricRegex = /\b([STFGM])(\d{7})([A-Z])\b/gi;

/**
 * Wraps a full NRIC/FIN in a radio-spelled `<platform-spell>` tag so the
 * platform layer spells the letters phonetically and reads the digits clearly,
 * tuned per synthesis provider/model. The en-SG locale's spell definitions
 * supply the radio phrases (see `synthesis-rewrite-definitions.ts`).
 * S1234567A -> <platform-spell radio="true">S1234567A</platform-spell>
 */
export function spellOutFullNric(text: string): string {
    const match = text.match(/([STFGM])\d{7}[A-Z]/i);
    if (!match) {
        return text;
    }
    return `<platform-spell radio="true">${match[0]}</platform-spell>`;
}
