import { isValidGregorianDate } from "../../common/synthesis-rewrites/gregorian-date";
import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

const ID_ID_DIGIT_WORDS: { readonly [digit: string]: string | undefined } = {
    "0": "kosong",
    "1": "satu",
    "2": "dua",
    "3": "tiga",
    "4": "empat",
    "5": "lima",
    "6": "enam",
    "7": "tujuh",
    "8": "delapan",
    "9": "sembilan",
};

const ID_ID_MONTH_NAMES = [
    "januari",
    "februari",
    "maret",
    "april",
    "mei",
    "juni",
    "juli",
    "agustus",
    "september",
    "oktober",
    "november",
    "desember",
] as const;

const ID_ID_MONTH_NAME_PATTERN = ID_ID_MONTH_NAMES.join("|");
const ID_ID_PRE_2000_YEAR_REGEX = new RegExp(
    [
        String.raw`(?<![\p{L}\p{N}])(?:`,
        String.raw`(?:tahun|thn\.?|pada|sejak)\s+19\d{2}`,
        String.raw`|\d{1,2}[/-]\d{1,2}[/-]19\d{2}`,
        String.raw`|\d{1,2}\s+(?:${ID_ID_MONTH_NAME_PATTERN})\s*,?\s+19\d{2}`,
        String.raw`)(?![\p{L}\p{N}])`,
    ].join(""),
    "iu"
);

const ID_ID_NUMERIC_DATE_MATCH = /^(\d{1,2})[/-](\d{1,2})[/-](19\d{2})$/u;
const ID_ID_MONTH_NAME_DATE_MATCH = new RegExp(
    String.raw`^(\d{1,2})\s+(${ID_ID_MONTH_NAME_PATTERN})\s*,?\s+(19\d{2})$`,
    "iu"
);
const ID_ID_PRE_2000_YEAR_MATCH = /^(.*)(19\d{2})$/u;

function isValidIdIdDateContext(text: string): boolean {
    const numericDateMatch = text.match(ID_ID_NUMERIC_DATE_MATCH);
    if (numericDateMatch) {
        const day = Number.parseInt(numericDateMatch[1], 10);
        const month = Number.parseInt(numericDateMatch[2], 10);
        const year = Number.parseInt(numericDateMatch[3], 10);
        return isValidGregorianDate(year, month, day);
    }

    const monthNameDateMatch = text.match(ID_ID_MONTH_NAME_DATE_MATCH);
    if (monthNameDateMatch) {
        const day = Number.parseInt(monthNameDateMatch[1], 10);
        const monthName = monthNameDateMatch[2].toLowerCase();
        const month = ID_ID_MONTH_NAMES.findIndex(candidate => candidate === monthName) + 1;
        const year = Number.parseInt(monthNameDateMatch[3], 10);
        return isValidGregorianDate(year, month, day);
    }

    return true;
}

function rewriteIdIdPre2000YearForSynthesis(text: string): string {
    if (!isValidIdIdDateContext(text)) {
        return text;
    }
    const match = text.match(ID_ID_PRE_2000_YEAR_MATCH);
    if (!match) {
        return text;
    }
    const prefix = match[1];
    const year = match[2];
    if (!prefix || !year) {
        return text;
    }
    const digitWords = [...year.slice(2)].map(digit => ID_ID_DIGIT_WORDS[digit]);
    if (digitWords.some(word => word === undefined)) {
        return text;
    }
    return `${prefix}sembilan belas ${digitWords.join(" ")}`;
}

export const ID_ID_DEFAULT_SYNTHESIS_REWRITE_RULES: LocaleSynthesisRewriteRuleImpl[] = [
    {
        label: "Pre-2000 years",
        description:
            'Reads contextual 1900-1999 years as Indonesian century-plus-digits, for example "19 Maret 1998" as "19 Maret sembilan belas sembilan delapan".',
        playgroundSample: "Tanggal lahirnya 19 Maret 1998.",
        pattern: ID_ID_PRE_2000_YEAR_REGEX,
        replacement: rewriteIdIdPre2000YearForSynthesis,
    },
];

// @visibleForTesting - exported for unit tests only; not part of the public API.
export {
    rewriteIdIdPre2000YearForSynthesis as _rewriteIdIdPre2000YearForSynthesis,
    ID_ID_PRE_2000_YEAR_REGEX as _ID_ID_PRE_2000_YEAR_REGEX,
};
