import { isValidGregorianDate } from "../../common/synthesis-rewrites/gregorian-date";
import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

const THAI_NUMERIC_DATE_REGEX =
    /(?<![\p{L}\p{N}])(?:[0-9๐-๙]{1,2}[/-][0-9๐-๙]{1,2}[/-][0-9๐-๙]{2}(?:[0-9๐-๙]{2})?)(?![\p{L}\p{N}])/u;
const THAI_BAHT_AMOUNT_REGEX =
    /(?<![\p{L}\p{N}])(?:฿\s*[0-9๐-๙][0-9๐-๙,]*(?:\.[0-9๐-๙]{1,2})?|(?:THB|บาท)\s*[0-9๐-๙][0-9๐-๙,]*(?:\.[0-9๐-๙]{1,2})?|[0-9๐-๙][0-9๐-๙,]*(?:\.[0-9๐-๙]{1,2})?\s*(?:บาท|THB))(?![\p{L}\p{N}])/iu;
const LONG_DIGIT_SEQUENCE_REGEX = /(?<![\p{L}\p{N}])(?:[0-9๐-๙][ -]?){4,}[0-9๐-๙](?![\p{L}\p{N}])/u;

const THAI_DIGIT_WORDS = [
    "ศูนย์",
    "หนึ่ง",
    "สอง",
    "สาม",
    "สี่",
    "ห้า",
    "หก",
    "เจ็ด",
    "แปด",
    "เก้า",
] as const;
const THAI_NUMBER_UNITS = ["", "สิบ", "ร้อย", "พัน", "หมื่น", "แสน"] as const;
const THAI_MONTH_NAMES = [
    "มกราคม",
    "กุมภาพันธ์",
    "มีนาคม",
    "เมษายน",
    "พฤษภาคม",
    "มิถุนายน",
    "กรกฎาคม",
    "สิงหาคม",
    "กันยายน",
    "ตุลาคม",
    "พฤศจิกายน",
    "ธันวาคม",
] as const;
const THAI_NUMERAL_OFFSET = "๐".charCodeAt(0);

function normalizeThaiNumerals(text: string): string {
    return text.replace(/[๐-๙]/g, digit =>
        String.fromCharCode("0".charCodeAt(0) + digit.charCodeAt(0) - THAI_NUMERAL_OFFSET)
    );
}

function parseThaiNumber(value: string): number {
    return Number.parseInt(normalizeThaiNumerals(value), 10);
}

function spellThaiNumberBelowMillion(value: number): string | null {
    if (!Number.isInteger(value) || value < 0 || value >= 1_000_000) {
        return null;
    }
    if (value === 0) {
        return THAI_DIGIT_WORDS[0];
    }

    const digits = String(value).split("").map(Number);
    const parts: string[] = [];
    for (const [index, digit] of digits.entries()) {
        if (digit === 0) {
            continue;
        }

        const position = digits.length - index - 1;
        if (position === 0) {
            parts.push(digit === 1 && value > 10 ? "เอ็ด" : THAI_DIGIT_WORDS[digit]);
        } else if (position === 1) {
            if (digit === 1) {
                parts.push("สิบ");
            } else if (digit === 2) {
                parts.push("ยี่สิบ");
            } else {
                parts.push(`${THAI_DIGIT_WORDS[digit]}สิบ`);
            }
        } else {
            parts.push(`${THAI_DIGIT_WORDS[digit]}${THAI_NUMBER_UNITS[position]}`);
        }
    }

    return parts.join("");
}

function spellThaiInteger(value: number): string | null {
    if (!Number.isSafeInteger(value) || value < 0) {
        return null;
    }
    if (value < 1_000_000) {
        return spellThaiNumberBelowMillion(value);
    }

    const millions = Math.floor(value / 1_000_000);
    const remainder = value % 1_000_000;
    const millionWords = spellThaiInteger(millions);
    const remainderWords = remainder > 0 ? spellThaiNumberBelowMillion(remainder) : "";
    return millionWords ? `${millionWords}ล้าน${remainderWords}` : null;
}

function spellThaiDay(day: number): string | null {
    if (day < 1 || day > 31) {
        return null;
    }
    if (day === 1) {
        return THAI_DIGIT_WORDS[1];
    }
    return spellThaiInteger(day);
}

function resolveThaiCalendarYear(
    yearPart: string
): { buddhistYear: number; isoYear: number } | null {
    const normalizedYear = normalizeThaiNumerals(yearPart);
    const rawYear = Number.parseInt(normalizedYear, 10);
    if (Number.isNaN(rawYear)) {
        return null;
    }
    if (normalizedYear.length === 2) {
        const buddhistYear = rawYear >= 43 ? 2500 + rawYear : 2543 + rawYear;
        return { buddhistYear, isoYear: buddhistYear - 543 };
    }
    if (rawYear >= 2400 && rawYear <= 2700) {
        return { buddhistYear: rawYear, isoYear: rawYear - 543 };
    }
    if (rawYear >= 1900 && rawYear <= 2399) {
        return { buddhistYear: rawYear + 543, isoYear: rawYear };
    }
    return null;
}

function rewriteThaiDateForSynthesis(text: string): string {
    const separator = text.includes("/") ? "/" : text.includes("-") ? "-" : null;
    if (!separator) {
        return text;
    }

    const [firstPart, secondPart, yearPart] = text.split(separator);
    const firstValue = parseThaiNumber(firstPart);
    const secondValue = parseThaiNumber(secondPart);
    const resolvedYear = resolveThaiCalendarYear(yearPart);
    if (Number.isNaN(firstValue) || Number.isNaN(secondValue) || !resolvedYear) {
        return text;
    }

    const dayMonthYear = isValidGregorianDate(resolvedYear.isoYear, secondValue, firstValue)
        ? { day: firstValue, month: secondValue }
        : isValidGregorianDate(resolvedYear.isoYear, firstValue, secondValue)
          ? { day: secondValue, month: firstValue }
          : null;
    if (!dayMonthYear) {
        return text;
    }

    const spokenDay = spellThaiDay(dayMonthYear.day);
    const spokenYear = spellThaiInteger(resolvedYear.buddhistYear);
    const spokenMonth = THAI_MONTH_NAMES[dayMonthYear.month - 1];
    if (!spokenDay || !spokenYear) {
        return text;
    }

    return `วันที่${spokenDay} ${spokenMonth} พ.ศ. ${spokenYear}`;
}

function parseThaiBahtAmount(text: string): { baht: number; satang: number } | null {
    const normalized = normalizeThaiNumerals(text)
        .replace(/THB/gi, "")
        .replace(/฿|บาท/g, "")
        .replace(/\s+/g, "")
        .replace(/,/g, "");
    const match = normalized.match(/^(\d+)(?:\.(\d{1,2}))?$/);
    if (!match) {
        return null;
    }

    const baht = Number.parseInt(match[1], 10);
    const satang = match[2] ? Number.parseInt(match[2].padEnd(2, "0"), 10) : 0;
    if (!Number.isSafeInteger(baht) || baht < 0 || satang < 0 || satang > 99) {
        return null;
    }
    return { baht, satang };
}

function rewriteThaiBahtForSynthesis(text: string): string {
    const amount = parseThaiBahtAmount(text);
    if (!amount) {
        return text;
    }

    const bahtWords = spellThaiInteger(amount.baht);
    const satangWords = amount.satang > 0 ? spellThaiInteger(amount.satang) : null;
    if (!bahtWords || (amount.satang > 0 && !satangWords)) {
        return text;
    }

    return amount.satang > 0 ? `${bahtWords}บาท${satangWords}สตางค์` : `${bahtWords}บาทถ้วน`;
}

function rewriteThaiDigitSequenceForSynthesis(text: string): string {
    const digitWords = normalizeThaiNumerals(text)
        .match(/[0-9]/g)
        ?.map(digit => THAI_DIGIT_WORDS[Number.parseInt(digit, 10)]);
    return digitWords && digitWords.length > 0 ? digitWords.join(" ") : text;
}

export const TH_TH_DEFAULT_SYNTHESIS_REWRITE_RULES: LocaleSynthesisRewriteRuleImpl[] = [
    {
        label: "Date normalization",
        description:
            "Converts Thai numeric dates into spoken Thai, assuming DD/MM/YYYY and Buddhist Era year numbering. Falls back to MM/DD/YYYY if only valid option.",
        playgroundSample: "การนัดหมายของคุณคือวันที่ 04/02/2026.",
        pattern: THAI_NUMERIC_DATE_REGEX,
        replacement: rewriteThaiDateForSynthesis,
    },
    {
        label: "Thai baht normalization",
        description: "Converts Thai baht amounts into fully spoken Thai baht and satang.",
        playgroundSample: "ยอดที่ต้องชำระคือ ฿1,234.50.",
        pattern: THAI_BAHT_AMOUNT_REGEX,
        replacement: rewriteThaiBahtForSynthesis,
    },
    {
        label: "Digit sequence normalization",
        description:
            "Reads long confirmation numbers, phone numbers, and other IDs digit by digit.",
        playgroundSample: "รหัสยืนยันของคุณคือ 12345.",
        pattern: LONG_DIGIT_SEQUENCE_REGEX,
        replacement: rewriteThaiDigitSequenceForSynthesis,
    },
];
