// [variantKey, localeCode, defaults]. variantKey is the localization key the
// schema emits (`<code>` or `<code>-feminine`/`<code>-masculine`); localeCode is
// the bare BCP-47 code used to look rules up in the synthesis-rewrites registry.
const LOCALIZED_DEFAULTS: [string, string, LocaleDefaults][] = [];
for (const [code, defaults] of Object.entries(SUPPORTED_LOCALE_DEFAULTS)) {
    if (isLocaleDefaultsByVariant(defaults)) {
        LOCALIZED_DEFAULTS.push([`${code}-feminine`, code, defaults.feminine]);
        LOCALIZED_DEFAULTS.push([`${code}-masculine`, code, defaults.masculine]);
    } else {
        LOCALIZED_DEFAULTS.push([code, code, defaults]);
    }
}

// Project a flat LocaleDefaults onto the field-name map a per_locale entry's
// `localization` block expects: { [schemaFieldName]: defaultValue }.
function projectLocaleDefaults<K extends keyof LocaleDefaults>(
    defaults: LocaleDefaults,
    fieldToKey: { readonly [field: string]: K }
): { [field: string]: unknown } {
    return Object.fromEntries(
        Object.entries(fieldToKey).map(([field, key]) => [field, defaults[key]])
    );
}

// Flatten SUPPORTED_LOCALE_DEFAULTS into the schema's `localization` block.
// Single-variant locales emit one entry keyed by BCP-47 code. Gendered
// locales emit two entries keyed `<code>-feminine` / `<code>-masculine` so
// the encoder can pick the right variant per agent at bake time. The wire
// shape stays `{<code>: {value: ...}}` because the encoder writes baked
// values back under the bare code; the runtime SDK resolver never sees the
// composite keys.
function perLocaleDefaults<K extends keyof LocaleDefaults>(fieldToKey: {
    readonly [field: string]: K;
}): { [variantKey: string]: { [field: string]: unknown } } {
    const out: { [key: string]: { [field: string]: unknown } } = {};
    for (const [variantKey, , defaults] of LOCALIZED_DEFAULTS) {
        out[variantKey] = projectLocaleDefaults(defaults, fieldToKey);
    }
    return out;
}

// Build the localization block for the single-`per_locale` `sdk:abuse` entry.
// The whole config object lives under one `config` per_locale field, so the
// shipped default for each locale is the full default config object nested
// under the `config` field name (the frontend looks it up as
// `entryLocalization[localeKey].config`). The message fields carry per-locale
// defaults and `globalMode` ships a fixed `defend-terminate` default for every
// locale; the remaining behavioral fields fall back to their own schema
// `defaultValue`. Keyed `<code>` / `<code>-<variant>` like perLocaleDefaults.
function abuseConfigPerLocaleDefaults(): {
    [variantKey: string]: { config: { [field: string]: unknown } };
} {
    const configDefaults = (defaults: LocaleDefaults): { [field: string]: unknown } => ({
        globalMode: "defend-terminate",
        globalTerminateMessage: defaults.abuseDetectedTerminationMessage,
        globalTransferMessage: defaults.abuseDetectedTransferMessage,
    });
    const out: { [key: string]: { config: { [field: string]: unknown } } } = {};
    for (const [code, defaults] of Object.entries(SUPPORTED_LOCALE_DEFAULTS)) {
        if (isLocaleDefaultsByVariant(defaults)) {
            out[`${code}-feminine`] = { config: configDefaults(defaults.feminine) };
            out[`${code}-masculine`] = { config: configDefaults(defaults.masculine) };
        } else {
            out[code] = { config: configDefaults(defaults) };
        }
    }
    return out;
}

// Localization for CoreAgentVoiceSynthesisRewrites. The custom `synthesisRewrites`
// come from each locale's defaults, while the read-only built-in rule metadata
// (`enabledDefaultSynthesisRewriteRuleIds`) is derived from the runtime rule
// registry so it has a single source of truth (see synthesis-rewrites-registry.ts).
function synthesisRewritesLocalization(): {
    [variantKey: string]: { [field: string]: unknown };
} {
    const out: { [key: string]: { [field: string]: unknown } } = {};
    for (const [variantKey, code, defaults] of LOCALIZED_DEFAULTS) {
        out[variantKey] = {
            synthesisRewrites: defaults.defaultVoiceSynthesisRewrites,
            enabledDefaultSynthesisRewriteRuleIds:
                getDefaultSynthesisRewriteRuleMetadataForLocale(code),
        };
    }
    return out;
}

