function makeAbuseTypeObjectField(entry: AbuseTypeEntry): ContentTypeField {
    const fields: ContentTypeField[] = [];

    if (!entry.isCore) {
        fields.push(
            defineField({
                type: "checkbox",
                name: "disabled",
                label: "Disable this category",
                defaultValue: false,
            })
        );
    }

    fields.push(
        defineField({
            type: "picklist",
            name: "mode",
            label: "Guardrail action",
            optional: true,
            items: entry.isCore
                ? [...DETECT_ABUSE_DEFEND_MODE_ITEMS]
                : [...DETECT_ABUSE_ALL_MODE_ITEMS],
        }),
        defineField({
            type: "multiline",
            name: "terminateMessage",
            label: "Guardrail response",
            showIf: equals("mode", "defend-terminate"),
            rows: 3,
            optional: true,
        }),
        defineField({
            type: "multiline",
            name: "transferMessage",
            label: "Guardrail response",
            showIf: equals("mode", "defend-transfer"),
            rows: 3,
            optional: true,
        }),
        defineField({
            type: "array",
            name: "additionalDescriptions",
            label: "Additional descriptions",
            description:
                "Extra examples of customer behavior that should be classified as this type of abuse, " +
                "added on top of the built-in detection. Each description should describe what the customer is doing " +
                '(for example, "The customer is asking the agent to recommend specific stocks").',
            optional: true,
            childType: {
                type: "text",
                optional: true,
                placeholder: "The customer is...",
                validation: rule =>
                    rule.optional().minLength(1).error("Description should not be empty."),
            },
        }),
        defineField({
            type: "array",
            name: "honeypots",
            label: "Allowances",
            description:
                "Examples of legitimate customer behavior that look similar to this category but should not be treated as abuse. Add descriptions here to mitigate false positive detections.",
            optional: true,
            childType: {
                type: "text",
                optional: true,
                placeholder: "The customer is...",
                validation: rule =>
                    rule.optional().minLength(1).error("Allowance should not be empty."),
            },
        })
    );

    // Refocus fields are configurable on every category, including core. A
    // customer who raises `maxAllowed` on a core category will (correctly)
    // surface in the `core_categories_modified` health-metric bucket, since
    // delayed escalation is a meaningful change to core safety behavior.
    fields.push(
        defineField({
            type: "number",
            name: "maxAllowed",
            label: "Detections before escalation",
            description:
                "Number of detections required to escalate. " +
                "For example, 3 means escalate on the third detection (the first two can show the response below). " +
                "Leave blank to use the default. Set to 1 to escalate immediately.",
            optional: true,
            minValue: 1,
        }),
        defineField({
            type: "multiline",
            name: "refocusMessage",
            label: "Response before escalation",
            rows: 3,
            optional: true,
        })
    );

    // `isCore` is a public contract read by the Agent Studio guardrails panel
    // (web/sites/app/ui/panels/content/detect-abuse-package-sections.tsx). The panel
    // uses it to gate per-category UI and falls back to the absence of a `disabled`
    // subfield for older builds where this bit is not serialized.
    return defineField({
        type: "object",
        name: entry.id,
        label: entry.label,
        description: entry.description,
        optional: true,
        display: { type: "vertical" },
        fields,
        isCore: entry.isCore,
    });
}

