import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";
import { isValidGregorianDate } from "../../common/synthesis-rewrites/gregorian-date";

// ---------------------------------------------------------------------------
// Shared German digit / number words
// ---------------------------------------------------------------------------

// Standalone cardinals (0–9). "eins" is the standalone form of 1; the combining
// form "ein" is used as a prefix before "und", "hundert", and "tausend".
const DE_DIGIT_WORDS = [
    "null",
    "eins",
    "zwei",
    "drei",
    "vier",
    "fünf",
    "sechs",
    "sieben",
    "acht",
    "neun",
] as const;

// Combining form of 1–9 used before "und" / "hundert" / "tausend"
// (e.g. "einundzwanzig", "einhundert", "eintausend").
const DE_ONES_COMBINING = [
    "",
    "ein",
    "zwei",
    "drei",
    "vier",
    "fünf",
    "sechs",
    "sieben",
    "acht",
    "neun",
] as const;

const DE_TEENS = [
    "zehn",
    "elf",
    "zwölf",
    "dreizehn",
    "vierzehn",
    "fünfzehn",
    "sechzehn",
    "siebzehn",
    "achtzehn",
    "neunzehn",
] as const;

// Index 2–9 maps to 20–90. Indices 0 and 1 are unused (handled by ones/teens).
const DE_TENS = [
    "",
    "",
    "zwanzig",
    "dreißig",
    "vierzig",
    "fünfzig",
    "sechzig",
    "siebzig",
    "achtzig",
    "neunzig",
] as const;

// Spells 1–99 in German. German places the ones word before the tens, joined by
// "und" (e.g. 24 → "vierundzwanzig", 67 → "siebenundsechzig").
function spellUnder100(n: number): string | null {
    if (n < 1 || n > 99) {
        return null;
    }
    if (n < 10) {
        return DE_DIGIT_WORDS[n];
    }
    if (n < 20) {
        return DE_TEENS[n - 10];
    }
    const tens = Math.floor(n / 10);
    const ones = n % 10;
    if (ones === 0) {
        return DE_TENS[tens];
    }
    return `${DE_ONES_COMBINING[ones]}und${DE_TENS[tens]}`;
}

// Spells 1–999 in German (e.g. 234 → "zweihundertvierunddreißig").
function spellUnder1000(n: number): string | null {
    if (n < 1 || n > 999) {
        return null;
    }
    if (n < 100) {
        return spellUnder100(n);
    }
    const hundreds = Math.floor(n / 100);
    const remainder = n % 100;
    const hundredsPart = `${DE_ONES_COMBINING[hundreds]}hundert`;
    if (remainder === 0) {
        return hundredsPart;
    }
    const remainderPart = spellUnder100(remainder);
    return remainderPart ? `${hundredsPart}${remainderPart}` : null;
}

// Fully spells a non-negative integer (0–999,999) in German. Larger values are
// left as digits.
function spellGermanWholeNumber(n: number): string | null {
    if (n < 0 || n > 999_999) {
        return null;
    }
    if (n === 0) {
        return "null";
    }
    if (n < 1000) {
        return spellUnder1000(n);
    }
    const thousands = Math.floor(n / 1000);
    const remainder = n % 1000;
    const prefix = thousands === 1 ? "ein" : spellUnder1000(thousands);
    if (!prefix) {
        return null;
    }
    const result = `${prefix}tausend`;
    if (remainder === 0) {
        return result;
    }
    const remainderPart = spellUnder1000(remainder);
    return remainderPart ? `${result}${remainderPart}` : null;
}

// ---------------------------------------------------------------------------
// Date normalisation (dd.mm.yyyy, German convention)
// ---------------------------------------------------------------------------

const DE_DATE_REGEX = /\b(?:(?:am|vom|zum|ab|bis|seit)\s+)?\d{1,2}\.\d{1,2}\.(?:\d{4}|\d{2})\b/i;

// Two-digit years below this threshold map to the 21st century (e.g. "21" →
// 2021), at or above it to the 20th century (e.g. "95" → 1995). Mirrors the
// shared English day-first date rewrite.
const TWENTY_FIRST_CENTURY_THRESHOLD = 30;

const DE_MONTH_NAMES = [
    "Januar",
    "Februar",
    "März",
    "April",
    "Mai",
    "Juni",
    "Juli",
    "August",
    "September",
    "Oktober",
    "November",
    "Dezember",
] as const;

// Nominative ordinals 1–31 ("der erste", "der zweite", …). Index 0 unused.
const DE_ORDINAL_DAYS = [
    "",
    "erste",
    "zweite",
    "dritte",
    "vierte",
    "fünfte",
    "sechste",
    "siebte",
    "achte",
    "neunte",
    "zehnte",
    "elfte",
    "zwölfte",
    "dreizehnte",
    "vierzehnte",
    "fünfzehnte",
    "sechzehnte",
    "siebzehnte",
    "achtzehnte",
    "neunzehnte",
    "zwanzigste",
    "einundzwanzigste",
    "zweiundzwanzigste",
    "dreiundzwanzigste",
    "vierundzwanzigste",
    "fünfundzwanzigste",
    "sechsundzwanzigste",
    "siebenundzwanzigste",
    "achtundzwanzigste",
    "neunundzwanzigste",
    "dreißigste",
    "einunddreißigste",
] as const;

const DE_DATE_PREPOSITION_REPLACEMENTS: Record<string, (day: string) => string> = {
    am: day => `am ${day}`,
    vom: day => `vom ${day}`,
    zum: day => `zum ${day}`,
    ab: day => `ab dem ${day}`,
    bis: day => `bis zum ${day}`,
    seit: day => `seit dem ${day}`,
};

function dativeOrdinal(nominativeOrdinal: string): string {
    return `${nominativeOrdinal}n`;
}

function preserveInitialCapitalization(source: string, replacement: string): string {
    if (source[0] !== source[0].toUpperCase()) {
        return replacement;
    }
    return `${replacement[0].toUpperCase()}${replacement.slice(1)}`;
}

// Spells calendar years 1000–2099 the way Germans say them:
// 2026 → "zweitausendsechsundzwanzig", 1990 → "neunzehnhundertneunzig".
function spellGermanYear(year: number): string | null {
    if (year >= 2000 && year <= 2099) {
        const remainder = year - 2000;
        if (remainder === 0) {
            return "zweitausend";
        }
        const remainderPart = spellUnder1000(remainder);
        return remainderPart ? `zweitausend${remainderPart}` : null;
    }
    if (year >= 1000 && year <= 1999) {
        const hundreds = Math.floor(year / 100);
        const remainder = year % 100;
        const hundredsWord = spellUnder100(hundreds);
        if (!hundredsWord) {
            return null;
        }
        const base = `${hundredsWord}hundert`;
        if (remainder === 0) {
            return base;
        }
        const remainderPart = spellUnder100(remainder);
        return remainderPart ? `${base}${remainderPart}` : null;
    }
    return null;
}

function rewriteDeDateForSynthesis(text: string): string {
    const trimmed = text.trim();
    const match =
        /^(?:(?<preposition>am|vom|zum|ab|bis|seit)\s+)?(?<date>\d{1,2}\.\d{1,2}\.(?:\d{4}|\d{2}))$/i.exec(
            trimmed
        );
    const dateText = match?.groups?.["date"] ?? trimmed;
    const parts = dateText.split(".");
    if (parts.length !== 3) {
        return text;
    }
    const day = Number.parseInt(parts[0], 10);
    const month = Number.parseInt(parts[1], 10);
    const rawYear = Number.parseInt(parts[2], 10);

    if (Number.isNaN(day) || Number.isNaN(month) || Number.isNaN(rawYear)) {
        return text;
    }

    const year =
        parts[2].length === 2
            ? rawYear < TWENTY_FIRST_CENTURY_THRESHOLD
                ? 2000 + rawYear
                : 1900 + rawYear
            : rawYear;

    if (!isValidGregorianDate(year, month, day)) {
        return text;
    }

    const nominativeOrdinal = DE_ORDINAL_DAYS[day];
    const monthName: string | undefined = DE_MONTH_NAMES[month - 1];
    const spokenYear = spellGermanYear(year);
    if (!nominativeOrdinal || !monthName || !spokenYear) {
        return text;
    }

    const rawPreposition = match?.groups?.["preposition"];
    const preposition = rawPreposition?.toLowerCase();
    if (rawPreposition && preposition) {
        const replacement = DE_DATE_PREPOSITION_REPLACEMENTS[preposition];
        const phrase = replacement(dativeOrdinal(nominativeOrdinal));
        return `${preserveInitialCapitalization(rawPreposition, phrase)} ${monthName} ${spokenYear}`;
    }

    return `der ${nominativeOrdinal} ${monthName} ${spokenYear}`;
}

// ---------------------------------------------------------------------------
// Phone number normalisation (German local + international +49)
// ---------------------------------------------------------------------------

// Matches German phone numbers in local form (leading 0, e.g. 030 12345678,
// 0151-23456789) or international form (+49 …). Separators may be spaces,
// hyphens, or slashes. The leading lookbehind prevents mid-number matches.
const DE_PHONE_REGEX = /(?<!\d)(?:\+49|0)(?:[ /-]?\d){5,12}(?!\d)/;

function spellDigit(ch: string): string {
    const n = Number.parseInt(ch, 10);
    return Number.isNaN(n) ? ch : DE_DIGIT_WORDS[n];
}

function spellDigitGroup(group: string): string {
    return [...group].map(spellDigit).join(" ");
}

function spellPhoneTailGroup(group: string): string {
    const pairs: string[] = [];
    for (let i = 0; i < group.length; i += 2) {
        pairs.push(spellDigitGroup(group.slice(i, i + 2)));
    }
    return pairs.join(", ");
}

function rewriteDePhoneForSynthesis(text: string): string {
    const normalized = text.replace(/[ /-]/g, "");

    let digits: string;
    let prefixSpoken: string | null;
    let explicitGroups: string[];

    if (normalized.startsWith("+49")) {
        prefixSpoken = "plus vier neun";
        digits = normalized.slice(3);
        explicitGroups = text.replace(/^\+49/, "").match(/\d+/g) ?? [];
    } else if (normalized.startsWith("0")) {
        prefixSpoken = null;
        digits = normalized;
        explicitGroups = text.match(/\d+/g) ?? [];
    } else {
        return text;
    }

    if (/\D/.test(digits) || digits.length === 0) {
        return text;
    }

    const groups =
        explicitGroups.length > 1
            ? explicitGroups.map((group, index) =>
                  index === 0 ? spellDigitGroup(group) : spellPhoneTailGroup(group)
              )
            : [spellPhoneTailGroup(digits)];
    const spoken = groups.join(", ");
    return prefixSpoken ? `${prefixSpoken}, ${spoken}` : spoken;
}

// ---------------------------------------------------------------------------
// Currency normalisation (Euro / Cent)
// ---------------------------------------------------------------------------

// Matches euro amounts in either German order: symbol/EUR-first (€1.234,56,
// EUR 1.234,56) or amount-first (1.234,56 € / 1.234,56 EUR). German formatting
// uses a period as the thousands separator and a comma as the decimal
// separator; the integer part allows either grouped (1.234) or ungrouped (1234)
// digits, mirroring the en-GB currency rule.
const DE_CURRENCY_REGEX =
    /(?:-\s?)?(?:(?:€|EUR)\s?\d{1,3}(?:(?:\.\d{3})+|\d*)(?:,\d{1,2})?|\d{1,3}(?:(?:\.\d{3})+|\d*)(?:,\d{1,2})?\s?(?:€|EUR))/i;

function rewriteDeCurrencyForSynthesis(text: string): string {
    let body = text.trim();

    const negative = body.startsWith("-");
    if (negative) {
        body = body.slice(1).trimStart();
    }

    body = body.replace(/€|EUR/gi, "").replace(/\s/g, "");
    if (!body) {
        return text;
    }

    const [wholePart, fractionPart = ""] = body.split(",");
    const whole = Number.parseInt(wholePart.replace(/\./g, ""), 10);
    if (Number.isNaN(whole)) {
        return text;
    }

    let fraction = 0;
    if (fractionPart) {
        const padded = fractionPart.length === 1 ? `${fractionPart}0` : fractionPart;
        fraction = Number.parseInt(padded, 10);
        if (Number.isNaN(fraction)) {
            return text;
        }
    }

    const parts: string[] = [];

    if (whole > 0) {
        const spokenWhole = whole === 1 ? "ein" : spellGermanWholeNumber(whole);
        if (!spokenWhole) {
            return text;
        }
        parts.push(`${spokenWhole} Euro`);
    }

    if (fraction > 0) {
        const spokenFraction = fraction === 1 ? "ein" : spellGermanWholeNumber(fraction);
        if (!spokenFraction) {
            return text;
        }
        parts.push(`${spokenFraction} Cent`);
    }

    if (parts.length === 0) {
        parts.push("null Euro");
    }

    return `${negative ? "minus " : ""}${parts.join(" und ")}`;
}

// ---------------------------------------------------------------------------
// Long digit sequences (account numbers, IBANs, references)
// ---------------------------------------------------------------------------

// Matches digit sequences of 7+ characters that are NOT part of a phone number.
// Lookbehinds exclude sequences preceded by '+' or a digit (international
// prefixes) and by ') ' (parenthesised area codes).
const DE_LONG_DIGIT_REGEX = /(?<![+\d])(?<!\+\d\d\s)(?<!\)\s)\d(?:[ -]?\d){6,}(?!\d)/;

const DE_LONG_DIGIT_MIN_LENGTH = 7;

// Reads long digit sequences in two-digit pairs with brief pauses, matching the
// grouping convention used by the phone rule.
function rewriteDeLongDigitsForSynthesis(text: string): string {
    const digits = text.replace(/[ -]/g, "");
    if (digits.length < DE_LONG_DIGIT_MIN_LENGTH || /\D/.test(digits)) {
        return text;
    }
    // Skip international dial-out numbers (00 + country code + number).
    if (digits.startsWith("00") && digits.length >= 12) {
        return text;
    }
    const pairs: string[] = [];
    for (let i = 0; i < digits.length; i += 2) {
        pairs.push(spellDigitGroup(digits.slice(i, i + 2)));
    }
    return pairs.join(", ");
}

// @visibleForTesting — exported for unit tests only; not part of the public API.
export {
    rewriteDeDateForSynthesis as _rewriteDeDateForSynthesis,
    rewriteDePhoneForSynthesis as _rewriteDePhoneForSynthesis,
    rewriteDeCurrencyForSynthesis as _rewriteDeCurrencyForSynthesis,
    rewriteDeLongDigitsForSynthesis as _rewriteDeLongDigitsForSynthesis,
    dativeOrdinal as _dativeOrdinal,
    preserveInitialCapitalization as _preserveInitialCapitalization,
    spellGermanYear as _spellGermanYear,
    spellGermanWholeNumber as _spellGermanWholeNumber,
    DE_DATE_REGEX as _DE_DATE_REGEX,
};

