import type { LocaleSynthesisRewriteRuleImpl } from "../../synthesis-rewrites";

// Case-sensitive: avoids catching unrelated lowercase tokens like the chip
// term "asic".
const ACRONYM_LETTERS: readonly string[] = [
    // Regulators
    "ATO",
    "ASIC",
    "APRA",
    "ACMA",
    "ACCC",
    "AUSTRAC",
    // Financial identifiers and taxes
    "TFN",
    "ABN",
    "ACN",
    "BSB",
    "GST",
    // Government services and finance
    "NDIS",
    "HECS",
    "RBA",
];

function spellLetters(value: string): string {
    return value.split("").join(" ");
}

export const EN_AU_ACRONYM_REWRITES: LocaleSynthesisRewriteRuleImpl[] = ACRONYM_LETTERS.map(
    acronym => ({
        label: `Acronym: ${acronym}`,
        description: `Spells out the Australian initialism "${acronym}" letter by letter.`,
        playgroundSample: `Your ${acronym} reference is on file.`,
        pattern: new RegExp(`\\b${acronym}\\b`, "g"),
        replacement: spellLetters(acronym),
    })
);
