import { buildSchema } from "./builder";
import { findDocumentEntries } from "./schema";
import type {
    LegacyContentEntry,
    ContentEntry,
    ContentEntryOptions,
    DocumentEntry,
} from "./structure";

import type { ContentType, ContentTypeField, CustomContentType } from "./types";
import type { CannedContentType } from "./types-canned";
import { validateEntry, validateField, validateType } from "./validate-schema";

export function defineField(field: ContentTypeField): ContentTypeField {
    return validateField(field);
}

type RequiredPerLocaleFieldName<Field> = Field extends {
    type: "per_locale";
    childType: { optional: true };
}
    ? never
    : Field extends {
            type: "per_locale";
            name: infer Name extends string;
        }
      ? Name
      : never;

// Top-level required `per_locale` field names are type-checked against `Fields`;
// optional-child `per_locale` fields do not require localization defaults. Nested
// `per_locale` fields (under `object` fields) use dotted paths at runtime like
// "contactInfo.phoneNumber" but are not reflected here — modeling them precisely
// exceeds TS recursion limits.
export type TypeLocalization<Fields extends readonly ContentTypeField[]> = {
    [locale: string]: {
        [K in RequiredPerLocaleFieldName<Fields[number]>]: unknown;
    };
};

type DefineTypeInput<Fields extends readonly ContentTypeField[]> = Omit<
    CustomContentType,
    "type" | "fields" | "localization"
> & {
    fields: Fields;
    localization?: TypeLocalization<Fields>;
};

export function defineType<const Fields extends readonly ContentTypeField[]>(
    type: DefineTypeInput<Fields>,
    opts: { skipValidation?: boolean } = {}
): CustomContentType {
    const typeWithFields: Omit<CustomContentType, "type"> = {
        ...type,
        fields: [...type.fields],
    };
    const contentType =
        (opts.skipValidation ?? false)
            ? {
                  ...typeWithFields,
                  type: "custom" as const,
              }
            : (validateType({
                  ...typeWithFields,
                  type: "custom" as const,
              }) as CustomContentType);

    if (type.version) {
        return {
            ...contentType,
            fields: [...contentType.fields, versionField(type.version)],
        };
    }
    return contentType;
}

export function cannedType(type: Omit<CannedContentType, "type">): ContentType {
    return {
        ...type,
        type: "canned",
    };
}

export function defineListEntry({
    type,
    ...options
}: {
    type: ContentType;
} & ContentEntryOptions): DocumentEntry {
    return validateEntry({
        type: "list",
        typeName: type.name,
        contentType: type,
        ...options,
    });
}

export function defineConstantEntry({
    type,
    ...options
}: {
    type: ContentType;
} & ContentEntryOptions): DocumentEntry {
    return validateEntry({
        type: "constant",
        typeName: type.name,
        contentType: type,
        ...options,
    });
}

export function defineContentFolder({
    children,
    ...options
}: {
    children: ContentEntry[];
} & ContentEntryOptions): ContentEntry {
    return {
        type: "folder",
        children,
        ...options,
    };
}

export type ContentSchemaOptions = {
    /** @deprecated contentTypes are now pulled from entries in contentFolders */
    contentTypes?: ContentType[];
    contentFolders: LegacyContentEntry[];
    /** @deprecated contentFolders provides a complete content entry tree */
    contentEntries?: DocumentEntry[];
};

export function defineSchema({ contentFolders }: ContentSchemaOptions) {
    const entriesFromFolders = findDocumentEntries(contentFolders);
    const typesFromFolders = Array.from(
        // get distinct types
        new Set(entriesFromFolders.map(entry => entry.contentType))
    );
    return buildSchema({
        version: 1,
        contentTypes: typesFromFolders,
        contentEntries: entriesFromFolders,
        contentFolders,
    });
}

function versionField(version: string): ContentTypeField {
    // Clumsy way to implement a semantic version field, for handling the migration of core schema types
    // TODO: allow schemas to provide an upgrade function for execution on the CMS frontend
    return {
        type: "constant",
        name: "$version",
        showIf: {
            type: "constant",
            value: false,
        },
        label: "Version",
        value: version,
    };
}
